window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q11"]=window.__LIBQ["tien-nghich"]["q11"]||{};window.__LIBQ["tien-nghich"]["q11"]["artifacts"]={"updatedAt":"2026-07-13","count":148,"artifacts":[{"id":"ngoc-boi-menh-hon-ly-thien-mai","name":"Ngọc bội mệnh hồn","cn":null,"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lý Thiến Mai"],"trangThai":"Đặt trên tượng đá Vương Lâm, ánh sáng dần mờ, xuất hiện khe nứt","blurb":"Ngọc bội chứa mệnh hồn của Lý Thiến Mai, được nàng đặt lên tượng đá Vương Lâm trước khi rời sơn cốc để duy trì sinh cơ cho tượng.","detail":"Lý Thiến Mai đặt ngọc bội mệnh hồn lên tượng đá Vương Lâm vào tháng thứ chín của năm thứ mười, khi đạo huyết nguyên thần cũng không còn đủ cung ứng. Ngọc bội tỏa ánh sáng nhu hòa, có thể duy trì tượng đá khoảng một tháng. Khi ba tháng trôi qua mà Lý Thiến Mai không trở về, ánh sáng ngọc bội dần mờ và xuất hiện khe nứt nhỏ, ám chỉ mệnh hồn nàng đang suy yếu nghiêm trọng.","nguon":["@c1214"]},{"id":"hon-huyet-ly-thien-mai","name":"Hồn huyết Lý Thiến Mai","cn":null,"category":"khac","categoryLabel":"Vật phẩm đặc thù","phamCap":"Không rõ","soHuu":["Lý Thiến Mai"],"trangThai":"Đã dung nhập tượng đá Vương Lâm, giúp hắn thức tỉnh","blurb":"Trái cầu máu cỡ nắm tay, thực chất là một phần hồn phách ngưng tụ, được Yêu Tông lấy trước khi tu sĩ ra chiến trường để dùng chuyển thế trọng tu nếu tử vong.","detail":"Hồn huyết không phải máu chính thức mà là một phần hồn phách ngưng tụ lại. Yêu Tông thu lấy hồn huyết từ các tu sĩ được coi trọng trước khi ra chiến trường, nếu tu sĩ tử vong thì dùng hồn huyết để chuyển thế trọng tu. Lý Thiến Mai muốn thu hồi hồn huyết bản thân để cứu Vương Lâm, phải đáp ứng điều kiện Yêu Tông — đi vào khe sâu nhất chiến trường dò xét thông đạo giới ngoại, gần như tử lộ. Bà lão bạch y (sư tỷ Lý Thiến Mai) mang hồn huyết tới sơn cốc, dung nhập vào tượng đá. Huyết quang tỏa ra mang sinh cơ và sự ôn nhu mười năm của Lý Thiến Mai, khiến Vương Lâm lần đầu mở mắt sau mười năm hôn mê.","nguon":["@c1214"]},{"id":"ngon-nui-thanh-kiem-co-than","name":"Ngọn núi thanh kiếm Cổ Thần (pháp khí Cổ Thần cửu tinh)","aliases":["Pháp khí Cổ Thần cửu tinh"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí Cổ Thần cửu tinh","soHuu":["Vương Lâm"],"trangThai":"Đang bị Vương Lâm đoạt từ Vô Cực Tông","blurb":"Ngọn núi hùng vĩ tại sơn môn Vô Cực Tông do thanh kiếm Cổ Thần cửu tinh hóa thành, vốn không thuộc tông phái này. Bên trong phong ấn pho tượng Cổ Thần, chứa Cổ Thần lực chí cường, khi được kích hoạt sẽ truyền Cổ Thần lực cho người mang huyết mạch Cổ Thần.","detail":"Ngọn núi thanh kiếm Cổ Thần là một pháp khí Cổ Thần cửu tinh, nguyên bản do thanh kiếm Cổ Thần biến hóa mà thành, vốn không thuộc về Vô Cực Tông. Bên trong ngọn núi phong ấn một pho tượng Cổ Thần lờ mờ mở mắt, giãy giụa gào thét muốn thoát khốn. Khi Vương Lâm kích hoạt Cổ Thần lực, ngọn núi phát ra khí tức tang thương kinh thiên, nứt vỡ, Cổ Thần lực từ bên trong liên tục chảy vào thân thể hắn, khiến mi tâm hắn tái hiện bốn Cổ Thần tinh điểm (@c1217).","congNang":["Chứa Cổ Thần lực chí cường, khi được kích hoạt truyền Cổ Thần lực liên tục vào thân thể người có huyết mạch Cổ Thần (@c1217)","Bên trong phong ấn pho tượng Cổ Thần"],"hinhDang":"Ngọn núi hùng vĩ do thanh kiếm Cổ Thần hóa thành","nguonGoc":"Vốn không thuộc Vô Cực Tông, do thanh kiếm Cổ Thần biến hóa","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vô Cực Tông","tuChuong":"@c1217","denChuong":"@c1217","cachCoDuoc":"Phong ấn sẵn tại sơn môn","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1217","denChuong":"","cachCoDuoc":"Dùng Cổ Thần lực kích hoạt và đoạt lấy","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1217","loai":"đổi chủ","importance":"major","giaiDoan":"Vương Lâm đoạt từ Vô Cực Tông","text":"Vương Lâm kích hoạt Cổ Thần lực bên trong ngọn núi, Cổ Thần lực chảy vào thân thể hắn, mi tâm tái hiện bốn Cổ Thần tinh điểm. Núi nứt vỡ, pho tượng Cổ Thần bên trong giãy giụa gào thét. Vô Cực Tông huy động sáu cường giả và bốn thái tổ trưởng lão ngăn cản nhưng bất thành.","anchor":"Đó là thứ hắn hoài nghi là pháp khí của Cổ Thần cửu tinh"}]},"capNhatToi":"@c1217","nguon":["@c1217"]},{"id":"ky-hieu-huyet-sac-vuong-lam","name":"Ký hiệu huyết sắc (huyết thệ Vương Lâm)","category":"khac","categoryLabel":"Vật phẩm","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Ký hiệu huyết sắc do Vương Lâm cắn lưỡi phun máu tạo ra, chứa một tia hồn phách, dùng làm tín vật huyết thệ gửi tông chủ Vô Cực Tông. Bị hắc y lão giả chụp nát.","detail":"Vương Lâm cắn chót lưỡi phun máu hóa thành ký hiệu huyết sắc chứa một tia hồn phách, gửi cho tông chủ Vô Cực Tông làm tín vật thề sẽ trả lại pháp khí. Khi bị hắc y lão giả chụp nát, ký hiệu sụp đổ, Vương Lâm sắc mặt tái nhợt.","congNang":["Chứa máu và hồn phách chủ nhân, làm tín vật huyết thệ"],"nguon":["@c1217"]},{"id":"ban-menh-phap-bao-dai-thu-yeu-tong","name":"Bản mệnh pháp bảo đại thụ (tông chủ Yêu Tông)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tông chủ đời đầu Yêu Tông"],"trangThai":"khong-ro","blurb":"Cây đại thụ cao chọc trời, là bản mệnh pháp bảo của tông chủ đời đầu Yêu Tông, hình ảnh được khắc trên sáu bia đá trong sáu sơn môn.","detail":"Bản mệnh pháp bảo của tông chủ Yêu Tông, có hình dạng cây đại thụ lớn đến mức cả đất trời không thể ngăn cản. Hình ảnh cây đại thụ đứng phía sau tông chủ được khắc trên sáu tấm bia đá chọc trời trong sáu sơn môn Yêu Tông.","hinhDang":"Cây đại thụ cao chọc trời","tabs":{"tienTrinh":[{"chuong":"@c1221","loai":"nhắc tới","importance":"normal","giaiDoan":"Hé lộ qua bia đá","text":"Hình ảnh bản mệnh pháp bảo đại thụ của tông chủ được khắc trên sáu bia đá trong sáu sơn môn Yêu Tông.","anchor":"cây đại thụ kia là bản mệnh pháp bảo của tông chủ Yêu Tông"}]},"nguon":["@c1221"]},{"id":"huyet-kiem-mau-co-than","name":"Huyết kiếm (máu Cổ Thần)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Huyết kiếm là thanh kiếm hóa từ giọt máu Cổ Thần nơi mi tâm Vương Lâm, toàn thân đỏ như máu, uy lực đủ chém nát pháp bảo của tu sĩ Thiên Nhân Đệ Nhị Suy. Vương Lâm có thể thu kiếm dung nhập vào cơ thể, biến bản thân thành huyết kiếm.","detail":"Trong trận chiến với trưởng lão Yêu Tông, giọt máu tươi từ mi tâm Vương Lâm — nơi ẩn chứa huyết mạch Cổ Thần — tự hóa thành một thanh huyết kiếm toàn thân đỏ thắm như máu. Thanh kiếm vừa thành hình đã chém nát mai rùa pháp bảo của trưởng lão Yêu Tông rồi xuyên thẳng vào thân thể đối phương, thể hiện uy lực vượt trội. Ngoài hình thái kiếm khí độc lập, Vương Lâm còn có thể thu huyết kiếm dung nhập trở lại cơ thể, lúc này toàn thân hắn chính là kiếm — người kiếm hợp nhất.","congNang":["Hóa hình từ giọt máu Cổ Thần nơi mi tâm Vương Lâm, tự ngưng tụ thành thanh kiếm đỏ như máu @c1222","Chém phá pháp bảo: chém nát mai rùa pháp bảo của trưởng lão Yêu Tông rồi xuyên vào thân thể đối phương @c1222","Có thể dung nhập vào cơ thể Vương Lâm, biến toàn thân thành huyết kiếm — người kiếm hợp nhất"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1222","denChuong":"","cachCoDuoc":"Hóa từ máu Cổ Thần trên mi tâm","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1222","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Giọt máu từ mi tâm Vương Lâm hóa thành huyết kiếm đỏ, chém nát mai rùa pháp bảo trưởng lão Yêu Tông, xuyên vào thân đối thủ. Sau đó dung nhập vào cơ thể Vương Lâm, hóa toàn thân thành kiếm.","anchor":"từ trong mi tâm bay ra một giọt máu tươi, hóa thành một thanh huyết kiếm toàn thân đỏ như máu"}]},"nguon":["@c1222"],"uyLuc":"Chém nát mai rùa pháp bảo của trưởng lão Yêu Tông (tu sĩ Thiên Nhân Đệ Nhị Suy) rồi xuyên thẳng vào thân thể đối phương.","dacDiem":"Toàn thân đỏ thắm như máu, hóa từ huyết mạch Cổ Thần, có thể tồn tại độc lập hoặc dung nhập vào thân chủ để người kiếm hợp nhất."},{"id":"mai-rua-phap-bao-truong-lao-yeu-tong","name":"Mai rùa (pháp bảo trưởng lão Yêu Tông)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Trưởng lão Yêu Tông"],"trangThai":"hong","blurb":"Pháp bảo phòng ngự của trưởng lão Yêu Tông, bấm quyết phun ra để chắn huyết kiếm nhưng bị chém nứt rồi tan vỡ.","detail":"Tấm mai rùa được trưởng lão Yêu Tông bấm quyết phun ra để phòng ngự trước huyết kiếm Vương Lâm, nhưng không chống nổi uy lực, vết nứt nổ tung và tan vỡ.","congNang":["Phòng ngự"],"chuSoHuu":[{"ten":"Trưởng lão Yêu Tông","tuChuong":"@c1222","denChuong":"@c1222","cachCoDuoc":"","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c1222","loai":"hư tổn/tu bổ","importance":"normal","giaiDoan":"Bị phá hủy","text":"Bấm quyết phun ra chắn huyết kiếm Vương Lâm nhưng bị chém nứt rồi tan vỡ hoàn toàn.","anchor":"tấm mai rùa kia hiển nhiên không thể ngăn cản được uy lực của thanh huyết kiếm, vết nứt trên đó nổ tung"}]},"nguon":["@c1222"]},{"id":"truong-kiem-nu-tu-ao-lam","name":"Trường kiếm của nữ tử áo lam","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lý Thiến Mai"],"trangThai":"khong-ro","blurb":"Thanh trường kiếm xuất hiện trong tay nữ tử áo lam (nghi là Lý Thiến Mai) qua ảo ảnh quá khứ tại khe nứt Tử Giới.","detail":"Xuất hiện trong ảo ảnh quá khứ khi Vương Lâm thi triển Tuế Nguyệt Nghịch Chuyển: nữ tử áo lam sắc mặt nhợt nhạt, quần áo nhuốm máu, tay cầm thanh trường kiếm, đang nhanh chóng bay đi trong hư vô.","nguon":["@c1223"]},{"id":"but-mau-vang-nu-tu-ao-lam","name":"Bút màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lý Thiến Mai"],"trangThai":"khong-ro","blurb":"Chiếc bút màu vàng vờn quanh bên ngoài thân thể nữ tử áo lam trong ảo ảnh quá khứ tại khe nứt Tử Giới.","detail":"Xuất hiện trong ảo ảnh quá khứ: chiếc bút màu vàng vờn quanh bên ngoài thân thể nữ tử áo lam (nghi là Lý Thiến Mai) khi nàng đang bị thương và bay đi.","nguon":["@c1223"]},{"id":"hu-anh-chiec-roi","name":"Hư ảnh chiếc roi","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Roi khổng lồ dạng hư ảnh tấn công bên trong khe nứt thế giới tím, chứa sức mạnh kỳ dị vượt qua quy tắc, bị phá hủy nhưng lại tái xuất hiện.","detail":"Hư ảnh chiếc roi khổng lồ quất vỡ lam quang bảo hộ trên thân Lý Thiến Mai, chứa sức mạnh kỳ dị mà ngay cả quy tắc Định Thân Thuật cũng không thể ngăn cản. Bị Vương Lâm kích phát sức mạnh Cổ Thần phá hủy, nhưng sau đó lại xuất hiện thêm hai hư ảnh chiếc roi mới tiếp tục tấn công. Nguồn gốc và chủ nhân chưa rõ.","congNang":["Tấn công phá vỡ quy tắc và lam quang bảo hộ","Tái sinh sau khi bị phá hủy, xuất hiện nhiều chiếc mới"],"nguon":["@c1225"]},{"id":"hai-hu-anh-chiec-roi","name":"Hai hư ảnh chiếc roi","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"da-huy","blurb":"Hai hư ảnh chiếc roi xuất hiện từ hư vô tối đen khi phong ấn cấm chế sụp đổ, lao tới tấn công Vương Lâm tại @c1226. Cả hai đều bị phá hủy hoàn toàn trong cuộc đối đầu.","detail":"Hai chiếc roi dưới dạng hư ảnh lóe lên từ bên trong khe nứt dẫn vào hư vô tối đen, ngay thời điểm phong ấn cấm chế sụp đổ. Chúng gào thét lao tới tấn công Vương Lâm. Chiếc thứ nhất bị lốc xoáy nguyên lực đánh vỡ tan. Chiếc thứ hai bị Vương Lâm dùng tay trái túm lấy rồi ném đi kèm huyết kiếm, phá hủy trong hư vô. Khi chiếc roi thứ hai vỡ, có tiếng kêu rên từ hư vô truyền ra, gợi ý rằng có một thực thể bí ẩn ẩn náu trong hư vô đang điều khiển hoặc liên kết với chúng.","congNang":["Tấn công từ hư vô tối đen, lóe lên gào thét lao tới mục tiêu @c1226"],"nguon":["@c1226"],"tabs":{"tienTrinh":[{"chuong":"@c1226","loai":"xuất hiện","importance":"major","giaiDoan":"Xuất hiện và bị phá hủy","text":"Hai hư ảnh chiếc roi lóe lên từ hư vô tối đen tấn công Vương Lâm khi phong ấn sụp đổ. Chiếc thứ nhất bị lốc xoáy đánh vỡ, chiếc thứ hai bị Vương Lâm túm rồi phun huyết kiếm phá hủy, tiếng kêu rên từ hư vô truyền ra.","anchor":"hai hư ảnh chiếc roi lóe lên gào thét bên trong hư vô tối đen"}]}},{"id":"chin-duoi-bo-cap-dung-hop","name":"Chín đuôi bọ cạp dung hợp","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đang giữ","blurb":"Chín chiếc đuôi bọ cạp cấp mười ba được Vương Lâm dùng nguyên khí hóa lửa lam thiêu đốt rồi cấm chế dung hợp thành một.","detail":"Vương Lâm giật chín đuôi bọ cạp cấp mười ba Tử Huyết, dùng nguyên khí hóa lửa lam thiêu đốt, hạ cấm chế dung hợp chín đuôi thành một rồi thu vào trữ vật.","congNang":["Chưa rõ công dụng cụ thể, vật liệu từ mãnh thú cấp mười ba"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1228","denChuong":"","cachCoDuoc":"Thu từ bọ cạp cấp mười ba bị tiêu diệt","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1228","loai":"xuat-hien","importance":"normal","giaiDoan":"Vương Lâm thu hoạch","text":"Vương Lâm giật chín đuôi bọ cạp cấp mười ba, dùng lửa lam thiêu đốt rồi cấm chế dung hợp thành một, thu vào trữ vật.","anchor":"chín chiếc đuôi bọ cạp dung hợp làm một, bị Vương Lâm thu vào trong khe nứt trữ vật"}]},"nguon":["@c1228"]},{"id":"hac-dan-bo-cap","name":"Hắc đan bọ cạp","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đang giữ","blurb":"Viên đan đen lớn bằng nắm tay trong đầu bọ cạp cấp mười ba, chứa nguyên thần nữ tử hóa hình.","detail":"Mãnh thú cấp mười ba hóa hình người có thể bảo tồn nguyên thần trong hắc đan khi thú thể bị diệt. Vương Lâm đập vỡ đầu bọ cạp Tử Huyết, lộ ra hắc đan, dùng thần thức xâm nhập lục soát ký ức.","congNang":["Chứa nguyên thần mãnh thú cấp mười ba hóa hình"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1228","denChuong":"","cachCoDuoc":"Đập vỡ đầu bọ cạp cấp mười ba","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1228","loai":"xuat-hien","importance":"normal","giaiDoan":"Vương Lâm thu hoạch","text":"Vương Lâm đập vỡ đầu bọ cạp, lộ ra hắc đan lớn bằng nắm tay chứa nguyên thần, dùng thần thức lục soát ký ức.","anchor":"lộ ra một hắc đan lớn bằng nắm tay"}]},"nguon":["@c1228"]},{"id":"ngoc-boi-truyen-tong-khe-nut","name":"Ngọc bội truyền tống khe nứt","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đang giữ","blurb":"Ngọc bội chứa truyền tống trận phức tạp, cho phép truyền tống hai chiều giữa bất kỳ đâu và khe nứt. Y Nguyệt trao cho Vương Lâm như một phần của thỏa thuận liên minh.","detail":"Ngọc bội này do Y Nguyệt trao cho Vương Lâm tại thời điểm hai bên đạt thỏa thuận liên minh. Bên trong ngọc bội chứa một truyền tống trận rất phức tạp, có thể kích hoạt từ bất kỳ nơi đâu để đi vào trong khe nứt, đồng thời cũng có thể từ bên trong khe nứt truyền tống ra ngoài miệng khe. Vương Lâm sau khi nhận đã dùng thần niệm kiểm tra, xác nhận trận pháp tuy phức tạp đến mức không nhìn ra manh mối nhưng an toàn, sau đó sử dụng ngọc bội để rời đi. @c1228","congNang":["Truyền tống hai chiều giữa bất kỳ đâu và khe nứt: có thể từ nơi bất kỳ vào trong khe nứt, hoặc từ khe nứt ra ngoài miệng khe @c1228"],"chuSoHuu":[{"ten":"Y Nguyệt","tuChuong":"","denChuong":"@c1228","cachCoDuoc":"Sở hữu ban đầu","trangThai":"da-cho"},{"ten":"Vương Lâm","tuChuong":"@c1228","denChuong":"","cachCoDuoc":"Y Nguyệt trao","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1228","loai":"doi-chu","importance":"major","giaiDoan":"Y Nguyệt trao cho Vương Lâm","text":"Y Nguyệt trao ngọc bội truyền tống cho Vương Lâm như phần thỏa thuận liên minh, Vương Lâm kiểm tra an toàn rồi dùng để rời khe nứt.","anchor":"Cầm lấy ngọc bội này, nó có thể từ bất kỳ nơi đâu vào trong khe nứt"}]},"nguon":["@c1228"],"dacDiem":"Bên trong chứa truyền tống trận rất phức tạp, Vương Lâm dùng thần niệm kiểm tra không nhìn ra manh mối nhưng xác nhận an toàn @c1228"},{"id":"toa-lau-cac-bach-ngoc","name":"Tòa lầu các bạch ngọc","cn":"","category":"khac","categoryLabel":"Vật thể bí ẩn trong thiên kiếp","phamCap":"Không rõ","soHuu":[],"trangThai":"Đang hiện ra từ lỗ hổng vô lượng kiếp","blurb":"Tòa lầu các bằng bạch ngọc xuất hiện từ lỗ hổng trong tầng mây vô lượng kiếp, thông tới một thế giới khác. Trên lầu có pho tượng ngồi khoanh chân, trước pho tượng cắm hai thanh thạch kiếm.","detail":"Tòa lầu các bạch ngọc xuất hiện bên trong lỗ hổng mở ra từ tầng mây thiên kiếp (vô lượng kiếp), từ thế giới khác đang từ từ tiến lại gần (@c1229). Toàn thân làm bằng bạch ngọc. Trên lầu đặt một pho tượng ngồi khoanh chân, phía trước pho tượng cắm hai thanh thạch kiếm. Tính tới mốc mới nhất, tòa lầu mới lộ ra một phần và vẫn đang tiến lại gần, công năng cụ thể chưa được làm rõ.","hinhDang":"Lầu các bằng bạch ngọc","nguonGoc":"Xuất hiện từ thế giới khác qua lỗ hổng trong tầng mây vô lượng kiếp","congNang":["Chưa rõ — đang tiến lại gần qua lỗ hổng thiên kiếp @c1229"],"tabs":{"tienTrinh":[{"chuong":"@c1229","loai":"xuất hiện","importance":"major","giaiDoan":"Hiện ra từ tầng mây vô lượng kiếp","text":"Tòa lầu các bạch ngọc xuất hiện từ lỗ hổng trong tầng mây thiên kiếp, đang tiến lại gần. Trên lầu có pho tượng ngồi khoanh chân, trước người cắm hai thanh thạch kiếm.","anchor":"Tòa lầu các này làm bằng bạch ngọc, đang không ngừng tiến lại gần lỗ hổng"}]},"capNhatToi":"@c1229","nguon":["@c1229"],"dacDiem":"Làm bằng bạch ngọc, thông tới thế giới khác qua lỗ hổng trong tầng mây vô lượng kiếp; trên lầu có pho tượng ngồi khoanh chân và hai thanh thạch kiếm cắm phía trước."},{"id":"hai-thanh-thach-kiem","name":"Hai thanh thạch kiếm","cn":"","category":"phap-bao","categoryLabel":"Kiếm / Pháp khí","phamCap":"Không rõ","soHuu":[],"trangThai":"Cắm trước pho tượng trên lầu các","blurb":"Hai thanh kiếm bằng đá cắm trước pho tượng trên lầu các bạch ngọc trong vô lượng kiếp. Lai lịch và công năng chưa rõ.","detail":"Xuất hiện cùng tòa lầu các bạch ngọc và pho tượng bí ẩn trong vô lượng kiếp. Bằng đá, cắm trước người pho tượng ngồi khoanh chân.","hinhDang":"Kiếm bằng đá","nguonGoc":"Chưa rõ, xuất hiện cùng lầu các bạch ngọc trong vô lượng kiếp","tabs":{"tienTrinh":[{"chuong":"@c1229","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện cùng pho tượng trong vô lượng kiếp","text":"Cắm trước pho tượng ngồi khoanh chân trên lầu các bạch ngọc trong tầng mây vô lượng kiếp.","anchor":"Trước người pho tượng này cắm hai thanh thạch kiếm!"}]},"capNhatToi":"@c1229","nguon":["@c1229"]},{"id":"pho-tuong-lau-cac-bach-ngoc","name":"Pho tượng trên lầu các bạch ngọc","cn":"","category":"khac","categoryLabel":"Thực thể bí ẩn","phamCap":"Không rõ","soHuu":[],"trangThai":"Ngồi khoanh chân trên lầu các","blurb":"Pho tượng bí ẩn ngồi khoanh chân trên tòa lầu các bạch ngọc trong vô lượng kiếp, trước người cắm hai thanh thạch kiếm.","detail":"Xuất hiện cùng tòa lầu các bạch ngọc từ lỗ hổng trong tầng mây vô lượng kiếp. Ngồi khoanh chân, hai thanh thạch kiếm cắm trước người. Danh tính chưa rõ.","hinhDang":"Pho tượng ngồi khoanh chân","nguonGoc":"Chưa rõ, xuất hiện từ thế giới khác qua lỗ hổng vô lượng kiếp","tabs":{"tienTrinh":[{"chuong":"@c1229","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện trên lầu các bạch ngọc","text":"Pho tượng ngồi khoanh chân trên lầu các bạch ngọc hiện ra từ tầng mây vô lượng kiếp, trước người cắm hai thanh thạch kiếm.","anchor":"Hắn thấy trên lầu các có một pho tượng đang ngồi khoanh chân"}]},"capNhatToi":"@c1229","nguon":["@c1229"]},{"id":"that-thai-dinh","name":"Thất Thải Đinh","cn":"七彩钉","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thủy Đạo Tử"],"trangThai":"dang-co","blurb":"Thất Thải Đinh là chiếc đinh bảy màu cắm ở mi tâm Thủy Đạo Tử. Tính tới mốc mới nhất, nó đang lộ ra ngoài mi tâm khi Thủy Đạo Tử cố ép nó ra nhưng thất bại vì ý chí Vương Lâm theo lôi đình kích hoạt khiến nó tỏa sáng.","detail":"Thất Thải Đinh đã lộ ra ngoài mi tâm Thủy Đạo Tử. Vào thời khắc mấu chốt hắn đang ép nó ra khỏi mi tâm thì ý chí Vương Lâm ẩn trong lôi đình thiên kiếp xâm nhập mật thất, kích hoạt Thất Thải Đinh tỏa sáng chói mắt, khiến Thủy Đạo Tử phun máu và toàn bộ công sức uổng phí. Đặc điểm nổi bật của pháp bảo này là phản ứng với ý chí/lôi đình của Vương Lâm ngay cả khi chủ nhân đang cố gỡ nó ra (@c1230).","congNang":["Phản ứng với ý chí/lôi đình của Vương Lâm dù đang bị chủ nhân ép gỡ, tỏa sáng chói mắt khiến quá trình gỡ thất bại (@c1230)"],"chuSoHuu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1230","denChuong":"","cachCoDuoc":"Cắm ở mi tâm (chưa rõ nguồn gốc)","trangThai":"đang cố ép ra nhưng thất bại"}],"tabs":{"tienTrinh":[{"chuong":"@c1230","loai":"khai phong","importance":"major","giaiDoan":"Bị kích hoạt bởi ý chí Vương Lâm, phá hoại tiến trình ép gỡ của Thủy Đạo Tử","text":"Đã lộ ra ngoài mi tâm Thủy Đạo Tử, hắn đang cố ép ra thì ý chí Vương Lâm theo lôi đình kích hoạt Thất Thải Đinh tỏa sáng chói mắt, khiến Thủy Đạo Tử phun máu, toàn bộ công sức uổng phí.","anchor":"Thất Thải Đinh lúc này đã lộ ra ngoài mi tâm hắn"}]},"nguon":["@c1230"],"dacDiem":"Chiếc đinh bảy màu cắm ở mi tâm Thủy Đạo Tử (@c1230)"},{"id":"bon-thanh-kiem-thien-kiep","name":"Bốn thanh kiếm thiên kiếp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo / Hiện tượng thiên kiếp","phamCap":"Thiên kiếp","soHuu":[],"trangThai":"tiêu tán vào tầng mây ngưng tụ núi mây","blurb":"Bốn trường kiếm màu xanh, lam, đen, vàng ẩn trong bốn thạch kiếm trước pho tượng trên lầu các bạch ngọc, lần lượt vỡ ra trong thiên kiếp. Chúng vây công huyết kiếm rồi xoay tròn tạo dòng xoáy chứa thế giới mê hoặc, sau đó ngưng tụ thành núi mây tím phù văn chữ đạo đè xuống Vương Lâm.","detail":"Bốn thạch kiếm phía sau pho tượng trên lầu các bạch ngọc lần lượt vỡ ra lộ bốn trường kiếm: xanh (ra trước), lam, đen, vàng (@c1231). Bốn kiếm vây công huyết kiếm rồi vờn quanh trên không xoay tròn tạo thành dòng xoáy chứa thế giới hỗn độn có tinh cầu và con người, phát tiếng gọi mê hoặc hứa trường sinh thoát luân hồi, hút mất hàng trăm tu sĩ. Dòng xoáy sau đó tiêu tán vào tầng mây, ngưng tụ thành núi mây khổng lồ toàn mây tím với phù văn chữ đạo, uy áp chấn kinh thiên địa đè xuống Vương Lâm.","congNang":["Vây công huyết kiếm rồi xoay tròn tạo dòng xoáy (@c1231)","Tạo dòng xoáy chứa thế giới mê hoặc, phát tiếng gọi hứa trường sinh thoát luân hồi hút sinh linh vào vùng đất ước mơ","Ngưng tụ thành núi mây tím phù văn chữ đạo nghiền nát, uy áp đè xuống mục tiêu"],"dacDiem":"Ẩn trong bốn thạch kiếm trước pho tượng trên lầu các bạch ngọc; bốn trường kiếm màu xanh, lam, đen, vàng; ngưng tụ thành núi mây tím phù văn chữ đạo.","capNhatToi":"@c1231","tabs":{"tienTrinh":[{"chuong":"@c1231","loai":"xuất hiện","importance":"major","giaiDoan":"Bốn kiếm thiên kiếp lộ diện tạo dòng xoáy mê hoặc","text":"Bốn thạch kiếm lần lượt vỡ ra lộ trường kiếm xanh, lam, đen, vàng, vây công huyết kiếm rồi xoay tạo dòng xoáy chứa thế giới hỗn độn. Tiếng gọi mê hoặc hút hàng trăm tu sĩ biến mất. Dòng xoáy tiêu tán ngưng tụ thành núi mây tím chữ đạo đè xuống Vương Lâm.","anchor":"Bốn thanh kiếm xanh, lam, đen, vàng vờn quanh trên không trung, lập tức xoay tròn"}]},"nguon":["@c1231"],"uyLuc":"Ngưng tụ thành núi mây tím khổng lồ với phù văn chữ đạo, uy áp chấn kinh thiên địa đè xuống Vương Lâm; dòng xoáy mê hoặc hút mất hàng trăm tu sĩ."},{"id":"chin-thien-thach-cuu-cung","name":"Chín thiên thạch Cửu Cung","category":"khac","categoryLabel":"Vật của Thiên Kiếp","phamCap":"Thiên Kiếp cấp","soHuu":[],"trangThai":"dang-hoat-dong","blurb":"Chín thiên thạch khổng lồ trong tinh không đã bị luyện hóa từ vô số năm trước thành vật của Thiên Kiếp, thu nhỏ thành chín tinh cầu nhập vào thân Vương Lâm qua chín đốm máu.","detail":"Chín thiên thạch bố trí theo Cửu Cung (càn, khảm, cấn, chấn, trung, tốn, ly, bạng, đoài), không phải tu chân tinh, không có sinh linh. Khi được pho tượng phát động, thu nhỏ xuyên qua lối vào Phong Giới đại trận lao thẳng đến Vương Lâm, nhập thể qua chín đốm máu trắng.","tabs":{"tienTrinh":[{"chuong":"@c1232","loai":"xuất hiện","importance":"normal","giaiDoan":"Nhập thể Vương Lâm","text":"Chín tinh cầu thu nhỏ xuyên qua lối vào Phong Giới đại trận lao đến Vương Lâm, nhập thể qua chín đốm máu cố ngưng tụ ở ngực.","anchor":"Cửu Cung hóa thành tinh cầu kia cũng không phải là tu chân tinh, trên đó cũng không có bất kỳ một sinh linh nào, mà là chín thiên thạch khổng lồ ở bên trong tinh không"}]},"nguon":["@c1232"]},{"id":"ngoc-boi-tong-chu","name":"Ngọc bội Tông Chủ","cn":"宗主玉佩","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (cực phẩm)","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Ngọc bội của Tông Chủ - chủ nhân Phong Giới, ẩn giấu bên trong Thiên Nghịch Châu. Khi được kích hoạt, nó biến ảo hiện ra cây đại thụ chọc trời mang mặt người Tông Chủ, dùng để triệu hoán hình ảnh chủ nhân và phá giải Phong Giới Đại Trận.","detail":"Ngọc bội Tông Chủ ẩn bên trong Thiên Nghịch Châu, biến ảo hiện ra khi Vương Lâm truyền thần niệm, xuyên qua thân thể bay ra (@c1233). Lúc xuất hiện khiến trời đất ầm vang, hư vô run lên, ngay cả Bát Quái Thiên Kiếp cũng chấn động, và được Huyền Bỉnh nhận ra là ngọc bội của Tông Chủ. Khi lóe sáng, nó biến ảo thành một cây đại thụ chọc trời hiện lên khuôn mặt già nua của Tông Chủ. Sau khi Tông Chủ nói xong, ngọc bội hóa tinh quang rơi xuống Phong Giới Đại Trận, hóa thành vô số sợi tơ xanh lan tràn thẩm thấu phá giải đại trận.","congNang":["Triệu hoán hình ảnh chủ nhân Phong Giới (Tông Chủ) qua cây đại thụ chọc trời hiện mặt người @c1233","Phá giải Phong Giới Đại Trận bằng cách hóa tinh quang, biến thành vô số sợi tơ xanh thẩm thấu lan tràn @c1233"],"chuSoHuu":[{"ten":"Chủ nhân Phong Giới","tuChuong":"","denChuong":"","cachCoDuoc":"Ngọc bội bản thân","trangThai":"truyen-lai"},{"ten":"Vương Lâm","tuChuong":"@c1233","denChuong":"@c1233","cachCoDuoc":"Ẩn trong Thiên Nghịch Châu, kích hoạt bằng thần niệm","trangThai":"da-dung"}],"nguon":["@c1233"],"tabs":{"tienTrinh":[{"chuong":"@c1233","loai":"xuat-hien","importance":"major","giaiDoan":"Kích hoạt và phá giải Phong Giới Đại Trận","text":"Từ Thiên Nghịch Châu biến ảo hiện ra, triệu hoán hình ảnh Tông Chủ qua cây đại thụ chọc trời. Sau đó hóa tinh quang rơi xuống Phong Giới Đại Trận, phá giải hoàn toàn.","anchor":"Ngọc bội của Tông Chủ! Hắn, hắn không ngờ lại có được ngọc bội của Tông Chủ!","phamCap":"Cực phẩm"}]},"uyLuc":"Khi xuất hiện khiến trời đất ầm vang, hư vô run lên, ngay cả Bát Quái Thiên Kiếp cũng chấn động @c1233","dacDiem":"Ẩn bên trong Thiên Nghịch Châu; khi kích hoạt biến ảo ra cây đại thụ chọc trời hiện mặt người già nua của Tông Chủ"},{"id":"tam-khien-mat-quy","name":"Tấm khiên hình mặt quỷ","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Lão giả Toái Niết đại viên mãn (thủ trận giới ngoại)"],"trangThai":"bi-huy","blurb":"Pháp bảo phòng ngự của lão giả Toái Niết đại viên mãn giới ngoại, lấy ra từ ngực. Bị tia chớp đỏ của Vương Lâm xuyên thủng, phát tiếng kêu thê lương rồi nổ tung thành nhiều mảnh.","detail":"Tấm khiên hình mặt quỷ dùng để chống đỡ tấn công. Khi bị tia chớp đỏ đánh trúng, phát ra tiếng kêu thê lương rồi sụp đổ nổ tung.","nguon":["@c1236"],"congNang":["Phòng ngự chống đỡ đòn tấn công"],"chuSoHuu":[{"ten":"Lão giả Toái Niết đại viên mãn (thủ trận giới ngoại)","tuChuong":"@c1236","denChuong":"@c1236","cachCoDuoc":"","trangThai":"bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c1236","loai":"dùng","importance":"normal","giaiDoan":"Bị phá hủy khi chống Vương Lâm","text":"Lão giả lấy khiên mặt quỷ từ ngực ra chống đỡ, bị tia chớp đỏ xuyên thủng, phát tiếng kêu thê lương rồi nổ tung thành nhiều mảnh.","anchor":"chiếc khiên mặt quỷ phát ra tiếng kêu thê lương, lập tức sụp đổ"}]}},{"id":"dam-khi-tinh-hon","name":"Đám khí tinh hồn","cn":"","category":"khac","categoryLabel":"Khác (năng lượng)","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Bảy đám khí tinh hồn Vương Lâm rút từ nhiều tu chân tinh, dùng hồi phục nguyên thần.","detail":"Vương Lâm dùng Trừu Tinh Hồn Lực rút tinh hồn từ nhiều tu chân tinh ngoại giới, tạo thành bảy đám khí tinh hồn lơ lửng quanh thân. Mỗi đám to bằng nắm tay, ẩn chứa tinh không, dùng để hồi phục nguyên thần bị thương.","nguon":["@c1238"],"congNang":["Hồi phục nguyên thần bị thương @c1238"],"tabs":{"tienTrinh":[{"chuong":"@c1238","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm rút tinh hồn tạo thành bảy đám khí","text":"Vương Lâm rút tinh hồn từ nhiều tu chân tinh tạo thành bảy đám khí tinh hồn lơ lửng quanh thân, nguyên thần hồi phục gần hết.","anchor":"dần dần bên ngoài thân thể Vương Lâm đã có bảy đám khí tinh hồn lơ lững"}]}},{"id":"van-than-diet-phien","name":"Vân Thần Diệt Phiến","cn":"云神灭扇","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Quạt nguyệt sắc trăm trượng của Nguyệt Tộc, tạo gió lốc trong Phong Thần Đại Trận.","detail":"Một trong các chí bảo Nguyệt Tộc triệu ra trong Phong Thần Đại Trận nhằm phong ấn Cổ Thần. Hình dạng quạt nguyệt sắc lớn trăm trượng, phát gió lốc mãnh liệt. Bị Cổ Thần Bát Tinh thuật Hư quét sạch cùng các pháp bảo khác.","nguon":["@c1239"]},{"id":"huyet-nguyet-thu","name":"Huyết Nguyệt Thú","cn":"血月兽","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Mãnh thú huyết tế của Nguyệt Tộc, tạo ấn ký huyết sắc trong Phong Thần Đại Trận.","detail":"Chí bảo Nguyệt Tộc dùng trong Phong Thần Đại Trận. Huyết tế mãnh thú tạo ra ấn ký huyết sắc tấn công Cổ Thần. Bị Cổ Thần Bát Tinh thuật Hư quét sạch.","nguon":["@c1239"]},{"id":"co-than-cuu-cot","name":"Cổ Thần Cửu Cốt","cn":"古神九骨","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Chín đầu lâu Cổ Thần, nổ tung tương đương chín tu sĩ bước thứ ba tự bạo.","detail":"Chín đầu lâu Cổ Thần được Nguyệt Tộc triệu ra trong Phong Thần Đại Trận. Khi kích hoạt, nổ tung với uy lực tương đương chín tu sĩ bước thứ ba tự bạo, nhằm phá hủy thân thể Cổ Thần. Bị Cổ Thần Bát Tinh thuật Hư quét sạch.","nguon":["@c1239"]},{"id":"hoi-than-dich","name":"Hội Thần Dịch","cn":"会神液","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Biển máu đen hôi thối chuyên luyện hóa Cổ Thần lực.","detail":"Chí bảo Nguyệt Tộc dùng trong Phong Thần Đại Trận, biến thành biển máu đen hôi thối có công năng luyện hóa Cổ Thần lực. Bị Cổ Thần Bát Tinh thuật Hư cuốn đi tiêu tan.","nguon":["@c1239"]},{"id":"mat-cua-co-than","name":"Mắt của Cổ Thần","cn":"古神之眼","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Mắt Cổ Thần do Nguyệt Tộc sở hữu, dùng trong Phong Thần Đại Trận.","detail":"Một trong các chí bảo Nguyệt Tộc triệu ra trong Phong Thần Đại Trận để phong ấn và tấn công Cổ Thần. Bị Cổ Thần Bát Tinh thuật Hư đánh nổ tung.","nguon":["@c1239"]},{"id":"cu-linh-chung","name":"Cự Linh Chung","cn":"巨灵钟","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Chuông cổ phát sóng âm trong Phong Thần Đại Trận.","detail":"Chuông cổ Nguyệt Tộc triệu ra trong Phong Thần Đại Trận, phát sóng âm nhắm vào Cổ Thần. Sóng chuông bị Cổ Thần Bát Tinh thuật Hư quét tiêu tán.","nguon":["@c1239"]},{"id":"diet-the-de-cuu-linh","name":"Diệt Thế Đệ Cửu Linh","cn":"灭世第九灵","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Hư ảnh xanh có khí tức giống đầu lâu Cổ Thần vùng đất Yêu Linh.","detail":"Chí bảo Nguyệt Tộc triệu ra cuối cùng trong chuỗi pháp bảo Phong Thần Đại Trận. Là hư ảnh xanh mang khí tức tương tự đầu lâu Cổ Thần ở vùng đất Yêu Linh. Bị Cổ Thần Bát Tinh thuật Hư quét tan thành mây khói.","nguon":["@c1239"]},{"id":"tan-cot-co-than-nguyet-toc","name":"Tàn cốt Cổ Thần (chí bảo Nguyệt Tộc)","cn":"古神残骨","aliases":["Đốt xương ngón tay Cổ Thần gần cửu tinh","Cổ Thần tàn cốt"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Gần cửu tinh Cổ Thần","soHuu":["Nguyệt Tộc","Vương Lâm","Thác Sâm"],"trangThai":"Bị chẻ đôi — nửa thuộc Vương Lâm, nửa thuộc Thác Sâm","blurb":"Đốt xương ngón tay Cổ Thần gần cửu tinh, đệ nhất bảo vật hộ tộc tối thượng của Nguyệt Tộc.","detail":"Đốt xương ngón tay của Cổ Thần gần cửu tinh (không phải thực sự cửu tinh), là bảo vật hộ tộc tối thượng của Nguyệt Tộc, được chuẩn bị vô số vạn năm. Lão giả tóc bạc Nguyệt Tộc tuyệt vọng triệu ra để đánh hai Cổ Thần. Đốt xương hạ xuống đánh vỡ ký hiệu Bát Tinh thuật Hư, khiến Thác Sâm phun máu ném xa, Vương Lâm xương cốt vỡ vụn toàn thân. Lần thứ hai được triệu sau hiến tế Nguyệt linh, đâm vào Thác Sâm. Thác Sâm cố thôn phệ nhưng Vương Lâm dùng huyết kiếm chém nứt đốt xương làm đôi. Một nửa bị Thác Sâm hút vào tinh điểm, nửa còn lại bị Vương Lâm đoạt mang đi.","nguon":["@c1239"]},{"id":"luc-pham-dao-linh","name":"Lục phẩm đạo linh","cn":"六品道灵","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Lục phẩm","soHuu":["Lão già Không Linh (Viễn Cổ Tinh Thần)","Ti Mặc Tử","Tư Mặc Tử","Trường Tôn Hội"],"trangThai":"đang được dùng làm vật tu luyện và phần thưởng truy bắt","blurb":"Đạo linh lục phẩm, phần thưởng nữ tử áo trắng trao cho hai cao thủ Viễn Cổ Tinh Thần.","detail":"Nữ tử áo trắng mang khí tức Tiên Vực trao cho lão già Không Linh và Ti Mặc Tử mỗi người một viên lục phẩm đạo linh như đã hứa trước, sau khi hai người hoàn thành việc truy sát (hoặc phối hợp theo dõi) Thác Sâm.","nguon":["@c1239","@c1281"],"tabs":{"tienTrinh":[{"chuong":"@c1281","loai":"dùng","importance":"normal","giaiDoan":"Tư Mặc Tử hấp thu","text":"Tư Mặc Tử hấp thu Lục Phẩm đạo linh đến sáu phần và mơ hồ cảm thấy dấu hiệu đột phá Không Niết sơ kỳ.","phamCap":"Lục Phẩm","anchor":"TA mới hấp thu được sáu phần đã mơ hồ có dấu hiệu đột phá Không Niết sơ kỳ"}]},"congNang":["Hỗ trợ tăng tu vi và cảm ngộ dấu hiệu đột phá Không Niết sơ kỳ @c1281"],"chuSoHuu":[{"ten":"Tư Mặc Tử","tuChuong":"@c1281","denChuong":"","cachCoDuoc":"đang hấp thu","trangThai":"dang-giu"},{"ten":"Trường Tôn Hội","tuChuong":"@c1281","denChuong":"","cachCoDuoc":"dùng làm phần thưởng truy bắt","trangThai":"treo-thuong"}]},{"id":"nua-dot-xuong-ngon-tay-co-than","name":"Nửa đốt xương ngón tay Cổ Thần","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":["Vương Lâm"],"trangThai":"đang sở hữu","blurb":"Nửa đốt xương ngón tay của Cổ Thần, chiến lợi phẩm Vương Lâm thu được sau trận chiến với Thác Sâm, chưa kịp nghiên cứu.","detail":"Được Vương Lâm thu vào khe trữ vật sau khi thoát khỏi cuộc đuổi giết của Thác Sâm. Chưa rõ công dụng cụ thể, chưa kịp nghiên cứu chi tiết.","tabs":{"tienTrinh":[{"chuong":"@c1240","loai":"xuất hiện","importance":"normal","giaiDoan":"Thu hoạch","text":"Vương Lâm thu nửa đốt xương ngón tay Cổ Thần vào khe trữ vật sau trận chiến với Thác Sâm.","anchor":"Nửa đốt xương ngón tay của Cổ Thần đã được Vương Lâm đưa vào trong khe trữ vật"}]},"nguon":["@c1240"]},{"id":"nam-dao-khi-thien-thach","name":"Năm đạo khí thiên thạch thiên ngoại","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Cực phẩm (khiến chưởng tôn kiêng dè)","soHuu":["Lam Mộng Đạo Tôn"],"trangThai":"dang-co","blurb":"Năm đạo khí do Lam Mộng Đạo Tôn luyện hóa từ năm thiên thạch thiên ngoại, xuất ra trời long đất lở, khiến chưởng tôn cũng kiêng dè.","detail":"Lam Mộng Đạo Tôn luyện hóa từ năm thiên thạch thiên ngoại thành năm đạo khí. Uy lực cực lớn, xuất ra trời long đất lở. Ngay cả chưởng tôn cũng phải cố kỵ. Đề nghị trao cho Vương Lâm nhưng bị từ chối vì đi kèm điều kiện thoát ly giới nội.","congNang":["Xuất ra trời long đất lở, uy lực khiến chưởng tôn kiêng dè"],"chuSoHuu":[{"ten":"Lam Mộng Đạo Tôn","tuChuong":"@c1243","denChuong":"","cachCoDuoc":"Tự luyện hóa từ thiên thạch thiên ngoại","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1243","loai":"xuat-hien","importance":"normal","giaiDoan":"Được Lam Mộng nhắc tới khi chiêu mộ Vương Lâm","text":"Lam Mộng Đạo Tôn đề cập năm đạo khí luyện từ thiên thạch thiên ngoại, xuất ra trời long đất lở, chưởng tôn cũng kiêng dè. Đề nghị trao cho Vương Lâm nhưng bị từ chối.","anchor":"Năm đạo khí đó xuất ra là trời long đất lở"}]},"nguon":["@c1243"]},{"id":"vong-tam-qua","name":"Vong tâm quả","cn":"忘心果","category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":"Không rõ","soHuu":["Lam Mộng Đạo Tôn"],"trangThai":"dang-co","blurb":"Vật phẩm dùng kèm lời thề bổn nguyên để thoát ly giới nội, ngụ ý giúp quên đi gốc rễ và ràng buộc cũ.","detail":"Điều kiện thứ nhất của Lam Mộng Đạo Tôn yêu cầu Vương Lâm ăn vong tâm quả, phát lời thề bổn nguyên thoát ly giới nội, trở thành người Thái Cổ Tinh Thần. Vương Lâm cự tuyệt.","congNang":["Dùng kèm thề bổn nguyên để thoát ly giới nội, quên gốc rễ cũ"],"chuSoHuu":[{"ten":"Lam Mộng Đạo Tôn","tuChuong":"@c1243","denChuong":"","cachCoDuoc":"Sẵn có","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1243","loai":"xuat-hien","importance":"normal","giaiDoan":"Được nhắc tới trong điều kiện chiêu mộ Vương Lâm","text":"Lam Mộng yêu cầu Vương Lâm ăn vong tâm quả và phát lời thề bổn nguyên thoát ly giới nội. Bị Vương Lâm cự tuyệt.","anchor":"Ngươi phải ăn vong tâm quả, phát lời thề bổn nguyên, thoát ly giới nội"}]},"nguon":["@c1243"]},{"id":"tieu-cau-loc-xoay-lam-mong","name":"Tiểu cầu lốc xoáy (Lam Mộng Đạo Tôn)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã tiêu tan","blurb":"Vật phẩm chứa đạo thuật dung hợp do Lam Mộng Đạo Tôn truyền thụ, Vương Lâm dùng năm đạo bổn nguyên hấp thu hết khí bên trong, tiểu cầu hoàn toàn tiêu tan.","detail":"Tiểu cầu lốc xoáy trôi nổi giữa không trung cùng thanh kiếm băng từ khi Lam Mộng Đạo Tôn rời đi. Chứa đạo thuật dung hợp bên trong. Vương Lâm dùng hai ngón tay kẹp, năm đạo bổn nguyên xoay trong đồng tử hấp thu khí vô hình từ tiểu cầu. Mấy ngày sau tiểu cầu hoàn toàn tiêu tan.","congNang":["Truyền thụ đạo thuật dung hợp khi được hấp thu bởi bổn nguyên"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1245","denChuong":"@c1245","cachCoDuoc":"Lam Mộng Đạo Tôn truyền thụ","trangThai":"đã tiêu tan"}],"capNhatToi":"@c1245","tabs":{"tienTrinh":[{"chuong":"@c1245","loai":"dùng","importance":"major","giaiDoan":"Vương Lâm hấp thu hoàn toàn, tiểu cầu tiêu tan","text":"Vương Lâm dùng năm đạo bổn nguyên hấp thu khí từ tiểu cầu lốc xoáy, mấy ngày sau tiểu cầu hoàn toàn tiêu tan, hoàn tất truyền thụ đạo thuật dung hợp.","anchor":"tiểu cầu lốc xoáy này hoàn toàn tiêu tan"}]},"nguon":["@c1245"]},{"id":"thanh-kiem-bang-lam-mong","name":"Thanh kiếm băng (Lam Mộng Đạo Tôn)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã biến đổi/tiêu hủy","blurb":"Thanh kiếm băng trôi nổi giữa không trung từ khi Lam Mộng Đạo Tôn rời đi, bị Vương Lâm dùng đạo thuật dung hợp biến thành mảnh băng, nước mưa, sương mù rồi đám mây trắng bay đi.","detail":"Thanh kiếm băng trôi nổi giữa không trung cùng tiểu cầu lốc xoáy, tuyết không bám được lên bề mặt. Vương Lâm dùng đạo thuật dung hợp lần đầu trên thanh kiếm này: kiếm nứt vỡ thành mảnh băng, mảnh băng hòa tan thành nước mưa, nước mưa thành lốc xoáy sương mù, sương mù hóa thành đám mây trắng bay đi. Đây là biểu hiện đầu tiên của khả năng dung hợp/biến đổi vật chất.","congNang":[],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1245","denChuong":"@c1245","cachCoDuoc":"Lam Mộng Đạo Tôn để lại","trangThai":"đã biến đổi/tiêu hủy"}],"capNhatToi":"@c1245","tabs":{"tienTrinh":[{"chuong":"@c1245","loai":"dùng","importance":"normal","giaiDoan":"Bị Vương Lâm dùng đạo thuật dung hợp biến thành mây trắng","text":"Vương Lâm cầm thanh kiếm băng, dùng đạo thuật dung hợp biến kiếm thành mảnh băng, nước mưa, sương mù rồi đám mây trắng bay đi — biểu hiện đầu tiên của đạo thuật dung hợp.","anchor":"từ bên trong tinh thể băng kia truyền ra âm thanh tách tách, trên đó bất chợt có rất nhiều vết nứt xuất hiện"}]},"nguon":["@c1245"]},{"id":"nua-dot-ngon-tay-co-than","name":"Nửa đốt ngón tay Cổ Thần","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"Chí bảo cấp Cổ Thần","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Nửa đốt ngón tay chứa khí tức Cổ Thần nồng đậm thực chất hóa, kích cỡ so được với tu chân tinh. Bên trong có ý chí tồn tại chống lại mọi sự cắn nuốt hấp thụ.","detail":"Vương Lâm lấy từ khe trữ vật, kích cỡ sánh ngang tu chân tinh. Khí tức Cổ Thần bên trong nồng đậm đến mức thực chất hóa. Chứa ý chí tồn tại không cho cắn nuốt. Vương Lâm dùng tinh điểm Cổ Thần trên mi tâm thử hấp thụ nhưng thất bại. Thác Sâm trước đó cũng muốn dùng tinh điểm nuốt nhưng gặp khó vì ý chí bên trong.","congNang":["Chứa khí tức Cổ Thần nồng đậm thực chất hóa"],"dacDiem":"Ý chí tồn tại bên trong chống cắn nuốt, kích cỡ sánh ngang tu chân tinh","tabs":{"tienTrinh":[{"chuong":"@c1247","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm thử hấp thụ — thất bại","text":"Vương Lâm lấy nửa đốt ngón tay ra, dùng tinh điểm Cổ Thần trên mi tâm thử hấp thụ nhưng thất bại vì ý chí bên trong chống lại.","anchor":"đốt ngón tay rất lớn từ bên trong cái khe chậm rãi bay ra, trôi giữa không trung, nhìn giống như một khối đại lục"}]},"nguon":["@c1247"]},{"id":"linh-chung","name":"Linh Chủng","cn":"灵种","category":"khac","categoryLabel":"Vật phẩm đặc thù","phamCap":"Không rõ","soHuu":["Nguyệt Phệ Tộc"],"trangThai":"dang-co","blurb":"Vật thể ký sinh trong cơ thể Nguyệt Phệ Tộc, là điều kiện bắt buộc để tu luyện Thanh Vân Linh Thuật hấp thụ sức mạnh Cổ Thần.","detail":"Linh Chủng do đám người thần bí để lại cho Nguyệt Tộc khi trợ giúp họ nổi loạn chống Cổ Thần. Ký sinh trong cơ thể người Nguyệt Tộc, được trồng ngày càng nhiều qua các thế hệ. Là điều kiện tiên quyết tu luyện Thanh Vân Linh Thuật.","nguon":["@c1248"]},{"id":"ngoc-boi-bach-y-nu-tu","name":"Ngọc bội (Bạch Y Nữ Tử)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nữ tử áo trắng"],"trangThai":"hu-ton","blurb":"Ngọc bội do phân thân Bạch Y Nữ Tử phun ra từ miệng, vừa hình thành phòng hộ trắng bảo vệ chủ nhân, vừa là vật liên kết bổn tôn, cho phép bổn tôn phóng chiếu cánh tay qua ngọc bội tấn công. Dù bị huyết kiếm đánh nứt, ngọc bội vẫn duy trì chức năng liên kết bổn tôn.","detail":"Ngọc bội được phân thân Bạch Y Nữ Tử phun ra từ miệng, hình thành một tầng phòng hộ trắng chống lại Phiên Thiên Ấn và cản trường kiếm đen bị chiết xạ ngược. Ngọc bội từng bị huyết kiếm của Vương Lâm đánh nứt nhưng vẫn tiếp tục hoạt động. Khi phân thân kêu cứu, từ ngọc bội hiện ra cánh tay trắng như ngọc của bổn tôn, ấn ngón tay xuống với uy lực kinh thiên, xuyên phá hoàn toàn Quang Ảnh Thuẫn.","hinhDang":"Ngọc bội","congNang":["Hình thành phòng hộ trắng bao bọc chủ nhân, chống lại Phiên Thiên Ấn và cản trường kiếm đen bị chiết xạ ngược @c1249","Liên kết bổn tôn, cho phép bổn tôn phóng chiếu cánh tay trắng qua ngọc bội để tấn công @c1249"],"dacDiem":"Bị huyết kiếm đánh nứt nhưng vẫn duy trì chức năng liên kết bổn tôn","chuSoHuu":[{"ten":"Nữ tử áo trắng","tuChuong":"@c1249","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1249","loai":"dùng","importance":"major","giaiDoan":"Xuất hiện + bị hư tổn + bổn tôn phóng chiếu","phamCap":"","text":"Bạch Y Nữ Tử phun ngọc bội phòng hộ chống Phiên Thiên Ấn, bị huyết kiếm đánh nứt. Phân thân kêu cứu, từ ngọc bội hiện ra cánh tay bổn tôn ấn ngón tay uy lực vượt Thủy Đạo Tử, xuyên phá Quang Ảnh Thuẫn.","anchor":"Một cánh tay trắng như ngọc từ trong ngọc bội hiện ra, hướng về phía Vương Lâm điểm một cái"}]},"nguon":["@c1249"],"uyLuc":"Cánh tay trắng hiện ra từ ngọc bội ấn ngón tay xuống với uy lực kinh thiên vượt cả Thủy Đạo Tử, xuyên phá Quang Ảnh Thuẫn hoàn toàn @c1249"},{"id":"an-ky-chu-xuyen","name":"Ấn ký hình chữ Xuyên","cn":"穿字印记","aliases":[],"category":"khac","categoryLabel":"Ấn ký","phamCap":"Không rõ","soHuu":["Bạch Y Nữ Tử"],"trangThai":"Đã kích hoạt (trước khi vật chủ tử vong)","blurb":"Ấn ký xuất hiện trên mi tâm Bạch Y Nữ Tử trong lúc nguy cấp, phát ba đạo ánh sáng đỏ, vàng, lam, kích hoạt ký ức bị phong ấn và bùng phát khí tức trắng sữa hỗ trợ phòng ngự/thoát thân.","detail":"Ấn ký có hình chữ “xuyên”, vốn không hiện trên mi tâm trơn nhẵn của Bạch Y Nữ Tử, chỉ lộ ra khi nàng lâm vào tình thế chí nguy. Khi kích hoạt, ấn ký phóng ra ba đạo ánh sáng đỏ, vàng, lam đồng thời khơi dậy ký ức bị phong ấn: nàng từng là thánh nữ bộ tộc, bị một bàn tay trắng nõn xóa tộc ấn gốc rồi thay bằng ấn ký này, biến nàng thành phân thân nuôi dưỡng hình chiếu và cánh cửa hương hỏa. Khí tức trắng sữa bùng lên từ ấn ký đủ sức đối kháng nắm đấm bổn nguyên của Vương Lâm và hỗ trợ na di thoát thân.","nguon":["@c1251"]},{"id":"kim-tuyen-phan-than-lan-phi","name":"Kim tuyến phân thân Lan Phi","cn":"金线","aliases":["Kim tuyến"],"category":"khac","categoryLabel":"Vật ký sinh","phamCap":"Không rõ","soHuu":["Lan Phi"],"trangThai":"Bị Ngân Y Nữ Thi nuốt","blurb":"Phân thân của Lan Phi (Viễn Cổ Bát Phi) ký sinh trong cơ thể Bạch Y Nữ Tử, khi vật chủ chết hóa thành kim tuyến phi vật chất lao vào hư vô, bị Ngân Y Nữ Thi bắt và nuốt.","detail":"Kim tuyến này là phân thân của Lan Phi trong Viễn Cổ Bát Phi, ký sinh bên trong cơ thể Bạch Y Nữ Tử. Khi vật chủ tử vong, kim tuyến thoát ra và lao vào hư vô định quay về bên người Lan Phi để trị thương. Kim tuyến có tính chất phi vật chất — huyết kiếm của Vương Lâm xuyên qua mà không gây bất kỳ thương tổn nào. Tuy nhiên Ngân Y Nữ Thi tùy ý giơ tay túm một cái liền kéo kim tuyến đã biến mất trong hư vô quay trở lại; kim tuyến run rẩy sợ hãi trong tay nàng. Ngân Y Nữ Thi vuốt nhẹ, kim tuyến tan vỡ hóa sương vàng chui vào thất khiếu nàng, nàng nói khí tức kim tuyến rất quen thuộc.","nguon":["@c1251"]},{"id":"thiem-dien-van-nam-bat-diet","name":"Đạo thiểm điện vạn năm bất diệt","cn":"闪电","aliases":["Thánh vật Thiểm Lôi Tộc"],"category":"than-khi","categoryLabel":"Thánh vật","phamCap":"Thánh vật tộc","soHuu":["Thiểm Lôi Tộc"],"trangThai":"Tồn tại trong Thiểm Lôi Tộc, bị Vương Lâm nhắm làm mục tiêu","blurb":"Thánh vật của Thiểm Lôi Tộc, tồn tại từ khai thiên lập địa, vạn vạn năm bất diệt, thủy chung xuyên qua trời đất, là nguồn suối sức mạnh toàn tộc.","detail":"Đạo thiểm điện này vạn vạn năm bất diệt, thủy chung xuyên qua trời đất, là thánh vật của Thiểm Lôi Tộc và cũng là nguồn suối sức mạnh của toàn bộ bộ tộc. Vương Lâm từ trí nhớ của những tu sĩ bị cắn nuốt mà biết được sự tồn tại của nó, nhận định nếu nuốt được đạo thiểm điện này sẽ khiến lôi bổn nguyên tiến thêm một bước lớn. Do Thiểm Lôi Tộc không có tu sĩ Đệ Tam Bộ, Vương Lâm quyết định lấy đây làm mục tiêu tiếp theo.","nguon":["@c1251"]},{"id":"loi-qua","name":"Lôi quả","cn":"雷果","category":"nguyen-lieu","categoryLabel":"Linh quả","phamCap":"Không rõ","soHuu":["Tề Trì"],"trangThai":"con-nguyen","blurb":"Quả từ cây lôi quả, to bằng nắm tay, màu xanh sậm, phát ra sấm sét yếu. Nuốt vào sẽ mở rộng tộc ấn và tăng tuổi thọ cho người Thiểm Lôi Tộc.","detail":"Lôi quả sinh trưởng trên cây lôi quả mọc ở vách đá sơn cốc, thân cây thò ra ngoài bảy thước. Quả to bằng nắm tay, màu xanh sậm, bề mặt phát ra sấm sét yếu ớt. Khi tu sĩ Thiểm Lôi Tộc nuốt lôi quả, tộc ấn trên mi tâm sẽ được mở rộng thêm, đồng thời tuổi thọ cũng tăng lên. Tuy nhiên cây lôi quả cần được tu sĩ tối thiểu cảnh giới Kết Đan tẩm bổ sấm sét để nuôi dưỡng. Vu Phi từng trồng chín cây, vừa nuốt một quả thì bị Tề Trì đánh trọng thương và cướp mất động phủ. Khi Vương Lâm chiếm lại động phủ, trên cây còn sáu quả.","nguon":["@c1253","@c1254"],"tabs":{"tienTrinh":[{"chuong":"@c1254","loai":"xuat-hien","importance":"normal","giaiDoan":"Được Vương Lâm khảo sát","text":"Vương Lâm hái một Lôi quả trong động phủ Tề Trì, bóp vỡ hấp thu sấm sét vào nguyên thần. Nhận định một quả đổi được một khối Lôi Tinh.","anchor":"một Lôi quả có thể đổi lấy một khối Lôi Tinh"}]},"congNang":["Cải thiện thể chất thích hợp thi triển thần thông sấm sét","Hấp thu sấm sét vào nguyên thần (cách dùng của Vương Lâm)"]},{"id":"thiem-loi-bang","name":"Thiểm Lôi Bảng","cn":"闪雷榜","category":"khac","categoryLabel":"Ngọc giản / Bảng xếp hạng","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Lấy từ mi tâm Tề Trì, đang do Vương Lâm nắm giữ","blurb":"Ngọc giản chứa trận pháp liên kết thiên địa, hiển thị danh sách 800 người xếp theo Lôi Tinh, nội dung thay đổi theo thời gian thực.","detail":"Thiểm Lôi Bảng là một ngọc giản đặc biệt ẩn chứa trận pháp có thể vận chuyển bất cứ lúc nào, mơ hồ dung hợp cùng thiên địa. Bảng hiển thị danh sách 800 người trên 13 tu chân tinh của Thiểm Lôi Tộc, xếp hạng theo số Lôi Tinh tích lũy. Cứ mỗi trăm năm, người đứng đầu bảng được vào thánh địa tiếp xúc sấm sét bất diệt. Nội dung bảng thay đổi theo thời gian thực. Người đứng đầu hiện tại là Vân Sam Tử với 19,7 tỷ Lôi Tinh, thứ hai là Phù Dung với 13,9 tỷ, vị trí 800 cũng hơn 40 vạn Lôi Tinh. Còn 7 năm nữa sẽ diễn ra tranh đoạt. Vương Lâm lấy ngọc giản này từ trong ký hiệu mi tâm của Tề Trì sau khi chế phục lão.","nguon":["@c1253"]},{"id":"canh-cay-loi-quang","name":"Cành cây Lôi quang","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đã bị Vương Lâm thu","blurb":"Cành cây to như cánh tay, lóe Lôi quang, Chung Đại Hồng cất giấu kỹ rồi dâng cho Vương Lâm, cùng đan dược tử quang tổng cộng đổi được một vạn Lôi tinh.","detail":"Một trong hai vật phẩm Chung Đại Hồng giấu riêng, dâng cho Vương Lâm khi bị ép giao nộp toàn bộ vật đổi Lôi tinh tại Thiên Lôi Tông.","congNang":["Đổi Lôi tinh (cùng đan dược tử quang tổng một vạn Lôi tinh)"],"chuSoHuu":[{"ten":"Chung Đại Hồng","tuChuong":"@c1255","denChuong":"@c1255","cachCoDuoc":"Sở hữu sẵn","trangThai":"da-giao"},{"ten":"Vương Lâm","tuChuong":"@c1255","denChuong":"","cachCoDuoc":"Chung Đại Hồng dâng nộp","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1255","loai":"đổi chủ","importance":"normal","giaiDoan":"Chung Đại Hồng dâng nộp cho Vương Lâm","text":"Chung Đại Hồng lấy ra cành cây Lôi quang cất giấu kỹ dâng cho Vương Lâm, cùng đan dược tử quang tổng cộng đổi được một vạn Lôi tinh.","anchor":"vật phẩm đầu tiên là một cành cây to như cánh tay và lóe lên Lôi quang"}]},"nguon":["@c1255"]},{"id":"phi-kiem-sac-ben","name":"Phi kiếm sắc bén","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đã bị Vương Lâm thu","blurb":"Thanh phi kiếm cực kỳ sắc bén bùng ra khí tức lạnh lẽo, Chung Đại Hồng dâng cho Vương Lâm, có thể đổi lấy mười vạn Lôi tinh.","detail":"Phi kiếm Chung Đại Hồng giao nộp cho Vương Lâm tại quảng trường Thiên Lôi Tông, giá trị đổi mười vạn Lôi tinh.","congNang":["Phi kiếm chiến đấu, khí tức lạnh lẽo","Đổi được mười vạn Lôi tinh"],"chuSoHuu":[{"ten":"Chung Đại Hồng","tuChuong":"@c1255","denChuong":"@c1255","cachCoDuoc":"Sở hữu sẵn","trangThai":"da-giao"},{"ten":"Vương Lâm","tuChuong":"@c1255","denChuong":"","cachCoDuoc":"Chung Đại Hồng dâng nộp","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1255","loai":"đổi chủ","importance":"normal","giaiDoan":"Chung Đại Hồng dâng nộp cho Vương Lâm","text":"Chung Đại Hồng dâng thanh phi kiếm cực kỳ sắc bén cho Vương Lâm, đổi được mười vạn Lôi tinh.","anchor":"Trong ô quang là một thanh phi kiếm cực kỳ sắc bén, đồng thời còn bùng ra những luồng khí tức cực kỳ lạnh lẽo"}]},"nguon":["@c1255"]},{"id":"ham-hon-dan","name":"Hàm Hồn đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Chung Đại Hồng"],"trangThai":"Đã tặng cho Chung Đại Hồng","blurb":"Đan dược Vương Lâm luyện chế tiện tay bằng thú hồn cấp bốn trên Vân Hải tinh vực, có thể đổi hai vạn Lôi tinh, cực kỳ hiếm.","detail":"Vương Lâm tặng cho Chung Đại Hồng để buộc hắn tận tâm sưu tập vật phẩm của Thiểm Lôi Tộc đổi Lôi tinh, tránh dùng đan dược mình đổi trực tiếp sẽ tăng thực lực cho Thiểm Lôi Tộc.","congNang":["Đổi được hai vạn Lôi tinh, cực kỳ hiếm"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1255","denChuong":"@c1255","cachCoDuoc":"Tự luyện chế bằng thú hồn cấp bốn trên Vân Hải tinh vực","trangThai":"da-giao"},{"ten":"Chung Đại Hồng","tuChuong":"@c1255","denChuong":"","cachCoDuoc":"Vương Lâm ban tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1255","loai":"đổi chủ","importance":"normal","giaiDoan":"Vương Lâm tặng cho Chung Đại Hồng","text":"Vương Lâm lấy ra Hàm Hồn đan luyện chế tiện tay, tặng cho Chung Đại Hồng để buộc hắn sưu tập vật đổi Lôi tinh.","anchor":"Hàm Hồn đan! Đan dược này có thể đổi lấy hai vạn Lôi tinh. hơn nữa lại cực kỳ hiếm có"}]},"nguon":["@c1255"]},{"id":"phi-kiem-ban-chung-dai-hong","name":"Thanh phi kiếm (Vương Lâm ban Chung Đại Hồng)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tầm thường (đối với Vương Lâm), bảo vật khủng bố (đối với Đệ Nhất Bộ)","soHuu":["Chung Đại Hồng"],"trangThai":"dang-dung","blurb":"Thanh phi kiếm Vương Lâm ban cho Chung Đại Hồng, tầm thường với Vương Lâm nhưng là bảo vật khủng bố đối với tu sĩ Đệ Nhất Bộ, giúp Chung Đại Hồng chiến đấu ngang Hóa Thần trung kỳ.","detail":"Một thanh phi kiếm rất tầm thường đối với Vương Lâm, nhưng đối với tu sĩ Đệ Nhất Bộ thì là bảo vật khủng bố. Vương Lâm ban cho Chung Đại Hồng (tu vi Hóa Thần) để hắn đi thu gom vật phẩm đổi Lôi tinh. Nhờ thanh kiếm này, Chung Đại Hồng có thể chiến đấu ngang Hóa Thần trung kỳ và chống đỡ được Hóa Thần hậu kỳ.","congNang":["Tăng chiến lực Chung Đại Hồng từ Hóa Thần lên ngang Hóa Thần trung kỳ, chống đỡ được Hóa Thần hậu kỳ"],"chuSoHuu":[{"ten":"Chung Đại Hồng","tuChuong":"@c1256","denChuong":"","cachCoDuoc":"Vương Lâm ban cho","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1256","loai":"đổi chủ","importance":"normal","giaiDoan":"Vương Lâm ban cho Chung Đại Hồng","text":"Vương Lâm ban cho Chung Đại Hồng thanh phi kiếm tầm thường, nhờ đó Chung Đại Hồng chiến lực ngang Hóa Thần trung kỳ, chống đỡ được Hóa Thần hậu kỳ.","anchor":"Kiếm này rất tầm thường nhưng đối với tu sĩ Đệ Nhất Bộ thì chính là bảo vật kh*ng b*"}]},"nguon":["@c1256"]},{"id":"loi-tinh","name":"Lôi tinh","cn":"雷晶","aliases":[],"category":"khac","categoryLabel":"Tiền tệ / Vật phẩm giao dịch","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Đơn vị giao dịch duy nhất trong Thiểm Lôi Tộc, chỉ có thể đổi tại Lôi Tinh Điện trong ba ngày mở cửa mỗi năm, không thể mang đi hay giao dịch riêng tư.","detail":"Lôi tinh là đơn vị tiền tệ và giao dịch của Thiểm Lôi Tộc. Mỗi năm Lôi Tinh Điện chỉ mở ba ngày để tộc nhân mang vật phẩm đến đổi lấy Lôi tinh. Lôi tinh không thể mang đi, không thể giao dịch riêng tư — chỉ có thể giao dịch qua Lôi Tinh Điện. Tuy nhiên, những lão quái tu vi cao thâm có phương pháp lén lút giao dịch bằng vật phẩm có giá trị Lôi tinh tương ứng, nhưng rất nguy hiểm. Dùng để mua pháp bảo và công pháp của Thiểm Lôi Tộc.","congNang":["Đơn vị tiền tệ duy nhất của Thiểm Lôi Tộc, dùng để đổi pháp bảo và công pháp tại Lôi Tinh Điện"],"dacDiem":"Không thể mang đi, chỉ giao dịch qua Lôi Tinh Điện, mỗi năm chỉ giao dịch được ba ngày","tabs":{"tienTrinh":[{"chuong":"@c1258","loai":"xuất hiện","importance":"normal","giaiDoan":"Giới thiệu hệ thống tiền tệ Thiểm Lôi Tộc","text":"Được giới thiệu là đơn vị giao dịch duy nhất trong Thiểm Lôi Tộc, chỉ có thể đổi tại Lôi Tinh Điện trong ba ngày mở cửa mỗi năm.","anchor":"Lôi tinh không thể nào đem đi, chỉ có thể giao dịch với Lôi Tinh Điện mà thôi"}]},"dinhDanh":"goc","capNhatToi":"@c1258","nguon":["@c1258"]},{"id":"ngoc-gian-thiem-loi-bang","name":"Ngọc giản Thiểm Lôi Bảng","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Tộc nhân Thiểm Lôi Tộc"],"trangThai":"dang-dung","blurb":"Ngọc giản của tộc nhân Thiểm Lôi Tộc, tự động hiển thị bảng xếp hạng Lôi tinh, bùng sóng gợn khi bảng thay đổi.","detail":"Mỗi tộc nhân Thiểm Lôi Tộc trên tất cả tu chân tinh đều sở hữu một khối ngọc giản Thiểm Lôi Bảng. Khi bảng xếp hạng thay đổi, ngọc giản lập tức bùng ra những con sóng gợn báo hiệu. Hiển thị tám trăm vị trí cùng số lượng Lôi tinh tương ứng.","congNang":["Tự động hiển thị thứ hạng Lôi tinh toàn tộc trên các tu chân tinh","Bùng sóng gợn khi có biến động bảng xếp hạng"],"tabs":{"tienTrinh":[{"chuong":"@c1259","loai":"xuất hiện","importance":"normal","giaiDoan":"Bảng biến động khi Vu Phi lọt vào","text":"Ngọc giản Thiểm Lôi Bảng trên tất cả tu chân tinh đồng loạt bùng sóng gợn báo hiệu bảng xếp hạng thay đổi, tên Vu Phi xuất hiện ở vị trí 799.","anchor":"Đúng lúc này tất cả ngọc giản Thiểm Lôi Bảng của tộc nhân Thiểm Lôi Tộc trên tất cả tu chân tinh lập tức bùng ra những con sóng gợn"}]},"capNhatToi":"@c1259","nguon":["@c1259"]},{"id":"ngoc-gian-menh-hon-vu-phi","name":"Ngọc giản mệnh hồn Vu Phi","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-dung","blurb":"Ngọc giản có chứa mệnh hồn của Vu Phi, dùng để ghi chép Lôi tinh khi đổi vật phẩm tại ao đen cửa đông Lôi Tinh Điện.","detail":"Vốn là vật của Vu Phi, trên đó có mệnh hồn. Vương Lâm chiếm dụng, dùng nó ném vào ao đen để đổi lượng lớn vật phẩm lấy Lôi tinh. Sau khi ao nuốt vật phẩm, trả lại ngọc giản đã ghi chép số lượng Lôi tinh đổi được.","congNang":["Ghi chép lượng Lôi tinh đổi được tại ao đen cửa đông Lôi Tinh Điện"],"chuSoHuu":[{"ten":"Vu Phi","tuChuong":"@c1252","denChuong":"@c1252","cachCoDuoc":"Vật gốc","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1252","denChuong":"","cachCoDuoc":"Chiếm dụng sau khi giết Vu Phi","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1259","loai":"dùng","importance":"normal","giaiDoan":"Dùng đổi Lôi tinh tại cửa đông","text":"Vương Lâm ném ngọc giản mệnh hồn Vu Phi vào ao đen cửa đông Lôi Tinh Điện, đổi lượng lớn vật phẩm lấy Lôi tinh, chính thức lên Thiểm Lôi Bảng dưới tên Vu Phi.","anchor":"hắn khẽ lật tay phải và lấy ra một khối ngọc giản, thứ này là vật của Vu Phi, trên đó có mệnh hồn, là vật để ghi chép Lôi tinh"}]},"capNhatToi":"@c1259","nguon":["@c1259"]},{"id":"tu-loi-hoan","name":"Tụ Lôi Hoàn","cn":"聚雷丸","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Lôi cầu như ngón tay cái do lão già Dương Thực cửa đông Lôi Tinh Điện tự luyện hóa, nén 8900 lần, tặng Vương Lâm phòng thân.","detail":"Tụ Lôi Hoàn hình dạng như lôi cầu cỡ ngón tay cái, do một trong ba lão già Dương Thực phụ trách cửa đông Lôi Tinh Điện tự tay luyện hóa. Đã được nén lại tám ngàn chín trăm lần, tặng cho người mới lên Thiểm Lôi Bảng để phòng thân.","congNang":["Phòng thân, lôi cầu nén 8900 lần"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1260","denChuong":"","cachCoDuoc":"Được lão già Dương Thực cửa đông tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1260","loai":"xuất hiện","importance":"normal","giaiDoan":"Lão già Dương Thực tặng Vương Lâm","text":"Lão già thứ nhất cửa đông tặng Vương Lâm Tụ Lôi Hoàn do lão tự luyện hóa, nén 8900 lần, dùng phòng thân.","anchor":"Đây là Tụ Lôi Hoàn được lão phu tự mình luyện hóa, đã nén lại tám ngàn chín trăm lần, tặng ngươi để phòng thân"}]},"nguon":["@c1260"]},{"id":"ngoc-gian-nhiem-vu-bay-tram-van","name":"Ngọc giản nhiệm vụ (bảy trăm vạn thiên địa)","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản mà Vương Lâm nhận từ Dương Thực, dùng xác nhận thân phận Vu Phi và làm thông hành vào bảy trăm vạn thiên địa.","detail":"Ngọc giản nhận từ tiểu bối Dương Thực Thiểm Lôi Tộc, chứa lời truyền âm của Hạo Nhiên đạo hữu khen ngợi Vương Lâm. Đưa cho lão tu sĩ cửa Tây xác nhận thân phận. Khi Chu Thiên Tử vào, ngọc giản bùng hào quang chói mắt, Vương Lâm chộp lại dùng để tiến vào bảy trăm vạn thiên địa.","congNang":["Chứng nhận thân phận Vu Phi, làm thông hành vào bảy trăm vạn thiên địa"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1261","denChuong":"","cachCoDuoc":"Nhận từ Dương Thực","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1261","loai":"dùng","importance":"normal","giaiDoan":"Dùng tại cửa Tây","text":"Vương Lâm đưa ngọc giản cho lão tu sĩ cửa Tây xác nhận thân phận Vu Phi, sau đó chộp lại khi ngọc giản bùng hào quang, dùng làm thông hành vào bảy trăm vạn thiên địa.","anchor":"ngọc giản nhiệm vụ bùng ra những luồng hào quang chói mắt bị Vương Lâm chộp vào trong tay"}]},"nguon":["@c1261"]},{"id":"linh-niem-loi","name":"Linh Niệm Lôi","cn":"灵念雷","category":"khac","categoryLabel":"Vật phẩm đặc thù","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Linh Niệm Lôi là một tia chớp nhỏ hình dáng tựa sinh linh, nhìn thấy được nhưng chạm vào lại vô hình. Bên trong ẩn chứa trận pháp sấm sét mạnh ngang lôi trì mười vạn dặm cùng một ý niệm sinh cơ cố chấp với sinh mệnh; phải thu thập đủ một ngàn luồng mới ngưng tụ thành niệm lôi hoàn chỉnh.","detail":"Linh Niệm Lôi là vật mà mỗi tộc nhân Thiểm Lôi Tộc được phát duy nhất một luồng khi lần đầu bước vào bảy trăm vạn thiên địa, cả đời chỉ có một cơ hội nhận; đánh mất thì phải cướp hoặc trao đổi lén, đây vốn là tộc quy nhằm phòng ngừa và bảo vệ. Tại chương @c1262, Vương Lâm mạo danh Vu Phi để nhận một luồng Linh Niệm Lôi, sau đó nghiên cứu và nhận ra nó tựa như một sinh linh mang trong mình ý niệm cố chấp đối với sinh mệnh. Mỗi luồng riêng lẻ chưa phải niệm lôi hoàn chỉnh mà cần gom đủ một ngàn luồng mới có thể ngưng tụ thành hình trọn vẹn.","congNang":["Thu thập đủ một ngàn luồng để ngưng tụ thành niệm lôi hoàn chỉnh @c1262"],"dacDiem":"Vô hình khi chạm, chứa ý niệm sinh linh và trận pháp sấm sét ngang lôi trì mười vạn dặm.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1262","denChuong":"","cachCoDuoc":"Được phát khi mạo danh Vu Phi vào bảy trăm vạn thiên địa","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1262","loai":"xuất hiện","importance":"major","giaiDoan":"Phát cho tộc nhân mới đến","text":"Vương Lâm mạo danh Vu Phi nhận Linh Niệm Lôi, nghiên cứu nhận ra nó giống sinh linh chứa ý niệm sinh cơ, cần thu thập đủ 1000 luồng mới thành niệm lôi hoàn chỉnh.","anchor":"Tia chớp này được Vương Lâm cầm trong tay, giống như nó không hẳn là tia chớp mà chính là một sinh linh"}]},"dinhDanh":"goc","capNhatToi":"@c1262","nguon":["@c1262"],"uyLuc":"Chứa trận pháp sấm sét mạnh ngang lôi trì mười vạn dặm."},{"id":"phi-kiem-tien-pham-loi-tinh-dien","name":"Phi kiếm tiên phẩm (Lôi Tinh Điện)","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tiên phẩm","soHuu":[],"trangThai":"chua-co","blurb":"Bốn thanh phi kiếm tiên phẩm có thể đổi tại Lôi Tinh Điện bằng Linh Niệm Lôi, là mục tiêu nhóm Trương Cảnh Vân lừa người mới thu niệm lôi để gộp đổi lấy.","detail":"Nhóm Trương Cảnh Vân bàn mưu thu niệm lôi của đám người mới, gộp lại thành Linh Niệm Lôi rồi đến Lôi Tinh Điện đổi lấy bốn thanh phi kiếm tiên phẩm.","congNang":["Phi kiếm chiến đấu phẩm cấp tiên phẩm"],"tabs":{"tienTrinh":[{"chuong":"@c1263","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhóm Trương Cảnh Vân nhắc đến khi bàn mưu","text":"Nhóm Trương Cảnh Vân bàn mưu thu niệm lôi của người mới để gộp thành Linh Niệm Lôi, đến Lôi Tinh Điện đổi lấy bốn thanh phi kiếm tiên phẩm.","anchor":"có thể đi đến Lôi Tinh Điện đổi lấy bốn thanh phi kiếm tiên phẩm"}]},"nguon":["@c1263"]},{"id":"linh-niem-loi-dung-hop","name":"Linh Niệm Lôi (dung hợp hoàn chỉnh)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Linh Niệm Lôi là loại sấm sét thứ chín trong Cửu đạo lôi. Gần ngàn luồng Linh Niệm Lôi được Vương Lâm dung hợp thành một luồng hoàn chỉnh, mang hình quả cầu khói xoay tròn bên trong hiện nhiều gương mặt, đã phóng xuyên mắt phải Vương Lâm nhập nguyên thần (@c1265).","detail":"Gần ngàn luồng Linh Niệm Lôi thu được từ tộc ấn Thiểm Lôi Tộc được Vương Lâm vung tay dung hợp thành một luồng duy nhất, hình dạng quả cầu khói xoay tròn bên trong hiện ra nhiều gương mặt. Khi sấm sét trong nguyên thần Vương Lâm lóe sáng, quả cầu tự phóng xuyên mắt phải dung nhập nguyên thần, hợp nhất với sấm sét và khai mở ký ức lôi bản nguyên từ thuở thiên địa sơ khai (@c1265). Đây là loại sấm sét thứ chín trong Cửu đạo lôi.","congNang":["Dung nhập nguyên thần qua mắt phải, hợp nhất với sấm sét, khai mở ký ức lôi bản nguyên thái cổ (@c1265)","Tăng trưởng lôi bản nguyên"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1265","denChuong":"","cachCoDuoc":"Dung hợp gần ngàn luồng Linh Niệm Lôi từ tộc ấn Thiểm Lôi Tộc","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1265","loai":"dung","importance":"major","giaiDoan":"Dung hợp và nhập nguyên thần","text":"Gần ngàn Linh Niệm Lôi dung hợp thành một luồng hoàn chỉnh, tự phóng xuyên mắt phải Vương Lâm nhập nguyên thần, khai mở ký ức lôi bản nguyên thái cổ.","anchor":"giống như một làn khói xoay quanh tạo thành hình cầu, trong đó mơ hồ xuất hiện rất nhiều gương mặt"}]},"capNhatToi":"@c1265","dinhDanh":"goc","nguon":["@c1265"],"dacDiem":"Loại sấm sét thứ chín trong Cửu đạo lôi; sau dung hợp mang hình quả cầu khói xoay tròn, bên trong hiện nhiều gương mặt."},{"id":"hat-chau-loi-quang","name":"Hạt châu lôi quang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tiên nhân trên kiếp vân"],"trangThai":"hong","blurb":"Pháp bảo do năm luồng niệm lôi hóa thành, ẩn giấu sấm sét uy lực kinh thiên. Bị Vương Lâm bóp nát, năm luồng niệm lôi bị mắt phải hấp thu.","detail":"Hạt châu lôi quang ẩn giấu sấm sét, do năm luồng niệm lôi hóa thành. Thuộc về Tiên nhân Khuy Niết hậu kỳ đại viên mãn trên kiếp vân. Bị Vương Lâm bóp nát, năm luồng niệm lôi nhanh chóng bị mắt phải hấp thu.","congNang":["Ẩn giấu sấm sét, uy lực kinh thiên, do năm luồng niệm lôi hóa thành"],"chuSoHuu":[{"ten":"Tiên nhân trên kiếp vân","tuChuong":"@c1266","denChuong":"@c1266","cachCoDuoc":"Sở hữu ban đầu","trangThai":"tu-vong"},{"ten":"Vương Lâm","tuChuong":"@c1266","denChuong":"","cachCoDuoc":"Bóp nát hấp thu niệm lôi bên trong","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1266","loai":"xuat-hien","importance":"normal","giaiDoan":"Xuất hiện và bị phá hủy","text":"Tiên nhân Khuy Niết dùng hạt châu lôi quang tấn công Vương Lâm. Vương Lâm bóp nát, mắt phải hấp thu năm luồng niệm lôi bên trong.","anchor":"Hạt châu lôi quang ẩn giấu sấm sét là pháp bảo do năm luồng niệm lôi hóa thành"}]},"nguon":["@c1266"]},{"id":"linh-phu-huyet-sac","name":"Linh phù huyết sắc","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Linh phù huyết sắc là pháp bảo do Tán Linh Thượng Nhân tự hủy mấy vạn phân thân, ngưng tụ toàn bộ lực lượng mà thành, được trao cho Vương Lâm. Linh phù có khả năng mở đường vào bảy trăm vạn thiên địa bị phong ấn sau ba lần hít thở, tuy nhiên đường này chỉ vào được mà không ra được.","detail":"Tán Linh Thượng Nhân không chút do dự tự hủy mấy vạn phân thân — các tu sĩ phân thân của ông trong bảy trăm vạn thiên địa đồng loạt tan vỡ thành máu thịt — ngưng tụ toàn bộ lực lượng thành một linh phù mang sắc huyết, trao cho Vương Lâm (@c1268). Linh phù hoạt động bằng cách phối hợp với pháp thuật mà Tán Linh đã bố trí sẵn bên trong bảy trăm vạn thiên địa, chỉ cần ba lần hít thở là mở ra con đường đi vào khu vực bị phong ấn. Tuy nhiên, con đường do linh phù khai mở mang tính một chiều: chỉ cho phép đi vào mà không thể quay ra.","congNang":["Mở đường vào bảy trăm vạn thiên địa bị phong ấn sau ba lần hít thở, phối hợp pháp thuật của Tán Linh Thượng Nhân bên trong; đường này chỉ vào được, không ra được (@c1268)"],"hinhDang":"Linh phù màu huyết sắc","nguonGoc":"Do Tán Linh Thượng Nhân tự hủy mấy vạn phân thân ngưng tụ","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1268","denChuong":"","cachCoDuoc":"Tán Linh Thượng Nhân trao tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1268","loai":"xuất hiện","importance":"major","giaiDoan":"Tạo ra và trao cho Vương Lâm","text":"Tán Linh Thượng Nhân tự hủy mấy vạn phân thân ngưng tụ toàn bộ lực lượng thành linh phù huyết sắc trao cho Vương Lâm, cho phép mở đường vào bảy trăm vạn thiên địa.","anchor":"Ta tự hủy hai phân thân thì có thể ngưng tụ ra linh phù, dùng linh phù sẽ phối hợp pháp thuật với ta trong đây"}]},"nguon":["@c1268"]},{"id":"loi-sat-kinh","name":"Lôi Sát Kính","cn":"雷杀镜","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Nhị phẩm Thứ Không Niết (tiếp cận Niết phẩm)","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"trangThai":"Đã bị phá hủy","blurb":"Bảo vật trấn tộc Thiểm Lôi Tộc, chiếc gương cổ một mặt có thể phục chế mọi thần thông dưới Đệ Tam Bộ với uy lực ngang bản gốc và phản kích.","detail":"Chiếc gương cổ một mặt màu xanh, mặt sau khắc ký hiệu tia chớp giống sấm sét bất diệt. Được đại trưởng lão Thiểm Lôi Tộc cất giữ trong tộc ấn mi tâm. Công năng cốt lõi là phục chế bất kỳ thần thông nào dưới Đệ Tam Bộ đại năng với uy lực không kém bản gốc, đồng thời phản kích lại người thi triển. Tuy nhiên, lực lượng Cổ Thần nằm ngoài phạm vi phục chế — khi đại trưởng lão dùng Lôi Sát Kính phục chế lôi quyền của Vương Lâm, phần lực lượng Cổ Thần trong đó không thể bị sao chép, khiến bản sao yếu thế. Vương Lâm nương theo đó phun huyết kiếm chém nát Lôi Sát Kính, phá hủy hoàn toàn bảo vật này.","nguon":["@c1270"]},{"id":"van-gioi-phong-hon-tien","name":"Vạn Giới Phong Hồn Tiên","cn":"万界封魂鞭","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (siêu việt mọi phẩm cấp đã biết)","soHuu":["Vị thủ lĩnh tu sĩ thần bí (năm xưa)"],"trangThai":"Đã bị mang đi (bản gốc); Côn Cực Tiên của Vương Lâm là bản mô phỏng","blurb":"Bản gốc của Côn Cực Tiên, pháp bảo do vị thủ lĩnh đám tu sĩ thần bí năm xưa sử dụng, vung ba roi tạo ra bảy trăm vạn thiên địa.","detail":"Tên thật của cây roi mà vị thủ lĩnh nhóm tu sĩ thần bí sử dụng thời khai thiên. Trong hồi ức của đại trưởng lão Thiểm Lôi Tộc (khi còn là tu sĩ Hóa Thần): roi thứ nhất làm thiên địa tan vỡ, tinh không xuất hiện khe nứt, tạo ra bảy trăm vạn thiên địa; roi thứ hai phá vỡ hư vô, cuốn lấy vài sinh linh đặt vào bảy trăm vạn thiên địa (nhóm người đầu tiên); roi thứ ba đánh tan hình bóng khủng bố lao ra từ hư vô. Sau đó đám tu sĩ mang roi đi. Bản chất là vài tỷ hồn phách sinh linh dung hợp tạo thành, chuyên đánh nguyên thần và hồn phách. Côn Cực Tiên hiện tại của Vương Lâm là bản mô phỏng, không phải bản gốc — lớp ngoài u quang là vỏ bọc, khi vỡ lộ ra bản thể kim quang mang uy áp tương tự nhưng yếu hơn bản gốc.","nguon":["@c1270"]},{"id":"la-ban-sinh-menh-than-thong","name":"La bàn khổng lồ (Sinh Mệnh Thần Thông)","cn":null,"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (pháp khí tế tổ)","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"trangThai":"Triệu hoán khi thi triển Sinh Mệnh Thần Thông, biến mất sau khi hấp thu thọ nguyên","blurb":"La bàn vô biên vô hạn xuất hiện khi đại trưởng lão Thiểm Lôi Tộc thi triển Sinh Mệnh Thần Thông, hấp thu 500 năm thọ nguyên làm vật dẫn tế tổ rút sấm sét bất diệt.","detail":"La bàn khổng lồ vô biên vô hạn, bùng ra khí tức tang thương muôn đời, bên ngoài bị phá hoại nhiều chỗ như từng trải qua đại chiến. Xuất hiện khi đại trưởng lão thi triển Sinh Mệnh Thần Thông — hy sinh 500 năm thọ nguyên, la bàn hấp thu toàn bộ sinh cơ tản ra rồi biến mất, sau đó một luồng sấm sét bất diệt từ miếu thờ thánh địa được rút ra tấn công, phá tan bảy vạn tầng lưới sấm sét của Vương Lâm trong nháy mắt. Các tinh vực ngoài Thiểm Lôi Tộc đều có thể nhìn thấy la bàn này khi nó xuất hiện.","nguon":["@c1270"]},{"id":"bo-giap-sam-set-bat-diet","name":"Bộ giáp sấm sét bất diệt","cn":null,"aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo vật truyền thừa Đệ Tam Bộ (vượt xa Lôi Sát Kính)","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"trangThai":"Bị phá hủy hoàn toàn","blurb":"Bảo vật truyền thừa Đệ Tam Bộ Thiểm Lôi Tộc, bộ giáp phòng ngự mạnh vượt xa Lôi Sát Kính, bị kiếm thứ nhất của Trảm Thiên kiếm phá hủy hoàn toàn.","detail":"Bộ giáp sấm sét bất diệt là bảo vật truyền thừa của Đệ Tam Bộ Thiểm Lôi Tộc, phẩm cấp vượt xa Lôi Sát Kính. Đại trưởng lão Thiểm Lôi Tộc mặc giáp này trong trận chiến tại bảy trăm vạn thiên địa. Khi Vương Lâm cầm Trảm Thiên kiếm chém kiếm thứ nhất — kiếm quang mang theo linh hồn sinh linh — bộ giáp bị phá hủy hoàn toàn, đại trưởng lão lộ ra ba vết thương trước ngực lộ xương trắng.","nguon":["@c1271"]},{"id":"tieu-cau-huong-hoa","name":"Tiểu cầu hương hỏa","cn":null,"aliases":[],"category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đã sử dụng","blurb":"Tiểu cầu ngưng tụ từ toàn bộ lực lượng hương hỏa mà Vương Lâm rút ra khi diệt hồn phách trong Hô Phong Hoán Vũ, dùng để phá vỡ vòng xoáy Lục Đạo Thần Lôi.","detail":"Vương Lâm ra lệnh tất cả hồn phách trong Hô Phong Hoán Vũ diệt hồn dâng hiến lực lượng hương hỏa — bao gồm cả viễn cổ tiên phi bạch y nữ tử, nguồn hương hỏa lớn nhất. Lực lượng hương hỏa ngưng tụ thành tiểu cầu, là lực lượng đặc trưng của Đệ Tam Bộ đại năng, khiến đại trưởng lão Thiểm Lôi Tộc kinh hoàng. Vương Lâm ném tiểu cầu phá vỡ vòng xoáy Lục Đạo Thần Lôi, sau đó diệt toàn bộ hồn phách còn lại để bùng ra đợt hương hỏa thứ hai, tiêu diệt hoàn toàn Lục Đạo Thần Lôi.","nguon":["@c1271"]},{"id":"tram-thien-kiem","name":"Trảm Thiên kiếm","cn":"斩天剑","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (ngưng tụ từ Tuyệt Thiên trận + tính mạng hàng tỷ sinh linh)","soHuu":["Vương Lâm"],"trangThai":"Đang sử dụng","blurb":"Trường kiếm do Tán Linh ngưng tụ từ Tuyệt Thiên trận phong ấn bát hoang, chứa hy vọng và sinh mệnh của tất cả sinh linh bảy trăm vạn thiên địa, giao cho Vương Lâm thi triển Thất Kiếm Trảm Thiên Sơn.","detail":"Trảm Thiên kiếm được Tán Linh Thượng Nhân ngưng tụ khi dung hợp vào đại trận Tuyệt Thiên trận phong ấn bát hoang — lấy tính mạng tất cả sinh linh (hàng tỷ phàm nhân và tu sĩ) trên bảy trăm vạn thiên địa làm nguồn lực. Kiếm chính là trường kiếm bảy thước, chứa hy vọng của toàn bộ sinh linh tình nguyện hy sinh. Tán Linh nói đây là “bảy phần nắm chắc” hắn đã hứa trước. Mỗi kiếm chém ra, sinh linh bảy trăm vạn thiên địa dâng tính mệnh, nhiều người tử vong — kiếm thứ nhất phá hủy bộ giáp sấm sét bất diệt, các kiếm tiếp theo khiến đại trưởng lão Thiểm Lôi Tộc trọng thương liên tiếp. Vương Lâm cảm nhận kiếm rất nặng vì chứa sinh mệnh người tình nguyện hy sinh, linh hồn được gột rửa dưới âm thanh đau thương. Đến kiếm thứ sáu, uy lực khiến biên giới bảy trăm vạn thiên địa tan vỡ thành từng mảng, tinh không nứt rạn.","nguon":["@c1271"]},{"id":"thiem-loi-an","name":"Thiểm Lôi ấn","cn":null,"aliases":["Tộc ấn trên mi tâm"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tộc ấn truyền thừa Thiểm Lôi Tộc","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"trangThai":"Nổ hơn một nửa","blurb":"Tộc ấn trên mi tâm đại trưởng lão Thiểm Lôi Tộc, vỗ vào để triệu hồi Lục Đạo Thần Lôi và hóa thành thuật Đệ Tam Bộ — sấm sét âm dương bất diệt.","detail":"Tộc ấn nằm trên mi tâm đại trưởng lão Thiểm Lôi Tộc, là vật truyền thừa chứa lực lượng tộc nhân. Đại trưởng lão vỗ vào tộc ấn để triệu hồi Lục Đạo Thần Lôi (sáu loại sấm sét truyền thừa qua các thế hệ). Sau đó kích nổ một nửa tộc ấn để triệu hồi sấm sét bất diệt bên ngoài tấn công gió bão. Đại trưởng lão còn dâng 3.000 năm thọ nguyên hóa Thiểm Lôi ấn thành thuật Đệ Tam Bộ — Âm Dương đồ phân ra hai luồng sấm sét phá nguyên thần và thân thể. Đến cuối trận, tộc ấn đã nổ hơn một nửa.","nguon":["@c1271"]},{"id":"sam-set-bat-diet","name":"Sấm sét bất diệt","cn":"不灭雷电","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Thánh vật Thiểm Lôi tộc","soHuu":["Thiểm Lôi tộc"],"trangThai":"trong-thuong","blurb":"Sấm sét bất diệt là thánh vật của Thiểm Lôi tộc, một luồng sấm sét có linh trí, có thể đáp ứng tiếng gọi của nô bộc. Uy lực của nó ngang ngửa trường kiếm ngưng tụ lực toàn bộ bảy trăm vạn thiên địa, nhưng sau trận đối đầu đã bị trọng thương và rút về miếu thờ thánh địa Thiểm Lôi tộc.","detail":"Sấm sét bất diệt là thánh vật được Thiểm Lôi tộc tôn thờ, bản chất là một luồng sấm sét sở hữu linh trí, có khả năng cảm ứng và đáp lại tiếng gọi cứu viện của nô bộc trong tộc. Khi đại trưởng lão Thiểm Lôi tộc gầm gọi cứu viện, sấm sét bất diệt tự động kích hoạt, phóng to thành thần lôi vạn trượng phá vỡ phong ấn gió bão do Tán Linh thượng nhân duy trì, rồi phóng thẳng vào không gian bảy trăm vạn thiên địa đối đầu với trường kiếm bảy thước — vốn ngưng tụ toàn bộ sức mạnh của bảy trăm vạn thiên địa. Hai lực lượng uy lực ngang nhau cùng va chạm, kết quả là lưỡng bại câu thương: trường kiếm tan vỡ, còn sấm sét bất diệt bị trọng thương buộc phải rút về miếu thờ thánh địa Thiểm Lôi tộc. Sau đó, mười sáu tu chân tinh anh mở đại trận phong tỏa để bảo vệ thánh vật trong lúc hồi phục.","hinhDang":"Luồng sấm sét, có thể phóng to thành thần lôi vạn trượng","nguonGoc":"Thánh vật của Thiểm Lôi tộc","dacDiem":"Là luồng sấm sét có linh trí, có thể tự cảm ứng tiếng gọi và chủ động hành động; khi kích hoạt hóa thành thần lôi vạn trượng. Sau khi bị trọng thương, rút về miếu thờ thánh địa Thiểm Lôi tộc, được mười sáu tu chân tinh anh mở đại trận phong tỏa bảo vệ.","congNang":["Hóa thần lôi vạn trượng, phá vỡ phong ấn cấp cao như phong ấn gió bão do Tán Linh thượng nhân duy trì @c1272","Phóng vào không gian bảy trăm vạn thiên địa đối đầu trực diện kiếm khí cấp tiên (trường kiếm bảy thước) với uy lực ngang ngửa @c1272","Có linh trí, tự động cảm ứng và đáp lại tiếng gọi cứu viện của nô bộc Thiểm Lôi tộc @c1272"],"chuSoHuu":[{"ten":"Thiểm Lôi tộc","tuChuong":"@c1272","denChuong":"","cachCoDuoc":"Thánh vật bộ tộc","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1272","loai":"dùng","importance":"major","giaiDoan":"Đối đầu trường kiếm bảy thước, bị trọng thương","phamCap":"Thánh vật","text":"Nghe tiếng gọi đại trưởng lão, hóa thần lôi vạn trượng phá vỡ phong ấn gió bão. Phóng vào bảy trăm vạn thiên địa đối đầu trường kiếm bảy thước, cả hai cùng tổn thương. Bị trọng thương rút về miếu thờ thánh địa.","anchor":"luồng sấm sét bất diệt chợt phóng vào trong trời đất bảy trăm vạn thiên địa"}]},"nguon":["@c1272"],"uyLuc":"Uy lực ngang ngửa trường kiếm ngưng tụ lực toàn bộ bảy trăm vạn thiên địa; khi đối đầu, cả hai cùng tổn thương — trường kiếm tan vỡ, sấm sét bất diệt bị trọng thương."},{"id":"toc-an-thiem-loi-toc-vat","name":"Tộc ấn (Thiểm Lôi tộc)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Ấn ký bộ tộc","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"trangThai":"hong","blurb":"Tộc ấn của Thiểm Lôi tộc nằm trên mi tâm nguyên thần đại trưởng lão. Khi bị dồn vào tuyệt lộ, đại trưởng lão cho nổ tộc ấn, giải phóng lực lượng khổng lồ tương đương tu sĩ Nội giới tự bạo, giết sạch oan hồn bao vây và tu vi tăng vọt tạm thời.","detail":"Tộc ấn tồn tại trên mi tâm nguyên thần của đại trưởng lão Thiểm Lôi tộc. Trong cơn tuyệt vọng khi bị oan hồn bao vây, đại trưởng lão chủ động cho nổ tộc ấn. Lực lượng giải phóng khi tự bạo tương đương một tu sĩ Nội giới tự bạo, đủ sức quét sạch oan hồn xung quanh, đồng thời khiến tu vi tăng vọt trong thời gian ngắn và thân thể sấm sét được tái tạo. Tuy nhiên, do đặc thù của tu sĩ Thái Cổ Tinh Thần có điểm khác biệt nên đại trưởng lão không chết ngay sau khi cho nổ tộc ấn.","congNang":["Tự bạo giải phóng lực lượng khổng lồ tương đương tu sĩ Nội giới tự bạo, đủ sức giết sạch oan hồn bao vây @c1272","Tu vi tăng vọt tạm thời sau khi tộc ấn nổ @c1272","Thân thể sấm sét được tái tạo sau khi bạo phát @c1272"],"chuSoHuu":[{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tuChuong":"@c1272","denChuong":"@c1272","cachCoDuoc":"Ấn ký bộ tộc sẵn có","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c1272","loai":"dùng","importance":"major","giaiDoan":"Tự bạo trong trận chiến","text":"Đại trưởng lão cho nổ tộc ấn trên mi tâm nguyên thần trong cơn tuyệt vọng, giết sạch oan hồn, tu vi tăng vọt, thân thể sấm sét tái tạo.","anchor":"tộc ấn trên mi tâm nguyên thần đã nổ ầm ầm"}]},"nguon":["@c1272"],"uyLuc":"Khi tự bạo, lực lượng giải phóng tương đương tu sĩ Nội giới tự bạo, quét sạch toàn bộ oan hồn bao vây đại trưởng lão.","dacDiem":"Tộc ấn nằm trên mi tâm nguyên thần; do đặc thù tu sĩ Thái Cổ Tinh Thần, chủ nhân không chết ngay sau khi cho nổ tộc ấn."},{"id":"nguyen-than-dai-truong-lao-thiem-loi-toc","name":"Nguyên thần đại trưởng lão Thiểm Lôi tộc","cn":"","category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":"Thiên Nhân Đệ Ngũ Suy","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Nguyên thần Thiên Nhân Đệ Ngũ Suy bị tàn phá hơn phân nửa, trí nhớ tiêu tán, Vương Lâm thu lại bằng Côn Cực Tiên. Chứa cảm ngộ sấm sét, có thể dùng Tát Đậu Thành Binh, được đánh giá là cơ hội tạo hóa.","detail":"Nguyên thần đại trưởng lão Thiểm Lôi tộc bị kiếm khí gây thương tích trước đó rồi bị trùng kích sấm sét bất diệt và trường kiếm bảy thước đánh tan hơn phân nửa, sắp tiêu tán. Vương Lâm dùng Côn Cực Tiên hóa roi kim quang quét lại, chụp vào tay. Nguyên thần chứa cảm ngộ sấm sét cả đời tu sĩ Thiên Nhân Đệ Ngũ Suy, có thể khai thác hoặc dùng Tát Đậu Thành Binh tạo binh sĩ cực hùng mạnh.","congNang":["Dùng Tát Đậu Thành Binh tạo binh sĩ cực hùng mạnh","Khai thác cảm ngộ sấm sét của Thiên Nhân Đệ Ngũ Suy"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1273","denChuong":"","cachCoDuoc":"Thu bằng Côn Cực Tiên sau khi đánh bại","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1273","loai":"đổi chủ","importance":"normal","giaiDoan":"Vương Lâm thu nguyên thần","text":"Nguyên thần bị tàn phá hơn phân nửa, sắp tiêu tán. Vương Lâm dùng Côn Cực Tiên hóa roi kim quang quét lại và chụp vào tay, đánh giá là cơ hội tạo hóa.","anchor":"nguyên thần của đại trưởng lão Thiểm Lôi tộc có thể so sánh với những bảo vật cực kỳ quý giá"}]},"capNhatToi":"@c1273","nguon":["@c1273"]},{"id":"phan-tinh","name":"Phàn Tinh","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Khoáng vật tiền tệ","phamCap":"phàm tục","soHuu":["Vương Lâm"],"trangThai":"đang lưu thông","blurb":"Vật sáng được dùng làm tiền tệ trong thế gian phàm tục nơi Vương Lâm đi qua. Nó không có tác dụng rõ với tu sĩ nhưng vì sáng và sản lượng ít nên được dùng thay ngân lượng.","detail":"Phàn Tinh được phân biệt theo độ lớn nhỏ và dùng trong giao dịch của đô thành phàm tục. Vương Lâm phát hiện vật này giống vai trò ngân lượng ở Chu Tước Tinh, sau đó dùng nguyên thần tìm mỏ dưới đất và thu nhiều Phàn Tinh vào không gian trữ vật.","phanLoaiPhu":"tiền tệ phàm tục, khoáng vật phát sáng","congNang":["Dùng làm tiền tệ giao dịch trong thế gian phàm tục @c1277"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1277","denChuong":"","cachCoDuoc":"dùng nguyên thần tìm mỏ dưới đất rồi thu lấy","trangThai":"đang giữ nhiều"}],"tabs":{"tienTrinh":[{"chuong":"@c1277","loai":"xuất hiện","importance":"normal","giaiDoan":"Tiền tệ trong đô thành","text":"Phàn Tinh được giới thiệu là vật sáng dùng giao dịch ở đô thành, sau đó Vương Lâm thu nhiều viên từ mỏ dưới lòng đất.","anchor":"Nơi đây có một vật được gọi là Phàn Tinh, phân biệt theo độ lớn nhỏ"}]},"capNhatToi":"@c1277","nguon":["@c1277"]},{"id":"mo-phan-tinh-duoi-long-dat","name":"Mỏ Phàn Tinh dưới lòng đất","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Khoáng mạch","phamCap":"phàm tục","soHuu":[],"trangThai":"bị Vương Lâm lấy một phần","blurb":"Khoáng mạch Phàn Tinh nằm dưới lòng đô thành phàm tục. Vương Lâm dùng nguyên thần quét qua và lập tức phát hiện nó.","detail":"Mỏ Phàn Tinh nằm dưới lòng đất của đô thành, không được mô tả như vật có ích cho tu sĩ nhưng là nguồn tiền tệ quan trọng của phàm nhân nơi đây. Sau khi phát hiện, Vương Lâm thu lấy một phần Phàn Tinh để luyện hóa và cất trữ.","phanLoaiPhu":"khoáng mạch","dacDiem":"Nằm dưới lòng đất đô thành.","congNang":["Cung cấp Phàn Tinh dùng trong giao dịch phàm tục @c1277"],"tabs":{"tienTrinh":[{"chuong":"@c1277","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị nguyên thần phát hiện","text":"Mỏ Phàn Tinh dưới lòng đất bị Vương Lâm dùng nguyên thần dò ra khi hắn tìm hiểu đô thành.","anchor":"hắn lập tức tìm được một mỏ Phàn Tinh dưới lòng đất"}]},"capNhatToi":"@c1277","nguon":["@c1277"]},{"id":"bau-ruou-gao-cua-lao-chu-quan","name":"Bầu rượu gạo của lão chủ quán","cn":"","aliases":[],"category":"khac","categoryLabel":"Đồ uống phàm tục","phamCap":"phàm tục","soHuu":["Lão già chủ quán than trước cổng thôn","Vương Lâm"],"trangThai":"đã dùng","blurb":"Bình rượu gạo lão chủ quán tặng cho Vương Lâm trong đêm lạnh. Sau khi Vương Lâm uống, rượu bị nguyên lực kích phát thành hỏa lực giúp luyện hóa Thái Cổ Lôi Long.","detail":"Ban đầu đây chỉ là bình rượu gạo phàm tục để uống giữ ấm khi đọc sách. Trong quá trình Vương Lâm luyện hóa tám Thái Cổ Lôi Long, rượu vào bụng lại bùng lên như bị thiêu đốt, khiến hỏa diễm trong nguyên thần tăng mạnh và trợ giúp quá trình thôn phệ.","phanLoaiPhu":"đồ uống, vật phẩm phàm tục","congNang":["Giữ ấm thân thể theo cách dùng phàm tục @c1277","Khi bị nguyên lực của Vương Lâm vận chuyển, hóa thành hỏa lực trợ giúp luyện hóa Thái Cổ Lôi Long @c1277"],"chuSoHuu":[{"ten":"Lão già chủ quán than trước cổng thôn","tuChuong":"@c1277","denChuong":"@c1277","cachCoDuoc":"vốn là rượu của quán","trangThai":"đã tặng"},{"ten":"Vương Lâm","tuChuong":"@c1277","denChuong":"@c1277","cachCoDuoc":"được lão chủ quán tặng","trangThai":"đã uống"}],"tabs":{"tienTrinh":[{"chuong":"@c1277","loai":"dùng","importance":"normal","giaiDoan":"Rượu trợ hỏa","text":"Bầu rượu gạo được lão chủ quán tặng cho Vương Lâm, rồi sau đó hóa thành hỏa lực trợ giúp hắn luyện hóa Thái Cổ Lôi Long.","anchor":"rượu trong bụng dưới giống như bị thiêu đốt mà ầm ầm bùng lên"}]},"capNhatToi":"@c1277","nguon":["@c1277"]},{"id":"thai-co-tinh-than-lenh","name":"Thái Cổ Tinh Thần Lệnh","cn":"","aliases":[],"category":"khac","categoryLabel":"Lệnh truy sát","phamCap":"khong-ro","soHuu":["Trường Tôn Hội"],"trangThai":"đang ban bố","blurb":"Thái Cổ Tinh Thần Lệnh là lệnh do Trường Tôn Hội ban ra sau khi xác nhận Thiểm Lôi Tộc bị tiêu diệt. Lệnh này thông báo cho tất cả bộ tộc trên toàn Thái Cổ Tinh Thần về biến cố và phát động truy sát hung thủ dựa trên hình ảnh cùng ký ức thần thức do Vân Lạc thôi diễn.","detail":"Sau khi chứng thực Thiểm Lôi Tộc bị diệt và đại trưởng lão thất bại mất tích, Trường Tôn Hội tuyên bố Thái Cổ Tinh Thần Lệnh. Lệnh này mang tính chất huy động trên phạm vi toàn bộ Thái Cổ Tinh Thần, phân tán hình ảnh cùng ký ức thần thức của hung thủ — do Vân Lạc thôi diễn — tới các bộ tộc nhằm triển khai truy sát trên diện rộng.","phanLoaiPhu":"lệnh truy sát","nguonGoc":"Trường Tôn Hội","uyLuc":"Huy động phạm vi truy tìm trên toàn Thái Cổ Tinh Thần, khiến mọi bộ tộc đều tiếp nhận lệnh truy sát.","dacDiem":"Gắn với biến cố diệt Thiểm Lôi Tộc và hình ảnh hung thủ do Vân Lạc thôi diễn.","chuHienThoi":"Trường Tôn Hội","congNang":["Thông báo cho tất cả bộ tộc trong Thái Cổ Tinh Thần về biến cố Thiểm Lôi Tộc bị tiêu diệt @c1278","Phát động truy sát hung thủ trên toàn Thái Cổ Tinh Thần, kèm phân tán hình ảnh và ký ức thần thức của đối tượng @c1278"],"chuSoHuu":[{"ten":"Trường Tôn Hội","tuChuong":"@c1278","denChuong":"","cachCoDuoc":"ban bố sau khi chứng thực biến cố Thiểm Lôi Tộc","trangThai":"đang nắm giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1278","loai":"xuất hiện","importance":"major","giaiDoan":"Lệnh truy sát toàn tinh thần","text":"Trường Tôn Hội tuyên bố Thái Cổ Tinh Thần Lệnh để báo cho các bộ tộc biết về biến cố Thiểm Lôi Tộc và triển khai truy sát hung thủ.","anchor":"sau đó tuyên bố Thái Cổ Tinh Thần Lệnh nói cho tất cả bộ tộc biết","phamCap":"khong-ro"}]},"capNhatToi":"@c1278","nguon":["@c1278"]},{"id":"cuu-pham-dao-linh","name":"Cửu Phẩm đạo linh","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Đạo linh","phamCap":"Cửu Phẩm","soHuu":["Trường Tôn Hội"],"trangThai":"phần thưởng truy sát","blurb":"Cửu Phẩm đạo linh là phần thưởng cao hơn mà Trường Tôn Hội đưa ra nếu giết chết người hủy diệt Thiểm Lôi tộc. Sự xuất hiện của nó cho thấy mức độ nghiêm trọng của lệnh truy bắt.","detail":"Trong huyết chỉ gửi tới Tư Mặc Tử, Trường Tôn Hội đặt Cửu Phẩm đạo linh làm phần thưởng cho việc giết chết mục tiêu. Đây là mức thưởng cao hơn so với Lục Phẩm đạo linh dành cho việc bắt giữ.","phanLoaiPhu":"đạo linh","dacDiem":"Được dùng làm phần thưởng cho nhiệm vụ giết chết mục tiêu.","congNang":["Làm phần thưởng truy sát người hủy diệt Thiểm Lôi tộc @c1281"],"chuSoHuu":[{"ten":"Trường Tôn Hội","tuChuong":"@c1281","denChuong":"","cachCoDuoc":"treo thưởng trong huyết chỉ","trangThai":"treo-thuong"}],"tabs":{"tienTrinh":[{"chuong":"@c1281","loai":"nhắc tới","importance":"normal","giaiDoan":"Treo thưởng truy sát","text":"Trường Tôn Hội treo Cửu Phẩm đạo linh làm phần thưởng nếu giết chết người hủy diệt Thiểm Lôi tộc.","phamCap":"Cửu Phẩm","anchor":"g**t ch*t người này được nhận một Cửu Phẩm đạo linh"}]},"capNhatToi":"@c1281","nguon":["@c1281"]},{"id":"huyet-chi-cua-truong-ton-hoi","name":"Huyết chỉ của Trường Tôn Hội","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Lệnh phù","phamCap":"không rõ","soHuu":["Trường Tôn Hội","Tư Mặc Tử"],"trangThai":"đã bị bóp nát để nhận lệnh","blurb":"Huyết chỉ của Trường Tôn Hội là luồng sáng đỏ thẫm mang mệnh lệnh truy bắt Vương Lâm tới Tư Mặc Tử. Khi bị bóp nát, nó hóa thành khí đỏ chui vào cánh tay để xác nhận nhiệm vụ.","detail":"Huyết chỉ xuất hiện trong khe nứt hư vô nơi Tư Mặc Tử bế quan. Nội dung của nó nêu phần thưởng đạo linh cho việc bắt giữ hoặc giết chết người hủy diệt Thiểm Lôi tộc.","phanLoaiPhu":"huyết chỉ truyền lệnh","hinhDang":"luồng sáng đỏ thẫm","congNang":["Truyền mệnh lệnh truy bắt và xác nhận nhiệm vụ sau khi bị bóp nát @c1281"],"chuSoHuu":[{"ten":"Trường Tôn Hội","tuChuong":"@c1281","denChuong":"","cachCoDuoc":"phát ra để truyền lệnh","trangThai":"da-phat"},{"ten":"Tư Mặc Tử","tuChuong":"@c1281","denChuong":"@c1281","cachCoDuoc":"nhận huyết chỉ trong khe nứt hư vô","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1281","loai":"dùng","importance":"normal","giaiDoan":"Tư Mặc Tử nhận lệnh","text":"Tư Mặc Tử bóp nát huyết chỉ, để luồng khí đỏ chui vào cánh tay và xác nhận nhiệm vụ truy bắt.","anchor":"Sau khi hắn bó p lại thì huyết chỉ vỡ tan hóa thành một luồng khí tức màu đỏ"}]},"capNhatToi":"@c1281","nguon":["@c1281"]},{"id":"qua-cau-nuoc-cua-van-lac","name":"Quả cầu nước của Vân Lạc","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Vật môi giới suy tính","phamCap":"không rõ","soHuu":["Vân Lạc"],"trangThai":"đã dùng để suy tính vị trí Vương Lâm","blurb":"Quả cầu nước của Vân Lạc là vật môi giới trong thuật suy tính truy tung. Nó hiển hiện bóng Vương Lâm rồi nổ thành màn nước biểu thị tinh không và tu chân tinh mục tiêu.","detail":"Trước người Vân Lạc, quả cầu nước xoay tròn với hình ảnh hỗn loạn, sau đó làm rõ bóng Vương Lâm. Khi phát nổ thành màn nước, nó cho thấy tinh không và tu chân tinh nơi Vương Lâm trú ngụ.","phanLoaiPhu":"vật môi giới suy tính","hinhDang":"quả cầu nước xoay tròn","congNang":["Hiển ảnh đối tượng và vị trí tu chân tinh mục tiêu qua suy tính @c1281"],"chuSoHuu":[{"ten":"Vân Lạc","tuChuong":"@c1281","denChuong":"","cachCoDuoc":"sử dụng trong suy tính","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1281","loai":"dùng","importance":"normal","giaiDoan":"Hiển ảnh Vương Lâm","text":"Quả cầu nước trước người Vân Lạc làm rõ hình bóng Vương Lâm rồi hiển thị tinh không và tu chân tinh mục tiêu.","anchor":"quả cầu nước vặn vẹo, hình bóng kia ngày càng rõ ràng, đây đúng là Vương Lâm"}]},"capNhatToi":"@c1281","nguon":["@c1281"]},{"id":"hon-dan-cua-vuong-lam","name":"Hồn đan của Vương Lâm","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Thượng phẩm trong mắt tu sĩ Hóa Thần hậu kỳ; bị thiếu chủ Ám Hạt Tộc xem là cấp tầm thường","soHuu":["Vương Lâm","Chung Đại Hồng"],"trangThai":"Được dùng làm lễ vật và vật trao đổi","blurb":"Đan dược Vương Lâm giao cho Chung Đại Hồng, được lão họ Chương xem là thượng phẩm phù hợp tu vi Hóa Thần hậu kỳ. Nam tử trung niên Ám Hạt Tộc nhận ra đây là hồn đan và đổi hai viên lấy một con rối.","detail":"Chung Đại Hồng đem ba viên đan dược Vương Lâm cho tặng lão họ Chương để kết giao và nhờ dẫn đi mua con rối. Lão họ Chương rất mừng vì đan dược thích hợp với tu vi Hóa Thần hậu kỳ của mình; tại đại điện Ám Hạt Tộc, nam tử trung niên nhận ra hai viên đan còn lại là hồn đan, dùng chúng làm giá trao đổi một con rối Hóa Thần sơ kỳ. Việc hồn đan xuất hiện cũng khiến Ám Hạt Tộc nảy ý truy bắt và truy tung nguồn gốc.","nguon":["@c1285"]},{"id":"con-roi-hoa-than-so-ky","name":"Con rối Hóa Thần sơ kỳ","cn":"","category":"khac","categoryLabel":"Con rối","phamCap":"Tu vi Hóa Thần sơ kỳ","soHuu":["Chung Đại Hồng","Vương Lâm"],"trangThai":"Đã được Chung Đại Hồng mang về giao cho Vương Lâm","blurb":"Con rối do Ám Hạt Tộc đổi cho Chung Đại Hồng bằng hai viên hồn đan. Nó có hình dạng giống chân thân, không tộc ấn, không linh tính hay sinh cơ, chỉ có khí tức âm trầm và tu vi Hóa Thần sơ kỳ.","detail":"Con rối này thuộc loại vật phẩm giao dịch do Ám Hạt Tộc nắm giữ. Nam tử trung niên Ám Hạt Tộc triệu ra nó trong đại điện và đổi lấy hai viên hồn đan của Chung Đại Hồng. Sau khi Chung bị tập kích nhưng vẫn chạy thoát, hắn đem con rối về giao cho Vương Lâm; Vương Lâm quan sát kỹ và nhận thấy vật này có điểm kỳ dị, nhưng chương này chưa giải thích sâu về cách luyện chế hay bản chất của nó.","nguon":["@c1285"]},{"id":"pho-tuong-bo-cap-den-trong-dai-dien","name":"Pho tượng bọ cạp đen trong đại điện","cn":"","category":"khac","categoryLabel":"Tượng vật thờ","phamCap":"Không rõ","soHuu":["Ám Hạt Tộc"],"trangThai":"Đặt trong đại điện Ám Hạt Tộc; đại điện về sau bị lôi đình phá nổ","blurb":"Pho tượng bọ cạp khổng lồ toàn thân đen kịt đặt giữa đại điện Ám Hạt Tộc. Nó phát ra hàn khí dày đặc, khiến Chung Đại Hồng không chống nổi mà thổ huyết khi vừa bước vào.","detail":"Trong đại điện trung tâm thành trì hoang phế của Ám Hạt Tộc có một pho tượng bọ cạp đen khổng lồ. Hàn khí từ pho tượng tạo áp lực rõ rệt lên Chung Đại Hồng, một tu sĩ Hóa Thần, khiến hắn phun máu ngay khi vào điện. Về sau khi Vương Lâm dùng lôi đình phá thành, đại điện nơi đặt pho tượng cũng bị đánh nổ.","nguon":["@c1285"]},{"id":"am-hat-chau","name":"Ám hạt châu","cn":"","category":"phap-bao","categoryLabel":"Vật phẩm công kích","phamCap":"Có thể làm tu sĩ Khuy Niết bị thương nếu đánh lén","soHuu":["Thanh niên thiếu chủ Ám Hạt Tộc"],"trangThai":"Bị Vương Lâm chụp giữ và kích nổ nhưng không gây thương tổn cho hắn","blurb":"Hạt châu màu tím tỏa sát khí, được thanh niên thiếu chủ Ám Hạt Tộc dùng để đánh lén Vương Lâm trong bảo tháp.","detail":"Ám hạt châu là vật phẩm công kích do thanh niên thiếu chủ Ám Hạt Tộc sử dụng khi Vương Lâm truy quét trong bảo tháp. Hạt châu tỏa sát khí kinh người, có thể tự nổ và theo nhận định đủ khiến tu sĩ Khuy Niết bị thương nếu bị đánh lén, nhưng Vương Lâm biến hóa bàn tay khổng lồ chụp lấy, chịu trọn vụ nổ mà không tổn hao.","nguon":["@c1286"]},{"id":"bon-con-roi-tram-truong","name":"Bốn con rối trăm trượng","cn":"","category":"phap-bao","categoryLabel":"Con rối chiến đấu","phamCap":"Mỗi con có khí tức tương đương âm dương hư thực","soHuu":["Lão giả Ám Hạt Tộc hắc bào"],"trangThai":"Được triệu ra để vây công và định tự nổ trước Vương Lâm","blurb":"Bốn con rối cỡ trăm trượng do lão giả Ám Hạt Tộc hắc bào triệu ra khi giao chiến với Vương Lâm.","detail":"Bốn con rối trăm trượng là lực lượng chiến đấu được lão giả Ám Hạt Tộc hắc bào gọi ra từ bảo tháp. Chúng có khí tức tương đương âm dương hư thực, lao ra vây Vương Lâm và được lão giả định dùng cách tự nổ để tạo sát thương trong lúc đối đầu.","nguon":["@c1286"]},{"id":"con-roi-tinh-niet-trung-ky-cua-am-hat-toc","name":"Con rối Tịnh Niết trung kỳ của Ám Hạt Tộc","cn":"","category":"phap-bao","categoryLabel":"Con rối chiến đấu","phamCap":"Tịnh Niết trung kỳ","soHuu":["Ám Hạt Tộc","Lão giả Ám Hạt Tộc hắc bào"],"trangThai":"Được lão giả Ám Hạt Tộc trình ra sau khi quy phục Vương Lâm","blurb":"Con rối mạnh nhất trong Ám Hạt Tộc, có cảnh giới Tịnh Niết trung kỳ và giá trị rất cao.","detail":"Đây là con rối cấp cao nhất mà Ám Hạt Tộc sở hữu ở thời điểm chương 1286. Nó có hình dạng một nam tử trung niên, không có sinh cơ, toàn thân phủ phong ấn; lão giả Ám Hạt Tộc nói con rối Tịnh Niết trung kỳ có giá cực cao và trình vật này ra khi báo cáo hệ thống con rối ở Điên Lạc cho Vương Lâm.","nguon":["@c1286"]},{"id":"viem-hoa-di-tinh","name":"Viêm hỏa dị tinh","cn":"","category":"nguyen-lieu","categoryLabel":"Tài liệu chế tạo con rối / dị vật","phamCap":"Dị tinh liên hệ Thái Cổ Tinh Thần và Tứ Thánh Tông","soHuu":["Điên Lạc","Hải hồn tông","Vương Lâm"],"trangThai":"đang được Vương Lâm giữ","blurb":"Dị vật được nói là của Điên Lạc, là một trong các tài liệu chế tạo con rối và có liên hệ khiến Vương Lâm nghĩ tới nguồn gốc Tứ Thánh Tông.","detail":"Viêm hỏa dị tinh được lão giả Ám Hạt Tộc nói là vật của Điên Lạc, nghe đồn do Điên Lạc đại đế mang đến và là một trong các tài liệu dùng để chế tạo con rối. Hải hồn tông do Hỏa Tước tộc phái tới Điên Lạc âm thầm sưu tầm vật này; khi lão giả dâng một mảnh nhỏ, Vương Lâm nhận ra nó liên hệ với lời Chu Tước lão Thánh Hoàng từng nói rằng Tứ Thánh Tông vốn từ Thái Cổ Tinh Thần mà đến.","nguon":["@c1286","@c1287"],"tabs":{"tienTrinh":[{"chuong":"@c1287","loai":"đổi chủ","importance":"normal","giaiDoan":"Được Vương Lâm thu giữ","text":"Viêm hỏa dị tinh được Kiệt trưởng lão lấy ra, bị Vương Lâm nhận ra là giống hòn đá trắng của Chu Tước Thánh Tông rồi thu vào không gian trữ vật.","anchor":"Vật được gọi là Viêm hỏa dị tinh tại Điên Lạc rõ ràng là thứ giống hệt","phamCap":"không rõ"}]},"chuSoHuu":[{"ten":"Kiệt trưởng lão","tuChuong":"@c1287","denChuong":"@c1287","cachCoDuoc":"Lấy ra trước mặt Vương Lâm","trangThai":"đã mất"},{"ten":"Vương Lâm","tuChuong":"@c1287","denChuong":"","cachCoDuoc":"Thu vào không gian trữ vật","trangThai":"đang giữ"}]},{"id":"tinh-the-trong-con-roi-am-hat-toc","name":"Tinh thể trong con rối Ám Hạt Tộc","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Vật chất kỳ dị","phamCap":"không rõ","soHuu":["Con rối nam tử trung niên của Ám Hạt Tộc"],"trangThai":"bị phá tán sau khi con rối nổ tung","blurb":"Tinh thể trong con rối Ám Hạt Tộc thay thế huyết nhục và cấu thành cả phần não của con rối. Vương Lâm nhận ra nó giống tinh thể ở vết thương đầu lâu Cổ Thần từng gặp.","detail":"Loại tinh thể này mềm mại ở thân thể nhưng phần não lại cứng rắn và tỏa nguyên lực, đồng thời có tầng ánh sáng phòng hộ ngăn thần thức. Sau khi con rối bị hủy, Vương Lâm liên hệ nó với mẫu tinh thể từ đầu lâu Cổ Thần ở vùng đất Yêu Linh.","nguon":["@c1287"],"phanLoaiPhu":"tinh thể kỳ dị","dacDiem":"Thay thế huyết nhục trong con rối và tương tự tinh thể ở vết thương đầu lâu Cổ Thần.","chuHienThoi":"không rõ","congNang":["Cấu thành thân thể và não của con rối, thay thế huyết nhục và che giấu nguyên thần bên trong @c1287"],"tabs":{"tienTrinh":[{"chuong":"@c1287","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị Vương Lâm phát hiện","text":"Tinh thể trong con rối Ám Hạt Tộc bị Vương Lâm phát hiện là vật chất thay thế huyết nhục và có điểm giống tinh thể ở vết thương đầu lâu Cổ Thần.","anchor":"Thứ tinh thể này cực kỳ giống với tinh thể thay thế huyết nhục","phamCap":"không rõ"}]},"capNhatToi":"@c1287"},{"id":"binh-nho-chua-tinh-the-vet-thuong-dau-co-than","name":"Bình nhỏ chứa tinh thể vết thương đầu Cổ Thần","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật chứa mẫu tinh thể","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"trong không gian trữ vật của Vương Lâm","blurb":"Bình nhỏ chứa tinh thể vết thương đầu Cổ Thần là mẫu tinh thể Vương Lâm giữ lại từ vùng đất Yêu Linh. Nó được nhớ tới khi hắn phát hiện tinh thể trong con rối Ám Hạt Tộc có nét tương tự.","detail":"Vương Lâm nhớ trong không gian trữ vật của mình còn một bình nhỏ chứa tinh thể lưu lại trên vết thương đầu Cổ Thần. Mẫu này trở thành căn cứ đối chiếu với tinh thể trong con rối ở Điên Lạc.","nguon":["@c1287"],"phanLoaiPhu":"mẫu tinh thể","dacDiem":"Chứa tinh thể lấy từ vết thương đầu lâu Cổ Thần.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1287","denChuong":"","cachCoDuoc":"Đã cất trong không gian trữ vật trước chương này","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1287","loai":"nhắc tới","importance":"normal","giaiDoan":"Được dùng đối chiếu","text":"Bình nhỏ chứa tinh thể vết thương đầu Cổ Thần được Vương Lâm nhớ tới khi so sánh với tinh thể trong con rối Ám Hạt Tộc.","anchor":"trong đó có chứa tinh thể lưu lại trên vết thương ở đầu Cổ Thần kia","phamCap":"không rõ"}]},"capNhatToi":"@c1287"},{"id":"con-roi-cao-giai-o-phuong-thi-long-giap-toc","name":"Con rối cao giai ở phường thị Long Giáp Tộc","cn":"","category":"khac","categoryLabel":"Con rối","phamCap":"cao giai","soHuu":["Long Giáp Tộc"],"trangThai":"đang được bày bán hoặc tìm mua","blurb":"Loại con rối cao giai được bán tại phường thị Long Giáp Tộc. Vương Lâm đến Long Giáp Tộc vốn định mua một ít để nghiên cứu.","detail":"Con rối cao giai ở phường thị Long Giáp Tộc là mục tiêu mua bán ban đầu của Vương Lâm sau khi rời tu chân tinh Ám Hạt Tộc. Việc tìm mua con rối nối tiếp mạch hắn còn đang suy nghĩ về cảnh tượng trong con rối trước đó.","phanLoaiPhu":"con rối","chuHienThoi":"Long Giáp Tộc","congNang":["Được Vương Lâm tìm mua làm đối tượng nghiên cứu @c1288"],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1288","loai":"nhắc tới","importance":"normal","giaiDoan":"Mục tiêu tìm mua","text":"Vương Lâm đến Long Giáp Tộc vốn định mua một ít con rối cao giai để nghiên cứu.","anchor":"Hắn tới đây vốn là định mua một ít con rối cao giai về nghiên cứu"}]},"capNhatToi":"@c1288","nguon":["@c1288"]},{"id":"long-giap-toc-lan","name":"Long Giáp Tộc lân","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tam bảo Long Giáp Tộc","soHuu":["Long Giáp Tộc"],"trangThai":"Được thiếu tộc trưởng Long Giáp Tộc giới thiệu trong giao dịch với Vương Lâm","blurb":"Bảo vật phòng hộ đứng đầu trong tam bảo của Long Giáp Tộc, dựa vào long lân phối hợp máu huyết tộc nhân và thần thông để tăng mạnh sức phòng ngự.","detail":"Long Giáp Tộc lân là bảo vật thứ nhất trong tam bảo của Long Giáp Tộc. Thiếu tộc trưởng Long Giáp Tộc nói vật này có thể khiến phòng hộ tăng lên gấp bội, đến mức pháp bảo tầm thường khó phá được lớp phòng hộ ấy.","nguon":["@c1289"]},{"id":"bach-cot-long","name":"Bạch cốt long","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tam bảo Long Giáp Tộc","soHuu":["Long Giáp Tộc"],"trangThai":"Được thiếu tộc trưởng Long Giáp Tộc giới thiệu trong giao dịch với Vương Lâm","blurb":"Bảo vật thứ hai trong tam bảo Long Giáp Tộc, do hài cốt tộc nhân xưa luyện hóa thành, có lực lượng kinh thiên động địa.","detail":"Bạch cốt long là một trong tam bảo của Long Giáp Tộc, được nói là do hài cốt tộc nhân từ xưa của Long Giáp Tộc luyện hóa thành. Thiếu tộc trưởng Long Giáp Tộc nhấn mạnh số lượng bạch cốt long rất lớn, mỗi con đều có lực lượng kinh thiên động địa và vì vốn đã tử vong nên được gọi là suốt đời bất diệt.","nguon":["@c1289"]},{"id":"bang-long-dan","name":"Băng long đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Tam bảo Long Giáp Tộc","soHuu":["Long Giáp Tộc","Vương Lâm"],"trangThai":"Vương Lâm đổi một vạn viên rồi luyện hợp thành một viên huyết sắc có uy lực uy hiếp thiên nhân đệ ngũ suy","blurb":"Tam bảo thứ ba của Long Giáp Tộc, vốn là đan dược nổ dùng để đả thương địch thủ. Vương Lâm đổi một vạn viên và luyện lại thành sát khí cấp cao.","detail":"Băng long đan là bảo vật thứ ba trong tam bảo Long Giáp Tộc, do Điên Lạc đại đế ban tặng, được dùng bằng cách cho nổ để đả thương đối thủ. Vương Lâm dùng một trăm hồn đan đổi một vạn Băng long đan, sau đó thi triển đạo thuật Dung, hỏa diễm mắt trái, lôi đình mắt phải, máu Cổ Thần và tinh khí nguyên thần để ép toàn bộ thành một viên huyết sắc; uy lực cuối cùng được hắn đánh giá đủ để uy hiếp tu sĩ thiên nhân đệ ngũ suy.","nguon":["@c1289"]},{"id":"mau-co-than-va-tinh-khi-cua-vuong-lam","name":"Máu Cổ Thần và tinh khí của Vương Lâm","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Được Vương Lâm phun vào viên Băng long đan đã luyện hợp để tăng uy lực","blurb":"Máu chứa huyết mạch Cổ Thần và tinh khí nguyên thần của Vương Lâm, được dùng như vật liệu tăng sát lực cho viên Băng long đan mới luyện.","detail":"Khi tế luyện một vạn Băng long đan thành một viên, Vương Lâm cắn đầu lưỡi phun ra máu tươi. Máu này vừa là máu của Cổ Thần, vừa chứa tinh khí nguyên thần của hắn, khiến viên đan chuyển sang huyết sắc và được nâng tới mức có thể uy hiếp tu sĩ thiên nhân đệ ngũ suy.","nguon":["@c1289"]},{"id":"tinh-the-mau-lam-dam-tu-viem-hoa-di-tinh","name":"Tinh thể màu lam đậm từ Viêm hỏa dị tinh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Được Vương Lâm luyện thành từ toàn bộ Viêm hỏa dị tinh thu được","blurb":"Tinh thể hỏa hệ do Vương Lâm luyện toàn bộ Viêm hỏa dị tinh thành một khối, bên trong có bổn nguyên hỏa diễm và hình ảnh Chu Tước.","detail":"Sau khi nhận thấy lượng Viêm hỏa dị tinh không đủ để khiến Chu Tước tỉnh giấc lần thứ tư, Vương Lâm dùng năng lực điều khiển hỏa diễm và đạo thuật Dung luyện toàn bộ dị tinh thành một tinh thể màu lam đậm. Bên trong tinh thể chứa bổn nguyên lực hỏa diễm và hình ảnh Chu Tước, được hắn đánh giá có uy lực không kém viên Băng long đan vừa tế luyện.","nguon":["@c1289"]},{"id":"giot-mau-trong-hon-dan","name":"Giọt máu trong hồn đan","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Lão giả Hỏa Tước tộc"],"trangThai":"Được lão giả Hỏa Tước tộc luyện tách ra từ một trăm hồn đan","blurb":"Giọt máu đỏ đậm ẩn trong hồn đan, là nguồn phát ra khí tức bổn nguyên khiến Hỏa Tước tộc chú ý.","detail":"Sau khi đổi được một trăm hồn đan từ Vương Lâm, lão giả Hỏa Tước tộc cùng tộc nhân dùng lửa luyện tan đan dược để truy tìm nguồn khí tức bổn nguyên. Cuối cùng, toàn bộ đan chỉ còn lại một giọt máu đỏ đậm có sắc đẹp kỳ dị; lão giả xác nhận khí tức bổn nguyên trong đan đến từ giọt máu này nhưng chưa biết đó là loại máu gì.","nguon":["@c1289"]},{"id":"phien-la-phong-an","name":"Phiến lá phong ấn","cn":"","category":"phap-bao","categoryLabel":"Vật phong ấn","phamCap":"Chưa rõ","soHuu":["Tham Lang","Vương Lâm"],"trangThai":"Vương Lâm đã chụp lấy sau khi Tham Lang trọng thương và không còn điều khiển được","blurb":"Phiến lá từng phong ấn hoặc khống chế vị trí của Vương Lâm. Khi Tham Lang bị huyết quang đánh trọng thương, Vương Lâm thoát ra từ chỗ lá cây và lập tức nắm lấy nó.","detail":"Phiến lá này gắn với tình thế Vương Lâm bị phong ấn hoặc bị khống chế vị trí trước đó. Sau khi Tham Lang bị huyết quang đánh trọng thương, hắn không còn khả năng điều khiển phiến lá, khiến Vương Lâm bước ra từ chỗ lá cây rồi không chần chừ chụp lấy. Việc đổi thế này đánh dấu Vương Lâm thoát khỏi trạng thái bị chế trụ và chuyển sang chủ động trong cuộc đối đầu với Tư Mặc Tử.","nguon":["@c1290"]},{"id":"ao-giap-an-giau-cua-tham-lang","name":"Áo giáp ẩn giấu của Tham Lang","cn":"","category":"phap-bao","categoryLabel":"Áo giáp hộ thân","phamCap":"Chưa rõ","soHuu":["Tham Lang"],"trangThai":"Bị huyết quang đánh lộ ra và xuất hiện vô số khe nứt","blurb":"Bộ áo giáp được Tham Lang giấu dưới áo, chỉ lộ ra khi huyết quang xuyên qua thân thể hắn. Sau đòn đánh, áo giáp nứt vỡ nhiều chỗ nhưng đã thể hiện vai trò hộ thân.","detail":"Khi Tham Lang bị huyết quang kinh thiên đánh trúng, trên ngực áo hắn lộ ra một mảng đen, cho thấy hắn mặc giấu một bộ áo giáp bên trong. Bộ giáp này có tác dụng hộ thân, nhưng trước uy lực của huyết quang vẫn xuất hiện vô số khe nứt, đồng thời Tham Lang bị thương nặng, phun máu và phải bỏ chạy.","nguon":["@c1290"]},{"id":"hai-ma-anh-duoi-chan-tham-lang","name":"Hai ma ảnh dưới chân Tham Lang","cn":"","category":"khac","categoryLabel":"Ma ảnh phụ trợ đào thoát","phamCap":"Chưa rõ","soHuu":["Tham Lang"],"trangThai":"Hóa thành hắc khí tạo gió lốc đen cuốn Tham Lang bỏ chạy","blurb":"Hai ma ảnh dưới chân Tham Lang là phương tiện hỗ trợ hắn đào thoát sau khi bị trọng thương. Chúng hóa thành hai đạo hắc khí, quấn quanh thân thể rồi tạo thành gió lốc màu đen.","detail":"Sau khi bị huyết quang đánh xuyên qua thân thể, Tham Lang lập tức vận dụng hai ma ảnh dưới chân. Hai ma ảnh hóa thành hai đạo hắc khí, xoay quanh thân thể hắn và hình thành một cơn gió lốc màu đen, cuốn hắn chạy khỏi tinh không. Thực thể này gắn trực tiếp với sở trường bỏ chạy và thủ đoạn bảo mạng của Tham Lang.","nguon":["@c1290"]},{"id":"buc-tranh-song-nuoc","name":"Bức tranh thiên địa / bức tranh sóng nước","cn":"","aliases":["Bức tranh thiên địa","Bức tranh sóng nước"],"category":"phap-bao","categoryLabel":"Pháp bảo / vật dẫn thần thông","phamCap":"Không rõ","soHuu":["Tư Mặc Tử"],"trangThai":"dang-co","blurb":"Bức tranh sóng nước là vật phẩm đấu giá tại Bồng Lai, vẽ hồ nước cuồn cuộn sống động như thật, được Vương Lâm mua rồi tặng cho Lý Thiến Ma. Về sau, bức tranh xuất hiện trong tay Tư Mặc Tử, được dùng để vẽ ra tu chân tinh và thân ảnh Vương Lâm nhằm vận chuyển Phá Thiên Đạo.","detail":"Bức tranh sóng nước xuất hiện với tư cách vật phẩm đấu giá thứ ba trong buổi đấu giá tại quảng trường trung tâm Bồng Lai. Khác với các bức tranh phong cảnh thông thường vẽ núi, bức tranh này vẽ hồ nước cuồn cuộn, sóng nước trong tranh sống động như thật. Trong buổi đấu giá, khi Vương Lâm lên tiếng muốn lấy thì không ai dám tranh đoạt, nhờ đó hắn dễ dàng mua được. Sau đó, Vương Lâm đem tặng lại bức tranh cho Lý Thiến Ma trước lúc nàng rời đi (@c1106). Tới giai đoạn sau, Tư Mặc Tử sử dụng bức tranh này, vẽ ra tu chân tinh và thân ảnh của Vương Lâm để vận chuyển Phá Thiên Đạo (@c1291).","hinhDang":"Bức tranh thiên địa có thể dung nhập cảnh tu chân tinh.","chuHienThoi":"Tư Mặc Tử","congNang":["Có thể được dùng để vẽ ra tu chân tinh và thân ảnh của một người, phục vụ vận chuyển Phá Thiên Đạo (@c1291)"],"chuSoHuu":[{"ten":"Tư Mặc Tử","tuChuong":"@c1291","denChuong":"","cachCoDuoc":"Đang sử dụng trong trận chiến","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1291","loai":"dùng","importance":"normal","giaiDoan":"Vật dẫn Phá Thiên Đạo","text":"Tư Mặc Tử dùng bức tranh vẽ ra tu chân tinh và thân ảnh Vương Lâm để vận chuyển Phá Thiên Đạo.","anchor":"Chỉ một vài nét bút nhưng ở trong bức tranh này đã hoàn toàn vẽ ra cả tu chân tinh"}]},"capNhatToi":"@c1291","nguon":["@c1291"],"dacDiem":"Sóng nước trong tranh sống động như thật."},{"id":"dai-phien-muoi-truong-cua-tu-mac-tu","name":"Đại phiên mười trượng của Tư Mặc Tử","cn":"","aliases":["Cây quạt mười trượng","Đại phiên mười trượng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tư Mặc Tử"],"trangThai":"dang-co","blurb":"Đại phiên mười trượng chứa vô số cấm chế, được Tư Mặc Tử dùng để thi triển Tuế Nguyệt Cấm.","detail":"Trong lúc bị Phiên thiên thần thông nén ép, Tư Mặc Tử gọi ra đại phiên mười trượng mang khí tức tang thương, phất lên thành ngàn vạn cấm chế và dòng xoáy để chống lại thiên địa nghịch chuyển.","hinhDang":"Đại phiên hoặc cây quạt dài mười trượng.","chuHienThoi":"Tư Mặc Tử","congNang":["Phóng ngàn vạn cấm chế và Tuế Nguyệt Cấm để chống lại Phiên thiên thần thông @c1291"],"chuSoHuu":[{"ten":"Tư Mặc Tử","tuChuong":"@c1291","denChuong":"","cachCoDuoc":"Xuất ra trong trận chiến","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1291","loai":"dùng","importance":"normal","giaiDoan":"Đối kháng Phiên thiên","text":"Tư Mặc Tử dùng đại phiên mười trượng phóng Tuế Nguyệt Cấm thành dòng xoáy cấm chế chống lại Phiên thiên thần thông.","anchor":"Một cây quạt mười trượng đột nhiên hiện ra bên cạnh Tư Mặc Tử"}]},"capNhatToi":"@c1291","nguon":["@c1291"]},{"id":"vien-dan-duoc-mau-vang","name":"Viên đan dược màu vàng","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược công kích","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã nổ","blurb":"Viên đan nhỏ màu vàng được Vương Lâm triệu ra gần Tư Mặc Tử rồi kích nổ. Vụ nổ gây lực hủy diệt mạnh, làm phân thân Tư Mặc Tử rách huyết nhục và gãy xương.","detail":"Trong lúc truy kích trước khi tiếng bốn kết thúc, Vương Lâm đưa viên đan màu vàng cỡ móng tay tới gần Tư Mặc Tử và cho nổ. Uy lực vụ nổ được mô tả như tu chân tinh nổ tung, tạo sóng âm và lực hủy diệt ở cự ly gần.","phanLoaiPhu":"đan dược tự nổ","hinhDang":"viên đan màu vàng chừng cái móng tay","congNang":["Tự nổ ở cự ly gần để tạo lực hủy diệt công kích đối thủ."],"uyLuc":"Vụ nổ làm phân thân Tư Mặc Tử rách huyết nhục và gãy xương.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1292","denChuong":"@c1292","cachCoDuoc":"đã có trong tay trước khi triệu ra","trangThai":"đã dùng để tự nổ"}],"tabs":{"tienTrinh":[{"chuong":"@c1292","loai":"dùng","importance":"normal","giaiDoan":"Truy kích Tư Mặc Tử","text":"Vương Lâm triệu viên đan dược màu vàng ở gần Tư Mặc Tử rồi kích nổ để gây lực hủy diệt trực diện.","anchor":"Lập tức có một viên đan dược màu vàng chừng cái móng tay từ trong hư vô xuất hiện"}]},"capNhatToi":"@c1292","nguon":["@c1292"]},{"id":"viem-hoa-di-tinh-bi-ap-suc","name":"Viêm hỏa dị tinh bị áp súc","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Vật phẩm công kích","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã nổ","blurb":"Viêm hỏa dị tinh đã bị áp súc vô số lần, được Vương Lâm dùng làm vật phẩm tự nổ trong trận chiến với Tư Mặc Tử. Nó tạo đợt hủy diệt thứ hai ngay sau vụ nổ viên đan màu vàng.","detail":"Sau khi kích nổ viên đan dược màu vàng, Vương Lâm tiếp tục đưa Viêm hỏa dị tinh bị áp súc tới gần Tư Mặc Tử. Khi vật này nổ tung, lực hủy diệt lần thứ hai bộc phát khiến tộc trưởng Long Giáp Tộc đang quan sát bằng thần thức biến sắc.","phanLoaiPhu":"dị tinh áp súc tự nổ","congNang":["Tự nổ sau khi áp sát đối thủ, tạo lực hủy diệt lần thứ hai."],"uyLuc":"Vụ nổ nối tiếp đòn đan dược, khiến người quan sát bằng thần thức biến sắc dữ dội.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1292","denChuong":"@c1292","cachCoDuoc":"đã có trong tay trước khi đưa vào trận chiến","trangThai":"đã dùng để tự nổ"}],"tabs":{"tienTrinh":[{"chuong":"@c1292","loai":"dùng","importance":"normal","giaiDoan":"Vụ nổ nối tiếp","text":"Vương Lâm đưa Viêm hỏa dị tinh bị áp súc tới gần Tư Mặc Tử và kích nổ để tạo đợt hủy diệt thứ hai.","anchor":"Viêm hỏa dị tinh bị áp súc vô số lần liền lóe ra"}]},"capNhatToi":"@c1292","nguon":["@c1292"]},{"id":"chin-muoi-chin-thanh-phi-kiem-cua-tham-lang","name":"Chín mươi chín thanh phi kiếm của Tham Lang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tham Lang","Vương Lâm"],"trangThai":"Vương Lâm giữ @c1293","blurb":"Bộ chín mươi chín thanh phi kiếm Tham Lang lấy được trong cổ mộ, bên cạnh một cái đầu lâu. Vương Lâm xác nhận chúng là bảo vật Cổ Yêu chứa yêu khí nồng đậm.","detail":"Bộ phi kiếm này nhiễm máu tươi và hợp thành kiếm trận. Vương Lâm để lại lạc ấn, thêm cấm chế rồi giữ lại, dự định sau khi trở về giới nội sẽ giao cho phân thân Cổ Yêu hấp thu hoặc sử dụng.","phanLoaiPhu":"Kiếm trận / pháp bảo Cổ Yêu","hinhDang":"Chín mươi chín thanh phi kiếm","nguonGoc":"Tham Lang lấy được bên cạnh một cái đầu lâu trong cổ mộ.","dacDiem":"Có yêu khí nồng đậm và vết máu, có thể hợp thành kiếm trận.","congNang":["Hợp thành một kiếm trận quanh cái đầu lâu trong cổ mộ @c1293","Có yêu khí nồng đậm, được Vương Lâm giữ lại cho phân thân Cổ Yêu sử dụng hoặc hấp thu @c1293"],"chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Tham Lang","tuChuong":"@c1293","denChuong":"@c1293","cachCoDuoc":"Lấy được bên cạnh một cái đầu lâu trong cổ mộ","trangThai":"đã mất"},{"ten":"Vương Lâm","tuChuong":"@c1293","denChuong":"","cachCoDuoc":"Tịch thu từ pháp bảo của Tham Lang và nghiên cứu sau trận chiến","trangThai":"đang giữ"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1293","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Vương Lâm kiểm tra","text":"Vương Lâm lấy chín mươi chín thanh phi kiếm ra nghiên cứu, xác nhận là bảo vật Cổ Yêu có yêu khí nồng đậm và giữ lại cho phân thân Cổ Yêu.","anchor":"Chín mươi chín thanh phi kiếm bên ngoài cái đầu lâu này đều nhiễm máu tươi, hợp thành một kiếm trận"}]},"capNhatToi":"@c1293","nguon":["@c1293"]},{"id":"ho-cot-thach-bi","name":"Hộ Cốt Thạch Bi","aliases":["Chín tấm bia đá","Hộ Cốt Cửu Bi","Cốt bi","Hộ cốt Thạch Bi","Hộ cốt Bị"],"cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm giữ @c1293","blurb":"Bộ chín tấm bia đá được Vương Lâm lấy ra sau khi cất phi kiếm. Chúng bay quanh người hắn và tỏa ra khí tức Cổ Thần quen thuộc.","detail":"Hộ Cốt Thạch Bi gồm chín tấm bia đá. Khi xuất hiện, chúng xoay quanh Vương Lâm và phát ra khí tức Cổ Thần, khiến hắn nhận ra sự quen thuộc của vật này.","phanLoaiPhu":"Bia đá / pháp bảo","hinhDang":"Chín tấm bia đá","dacDiem":"Tỏa khí tức Cổ Thần quen thuộc với Vương Lâm.","congNang":["Bay quanh người Vương Lâm và tỏa ra khí tức Cổ Thần @c1293"],"chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1293","denChuong":"","cachCoDuoc":"Lấy ra từ pháp bảo đang kiểm tra sau trận chiến","trangThai":"đang giữ"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1293","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ khí tức Cổ Thần","text":"Vương Lâm lấy Hộ Cốt Thạch Bi ra, chín tấm bia đá bay quanh người hắn và tỏa khí tức Cổ Thần quen thuộc.","anchor":"Đó là Hộ Cốt Thạch Bi! Chín tấm bia đá bay xung quanh"}]},"capNhatToi":"@c1293","nguon":["@c1293"]},{"id":"doc-menh-dan","name":"Độc mệnh đan","aliases":["Độc đan đại đế ban cho tộc trưởng Long Giáp Tộc"],"cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Điên Lạc đại đế","Nam tử trung niên hồng sam","Tộc trưởng Long Giáp Tộc"],"trangThai":"Bị ban cho tộc trưởng Long Giáp Tộc @c1293","blurb":"Viên đan dược màu đen do sứ giả đại đế ban cho tộc trưởng Long Giáp Tộc theo khẩu dụ. Tộc trưởng nhận ra đây là Độc mệnh đan và biến sắc.","detail":"Độc mệnh đan xuất hiện trong khẩu dụ xử phạt của Điên Lạc đại đế. Sứ giả yêu cầu tộc trưởng Long Giáp Tộc lập tức nuốt vào sau khi tước bỏ tư cách trưởng lão thứ chín của Lạc Sinh hội.","phanLoaiPhu":"Đan dược trừng phạt","hinhDang":"Viên đan dược màu đen","congNang":["Được dùng làm hình phạt theo khẩu dụ đại đế, buộc tộc trưởng Long Giáp Tộc phải nuốt ngay @c1293"],"chuHienThoi":"Tộc trưởng Long Giáp Tộc","chuSoHuu":[{"ten":"Điên Lạc đại đế","tuChuong":"@c1293","denChuong":"@c1293","cachCoDuoc":"Ban xuống theo khẩu dụ","trangThai":"đã ban"},{"ten":"Nam tử trung niên hồng sam","tuChuong":"@c1293","denChuong":"@c1293","cachCoDuoc":"Mang đan theo khẩu dụ đại đế","trangThai":"đã trao"},{"ten":"Tộc trưởng Long Giáp Tộc","tuChuong":"@c1293","denChuong":"","cachCoDuoc":"Bị sứ giả đại đế ban cho và buộc nuốt","trangThai":"bị ép dùng"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1293","loai":"xuất hiện","importance":"normal","giaiDoan":"Ban đan xử phạt","text":"Sứ giả đại đế ban viên đan dược màu đen cho tộc trưởng Long Giáp Tộc theo khẩu dụ và buộc hắn lập tức nuốt vào.","anchor":"kinh ngạc nhìn viên đan dược màu đen lơ lửng trước mặt"}]},"capNhatToi":"@c1293","nguon":["@c1293"]},{"id":"ngoc-boi-mau-xanh-chu-de","name":"Ngọc bội màu xanh chữ “đế”","cn":"","aliases":["Ngọc bội Điên Lạc đại đế đưa Vương Lâm"],"category":"phap-bao","categoryLabel":"Tín vật thân phận","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Tín vật thân phận thiếu đế do Điên Lạc đại đế sai sứ giả giao cho Vương Lâm. Trong vùng đất Điên Lạc, nó có uy thế như đại đế đích thân tới.","detail":"Sứ giả của đại đế trao ngọc bội màu xanh có chữ “đế” cho Vương Lâm sau khi xử trí Long Giáp Tộc. Vật này đại biểu thân phận thiếu đế, bảo đảm không ai trong vùng đất Điên Lạc dám làm chuyện bất lợi với Vương Lâm.","phanLoaiPhu":"tín vật thân phận","hinhDang":"ngọc bội màu xanh có chữ “đế”","nguonGoc":"Do Điên Lạc đại đế sai sứ giả đưa tới","congNang":["Biểu trưng thân phận thiếu đế của Vương Lâm trong vùng đất Điên Lạc @c1294","Có uy thế như Điên Lạc đại đế đích thân tới @c1294"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1294","denChuong":"","cachCoDuoc":"Sứ giả đại đế trao theo lệnh Điên Lạc đại đế","trangThai":"đang giữ"}],"capNhatToi":"@c1294","tabs":{"tienTrinh":[{"chuong":"@c1294","loai":"xuất hiện","importance":"normal","giaiDoan":"Tín vật thiếu đế","text":"Sứ giả trao ngọc bội xanh chữ “đế” cho Vương Lâm, xác nhận đây là tín vật đại biểu thân phận thiếu đế.","anchor":"Ngọc bội này như đại đế đích thân tới, ở vùng đất Điên Lạc không người nào dám làm chuyện bất lợi đối với ngài"}]},"nguon":["@c1294"]},{"id":"pho-tuong-bi-tan-pha-cua-tham-lang","name":"Pho tượng bị tàn phá của Tham Lang","cn":"","aliases":["Pho tượng bị tàn phá"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Tham Lang"],"trangThai":"đang thuộc Tham Lang","blurb":"Pháp bảo dạng pho tượng tàn phá từng được Tham Lang xuất ra khi bị tu sĩ thiên nhân đệ nhất suy truy sát. Uy lực của nó đủ diệt đối thủ và chấn động vùng đất Điên Lạc.","detail":"Khi một tộc lạc phái tu sĩ thiên nhân đệ nhất suy truy sát, Tham Lang dùng pháp bảo được đồn là pho tượng bị tàn phá. Lúc xuất hiện, mây mù bao phủ tinh vực, cuối cùng tu sĩ thiên nhân đệ nhất suy bị diệt tuyệt, khiến các tu sĩ thiên nhân suy kiếp ở Điên Lạc chấn kinh.","phanLoaiPhu":"pho tượng","hinhDang":"pho tượng bị tàn phá","uyLuc":"Có thể diệt tu sĩ thiên nhân đệ nhất suy trong lời thuật lại của chương.","dacDiem":"Khi xuất hiện gây mây mù bao phủ tinh vực, tạo uy thế lớn.","chuHienThoi":"Tham Lang","congNang":["Diệt tu sĩ thiên nhân đệ nhất suy trong một lần Tham Lang bị truy sát @c1295"],"chuSoHuu":[{"ten":"Tham Lang","tuChuong":"@c1295","denChuong":"","cachCoDuoc":"không rõ","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1295","loai":"dùng","importance":"normal","giaiDoan":"Truy sát tại Điên Lạc","text":"Tham Lang xuất ra pho tượng bị tàn phá khi bị tu sĩ thiên nhân đệ nhất suy truy sát và dùng nó diệt đối phương.","anchor":"Trong số đó có một pháp bảo mà nghe đồn là một pho tượng bị tàn phá","phamCap":"không rõ"}]},"dinhDanh":"goc","capNhatToi":"@c1295","nguon":["@c1295"]},{"id":"con-roi-thien-nhan-de-nhat-suy-cua-long-giap-toc","name":"Con rối thiên nhân đệ nhất suy của Long Giáp Tộc","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Con rối","phamCap":"Thiên Nhân Đệ Nhất Suy","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Con rối mạnh nhất trong số vô số con rối Long Giáp Tộc giao cho Vương Lâm sau biến cố tại tộc này.","detail":"Khi rời tu chân tinh Long Giáp Tộc, Vương Lâm mang theo vô số con rối; trong đó con rối có tu vi cao nhất đạt thiên nhân đệ nhất suy.","phanLoaiPhu":"Con rối chiến đấu","chuHienThoi":"Vương Lâm","congNang":["Con rối có tu vi cao nhất trong chiến lợi phẩm Long Giáp Tộc mà Vương Lâm thu được @c1296"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1296","denChuong":"","cachCoDuoc":"Long Giáp Tộc giao toàn bộ tích lũy","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1296","loai":"xuất hiện","importance":"normal","giaiDoan":"Theo tích lũy Long Giáp Tộc về tay Vương Lâm","text":"Con rối thiên nhân đệ nhất suy được nêu là con rối mạnh nhất trong số chiến lợi phẩm Long Giáp Tộc mà Vương Lâm mang đi.","anchor":"trong đó tu vi cao nhất là một con rối lên tới thiên nhân đệ nhất suy","phamCap":"Thiên Nhân Đệ Nhất Suy"}]},"dinhDanh":"goc","capNhatToi":"@c1296","nguon":["@c1296"]},{"id":"quat-lon-cua-tham-lang","name":"Quạt lớn của Tham Lang","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Tham Lang"],"trangThai":"dang-co","blurb":"Pháp bảo dạng quạt lớn được Tham Lang dùng để trút giận và thị uy trước Ám Hạt Tộc.","detail":"Tham Lang gọi ra quạt lớn rồi quạt một cái, tạo cuồng phong làm núi sụp, phá tan động phủ của Vương Lâm, đánh bay và làm bị thương nhiều tộc nhân Ám Hạt Tộc.","hinhDang":"Quạt lớn","uyLuc":"Một lần quạt làm rung động khu vực, phá núi và phá động phủ.","chuHienThoi":"Tham Lang","congNang":["Tạo cuồng phong phá núi, phá động phủ và cuốn bay tu sĩ @c1296"],"chuSoHuu":[{"ten":"Tham Lang","tuChuong":"@c1296","denChuong":"","cachCoDuoc":"Đã sở hữu khi tới Ám Hạt Tộc","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1296","loai":"dùng","importance":"normal","giaiDoan":"Phá động phủ Vương Lâm","text":"Tham Lang dùng quạt lớn quét qua khu vực Ám Hạt Tộc, khiến núi và động phủ của Vương Lâm tan tành.","anchor":"Một cây quạt lớn đột nhiên xuất hiện","phamCap":"Chưa rõ"}]},"dinhDanh":"goc","capNhatToi":"@c1296","nguon":["@c1296"]},{"id":"chin-muoi-chin-thanh-truong-kiem-cua-tham-lang","name":"Chín mươi chín thanh trường kiếm của Tham Lang","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Tham Lang"],"trangThai":"bo-lai","blurb":"Bộ trường kiếm được Tham Lang biến ảo ra khi phô bày kho pháp bảo trước Vân Độn tộc.","detail":"Sau chín tấm bia đá, Tham Lang gọi ra chín mươi chín thanh trường kiếm, khiến kiếm khí cuồn cuộn trong màn khoe pháp bảo của hắn.","uyLuc":"Tạo kiếm khí cuồn cuộn khi xuất hiện.","chuHienThoi":"Tham Lang","congNang":["Biến ảo thành chín mươi chín thanh trường kiếm, phóng ra kiếm khí trong màn thị uy @c1296"],"chuSoHuu":[{"ten":"Tham Lang","tuChuong":"@c1296","denChuong":"","cachCoDuoc":"Đã sở hữu khi tới Ám Hạt Tộc","trangThai":"bỏ lại khi chạy"}],"tabs":{"tienTrinh":[{"chuong":"@c1296","loai":"xuất hiện","importance":"normal","giaiDoan":"Phô bày trước Vân Độn tộc","text":"Tham Lang biến ảo ra chín mươi chín thanh trường kiếm trong lúc khoe pháp bảo chờ chủ nhân của Chung Đại Hồng tới.","anchor":"có chín mươi chín thanh trường kiếm biến ảo ra","phamCap":"Chưa rõ"}]},"dinhDanh":"goc","capNhatToi":"@c1296","nguon":["@c1296"]},{"id":"thanh-quang-hoa-rung-cay-cua-tham-lang","name":"Thanh quang hóa rừng cây của Tham Lang","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Tham Lang"],"trangThai":"bo-lai","blurb":"Mảnh thanh quang của Tham Lang rơi xuống đất, khiến cây cối mọc lên và hóa thành một rừng lớn.","detail":"Trong màn phô bày pháp bảo, Tham Lang gọi một mảnh thanh quang rơi xuống tinh cầu; nơi đó nhanh chóng mọc cây, lan thành rừng và tiếp tục kết thành thụ nhân khổng lồ.","hinhDang":"Mảnh thanh quang","congNang":["Khi rơi xuống đất có thể khiến cây cối mọc lên thành rừng @c1296"],"chuSoHuu":[{"ten":"Tham Lang","tuChuong":"@c1296","denChuong":"","cachCoDuoc":"Đã sở hữu khi tới Ám Hạt Tộc","trangThai":"bỏ lại khi chạy"}],"tabs":{"tienTrinh":[{"chuong":"@c1296","loai":"dùng","importance":"normal","giaiDoan":"Hóa rừng thành thế trận","text":"Thanh quang của Tham Lang rơi xuống tinh cầu, làm cây lớn mọc lên và lan thành rừng.","anchor":"nháy mắt trên tinh cầu này liền mọc lên một cây đại thụ","phamCap":"Chưa rõ"}]},"dinhDanh":"goc","capNhatToi":"@c1296","nguon":["@c1296"]},{"id":"thu-nhan-khong-lo-cua-tham-lang","name":"Thụ nhân khổng lồ của Tham Lang","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Hóa hình pháp bảo","phamCap":"Chưa rõ","soHuu":["Tham Lang"],"trangThai":"bo-lai","blurb":"Người cây cực lớn do rừng cây từ thanh quang của Tham Lang kết thành.","detail":"Rừng cây do pháp bảo thanh quang tạo ra co tụ lại thành một thụ nhân khổng lồ, tỏa khí tức cường đại và để Tham Lang đứng trên đầu thị uy.","hinhDang":"Người cây khổng lồ","uyLuc":"Tỏa khí tức cường đại khi ngưng tụ thành hình.","congNang":["Do vô số đại thụ kết thành người cây khổng lồ cho Tham Lang đứng trên đầu @c1296"],"chuSoHuu":[{"ten":"Tham Lang","tuChuong":"@c1296","denChuong":"","cachCoDuoc":"Do thanh quang hóa rừng cây ngưng tụ","trangThai":"bỏ lại khi chạy"}],"tabs":{"tienTrinh":[{"chuong":"@c1296","loai":"xuất hiện","importance":"normal","giaiDoan":"Ngưng tụ từ rừng cây","text":"Rừng cây từ pháp bảo của Tham Lang kết thành thụ nhân khổng lồ, nâng hắn đứng trên đầu.","anchor":"rõ ràng là một người do vô số đại thụ tạo thành","phamCap":"Chưa rõ"}]},"dinhDanh":"bien-the","capNhatToi":"@c1296","nguon":["@c1296"]},{"id":"thien-hoang-lo","name":"Thiên Hoàng lô","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Chí bảo","phamCap":"Chí bảo","soHuu":["Tham Lang"],"trangThai":"bo-lai","blurb":"Pháp khí vương tộc Cổ Thần, chiếc lò đỏ khổng lồ tỏa khí tang thương, cần huyết thống vương tộc Cổ Thần và tinh điểm Cổ Thần để kích hoạt, dùng bao vây và luyện hóa đối thủ. (+) Chí bảo nổi danh của Tham Lang, được Vân Độn tộc nhận ra khi hắn phô bày pháp bảo. [CAN-SOAT-GOP]","detail":"Thiên Hoàng lô được Tham Lang gọi ra từ khe nứt. Tu sĩ Vân Độn tộc kể rằng năm xưa khi Tham Lang còn ở Tịnh Niết, hắn từng dùng bảo này phản kích ba Toái Niết, giết một người và làm trọng thương hai người.","uyLuc":"Từng giúp Tham Lang khi ở Tịnh Niết phản kích ba Toái Niết, giết một làm trọng thương hai.","chuHienThoi":"Tham Lang","congNang":["Có uy lực đủ để Tham Lang dùng khi Tịnh Niết phản kích ba Toái Niết @c1296"],"chuSoHuu":[{"ten":"Tham Lang","tuChuong":"@c1296","denChuong":"","cachCoDuoc":"Đã sở hữu từ trước","trangThai":"bỏ lại khi chạy"}],"tabs":{"tienTrinh":[{"chuong":"@c1296","loai":"xuất hiện","importance":"normal","giaiDoan":"Chí bảo được phô bày","text":"Tham Lang gọi Thiên Hoàng lô ra trước Vân Độn tộc, khiến tu sĩ nhận ra uy danh cũ của bảo vật này.","anchor":"Đây chính là Thiên Hoàng lô chí bảo của Tham Lang","phamCap":"Chí bảo"}]},"dinhDanh":"goc","capNhatToi":"@c1296","nguon":["@c1296","@c1332"]},{"id":"truong-thuong-suong-mu-cua-tham-lang","name":"Trường thương sương mù của Tham Lang","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Tham Lang"],"trangThai":"bo-lai","blurb":"Trường thương do hắc vụ co rút hóa thành trong màn phô bày pháp bảo của Tham Lang.","detail":"Sau khi Thiên Hoàng lô xuất hiện, hắc vụ co rút hóa thành một cây trường thương sương mù, tỏa ra lực lượng hủy thiên diệt địa.","hinhDang":"Trường thương do sương mù tạo thành","uyLuc":"Tỏa lực lượng hủy thiên diệt địa khi xuất hiện.","congNang":["Hắc vụ co rút thành trường thương, tỏa lực lượng hủy diệt mạnh mẽ @c1296"],"chuSoHuu":[{"ten":"Tham Lang","tuChuong":"@c1296","denChuong":"","cachCoDuoc":"Đã sở hữu khi tới Ám Hạt Tộc","trangThai":"bỏ lại khi chạy"}],"tabs":{"tienTrinh":[{"chuong":"@c1296","loai":"xuất hiện","importance":"normal","giaiDoan":"Hắc vụ hóa thương","text":"Trường thương sương mù được Tham Lang gọi ra sau Thiên Hoàng lô, tỏa uy thế hủy diệt.","anchor":"Cây trường thương này do sương mù tạo thành","phamCap":"Chưa rõ"}]},"dinhDanh":"goc","capNhatToi":"@c1296","nguon":["@c1296"]},{"id":"vu-ma-thuong","name":"Vụ Ma Thương","cn":"","aliases":["Trường thương do sương mù màu đen tạo thành","Trường thương sương mù của Tham Lang"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm","Tham Lang"],"trangThai":"đổi chủ sang Vương Lâm","blurb":"Trường thương ngưng thành từ sương mù đen, vốn là pháp bảo của Tham Lang, mang khí tức Cổ Ma lâu đời ở bên ngoài. Sau khi bị Vương Lâm xóa liên hệ và thu lấy tại tu chân tinh Ám Hạt Tộc, Tham Lang ở xa cảm ứng được mà phản ứng dữ dội.","detail":"Vụ Ma Thương xuất hiện trong số bảo vật Tham Lang bỏ lại trên tu chân tinh Ám Hạt Tộc. Nó liên tục chuyển hóa hình thái bên trong màn sương mù đen, bản thân mang dấu vết liên quan tới Cổ Ma với khí tức lâu đời phủ ở bên ngoài. Khi Vương Lâm xóa liên hệ chủ nhân và thu lấy pháp bảo này, Tham Lang dù ở xa vẫn cảm ứng được, lập tức phun máu — cho thấy đây là món vật mà Tham Lang xem trọng. Vương Lâm nhận định khí tức Cổ Ma trên thương đã tồn tại từ rất lâu.","phanLoaiPhu":"trường thương sương mù","hinhDang":"trường thương do sương mù màu đen tạo thành","nguonGoc":"có dấu vết liên quan Cổ Ma","uyLuc":"Đủ khiến Tham Lang xem là pháp bảo quan trọng; khi bị xóa liên hệ chủ nhân, Tham Lang dù ở xa vẫn cảm ứng được mà phun máu, phản ứng dữ dội.","dacDiem":"Sương mù đen liên tục chuyển hóa hình thái, bên ngoài phủ khí tức Cổ Ma lâu đời, có dấu vết liên quan Cổ Ma.","chuHienThoi":"Vương Lâm","congNang":["Biến hóa liên tục hình thái trong sương mù đen, sử dụng như pháp bảo dạng trường thương. @c1297","Bên ngoài thương mang khí tức Cổ Ma lâu đời. @c1297"],"chuSoHuu":[{"ten":"Tham Lang","tuChuong":"@c1297","denChuong":"@c1297","cachCoDuoc":"đã có trước khi gặp lại Vương Lâm","trangThai":"mất"},{"ten":"Vương Lâm","tuChuong":"@c1297","denChuong":"","cachCoDuoc":"thu lấy sau khi Tham Lang bỏ chạy","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1297","loai":"đổi chủ","importance":"major","giaiDoan":"Bị Vương Lâm thu","text":"Vụ Ma Thương bị Vương Lâm thu lấy, đồng thời lộ đặc điểm có khí tức Cổ Ma rất lâu đời.","anchor":"Một bên còn có trường thương do sương mù màu đen tạo thành"}]},"capNhatToi":"@c1297","nguon":["@c1297"]},{"id":"tang-thien-moc-linh","name":"Táng Thiên Mộc Linh","cn":"","aliases":["Thụ nhân","Thụ nhân do rừng rậm biến thành"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm","Tham Lang"],"trangThai":"đổi chủ sang Vương Lâm","blurb":"Táng Thiên Mộc Linh là thụ nhân do rừng rậm biến thành, vốn thuộc về Tham Lang. Dù mất điều khiển, nó vẫn sở hữu lực phòng hộ cực mạnh, có thể phản chấn làm đại thủ hư ảo của Vương Lâm sụp đổ, sau đó bị hắn thu vào không gian trữ vật.","detail":"Sau khi các bảo vật khác của Tham Lang bị Vương Lâm thu đoạt, hắn thử đánh một chưởng vào Táng Thiên Mộc Linh — vốn là thụ nhân đang đứng ngơ ngác vì mất chủ nhân điều khiển. Bất ngờ, lực phòng hộ tự thân của thụ nhân phản chấn trở lại khiến đại thủ hư ảo của Vương Lâm sụp đổ hoàn toàn. Nhận ra giá trị của bảo vật này, Vương Lâm phun nguyên thần tinh khí hóa thành lưới ánh sáng, cuốn Táng Thiên Mộc Linh vào không gian trữ vật, chính thức đổi chủ.","phanLoaiPhu":"mộc linh dạng thụ nhân","hinhDang":"thụ nhân do rừng rậm biến thành","uyLuc":"Lực phòng hộ có thể phản chấn làm đại thủ hư ảo của Vương Lâm sụp đổ hoàn toàn, ngay cả khi thụ nhân không còn ai điều khiển.","dacDiem":"Mất điều khiển vẫn duy trì phòng hộ rất mạnh, cho thấy năng lực tự vệ không phụ thuộc vào chủ nhân.","chuHienThoi":"Vương Lâm","congNang":["Phòng hộ tự phát: dù mất người điều khiển vẫn duy trì lực phòng hộ cực mạnh bao quanh thân thụ nhân. @c1297","Phản chấn công kích: lực phòng hộ tự động đẩy ngược đòn tấn công nhằm vào thụ nhân, đủ sức làm sụp đổ đại thủ hư ảo của Vương Lâm. @c1297"],"chuSoHuu":[{"ten":"Tham Lang","tuChuong":"@c1297","denChuong":"@c1297","cachCoDuoc":"đã có trước khi gặp lại Vương Lâm","trangThai":"mất"},{"ten":"Vương Lâm","tuChuong":"@c1297","denChuong":"","cachCoDuoc":"dùng nguyên thần tinh khí hóa lưới ánh sáng thu vào không gian trữ vật","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1297","loai":"đổi chủ","importance":"major","giaiDoan":"Bị thu vào trữ vật","text":"Táng Thiên Mộc Linh phản chấn một chưởng của Vương Lâm rồi bị hắn dùng lưới ánh sáng thu vào không gian trữ vật.","anchor":"Vương Lâm há mồm phun ra nguyên thần tinh khí, hóa thành một tấm lưới ánh sáng thật lớn"}]},"capNhatToi":"@c1297","nguon":["@c1297"]},{"id":"co-tuc-diep","name":"Cổ Tức Diệp","cn":"","aliases":["Phiến lá khô Nhất diệp phong thiên","Phiến lá khô"],"category":"phap-bao","categoryLabel":"Pháp bảo phong ấn","phamCap":"Không rõ","soHuu":["Vương Lâm","Tham Lang"],"trangThai":"bị Vương Lâm phong ấn và thu giữ","blurb":"Cổ Tức Diệp là phiến lá khô do Tham Lang sử dụng để thi triển thần thông Nhất diệp phong thiên, có khả năng phong bế gợn sóng không gian. Sau khi Tham Lang bị Huyết kiếm trọng thương, Vương Lâm đoạt lấy phiến lá, đánh vô số cấm chế rồi thu vào không gian trữ vật.","detail":"Trong cuộc giao tranh giữa Vương Lâm và Tham Lang, Tham Lang ném Cổ Tức Diệp vào đúng vị trí Vương Lâm sắp hiện thân từ gợn sóng không gian, thi triển Nhất diệp phong thiên để phong ấn tinh không, khiến Vương Lâm bị phản chấn khi cố phá vỡ. Phiến lá cổ này cắt đứt đường hiện thân qua gợn sóng không gian, buộc Vương Lâm phải đổi phương thức truy đuổi. Tuy nhiên, khi Tham Lang bị Huyết kiếm trọng thương, Vương Lâm chụp lấy Cổ Tức Diệp, đánh vô số cấm chế lên trên rồi ném vào không gian trữ vật, hoàn tất việc đổi chủ @c1298.","phanLoaiPhu":"pháp bảo phong ấn","hinhDang":"phiến lá khô","uyLuc":"Phong bế gợn sóng tinh không đủ khiến Vương Lâm phải đổi cách truy đuổi.","dacDiem":"Gắn với thần thông Nhất diệp phong thiên.","chuHienThoi":"Vương Lâm","congNang":["Phong ấn tinh không và gợn sóng không gian, ngăn đối thủ hiện thân tại vị trí bị phong @c1298.","Cắt đường hiện thân của đối thủ đang truy kích qua gợn sóng không gian, buộc đối phương phải chuyển đổi cách di chuyển @c1298."],"chuSoHuu":[{"ten":"Tham Lang","tuChuong":"@c1298","denChuong":"@c1298","cachCoDuoc":"Đã sở hữu trước khi bị truy kích trong vùng đất Điên Lạc.","trangThai":"mất vào tay Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c1298","denChuong":"","cachCoDuoc":"Chụp lấy khi Tham Lang trọng thương không thể điều khiển pháp bảo.","trangThai":"đang giữ, đã phong ấn"}],"tabs":{"tienTrinh":[{"chuong":"@c1298","loai":"đổi chủ","importance":"major","giaiDoan":"Bị Vương Lâm thu giữ","text":"Cổ Tức Diệp từ pháp bảo phong đường của Tham Lang đổi sang tay Vương Lâm sau khi Tham Lang bị trọng thương.","anchor":"Sau khi bị Vương Lâm chụp lấy, liền bị hắn đánh lên vô số cấm chế phong ấn","phamCap":"Không rõ"}]},"capNhatToi":"@c1298","nguon":["@c1298"]},{"id":"ma-hon-binh","name":"Ma Hồn Bình","cn":"","aliases":["Bình ngọc màu đen khắc Cổ Ma","Ma hồn bình"],"category":"phap-bao","categoryLabel":"Pháp bảo chứa ma hồn","phamCap":"Không rõ","soHuu":["Tham Lang","Vương Lâm"],"trangThai":"Đang được luyện hóa","blurb":"Ma Hồn Bình là một bình ngọc màu đen khắc đồ án Cổ Ma, bên trong chứa ba trăm ma hồn Cổ Ma. Tham Lang dùng máu kích hoạt pháp bảo này để triệu hồi ma hồn hợp thành ma phong nhằm phong sát Vương Lâm, nhưng sau đó Vương Lâm khai thác bình, dẫn ma hồn ra dung hợp thành kén ma hồn và phát hiện bên trong còn chứa thêm bí mật.","detail":"Ma Hồn Bình là một pháp bảo hình bình ngọc đen, bề mặt khắc hình Cổ Ma. Khi kích hoạt, người dùng cần hiến máu vào bình và tuyên bố lời giao ước trả phách sinh linh; miệng bình sẽ hiện răng nanh hút máu rồi phun sương đen hóa thành ba trăm ma hồn Cổ Ma. Trong trận chiến tại chương @c1298, Tham Lang dùng Ma Hồn Bình triệu hồi ma hồn hợp thành ma phong tấn công Vương Lâm. Đến chương @c1304, Vương Lâm khai thác Ma Hồn Bình, dẫn các ma hồn bên trong ra ngoài để dung hợp thành kén ma hồn, đồng thời phát hiện trong bình còn chứa thêm bí mật ngoài ma hồn đơn thuần.","phanLoaiPhu":"pháp bảo ma hồn","hinhDang":"bình ngọc màu đen","dacDiem":"Bình ngọc màu đen, bề mặt khắc đồ án Cổ Ma, tỏa hơi lạnh và ma khí; khi kích hoạt, miệng bình hiện răng nanh hút máu người dùng rồi phun sương đen hóa thành ma hồn.","chuHienThoi":"Tham Lang","congNang":["Thả ra ba trăm ma hồn Cổ Ma hợp thành ma phong tấn công đối thủ @c1298","Kích hoạt bằng máu và lời giao ước trả phách sinh linh, miệng bình hiện răng nanh hút máu @c1298","Chứa và phóng thích hồn phách Cổ Ma @c1304","Cung cấp ma hồn để dung hợp thành kén ma hồn @c1304"],"chuSoHuu":[{"ten":"Tham Lang","tuChuong":"@c1298","denChuong":"","cachCoDuoc":"Đã sở hữu trước chương này.","trangThai":"đang giữ"},{"ten":"Vương Lâm","tuChuong":"@c1304","denChuong":"","cachCoDuoc":"Đang nắm giữ và luyện hóa","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1298","loai":"dùng","importance":"normal","giaiDoan":"Mượn ba trăm ma hồn","text":"Tham Lang kích hoạt Ma Hồn Bình bằng máu để gọi ba trăm ma hồn Cổ Ma phong sát Vương Lâm.","anchor":"Bên ngoài bình ngọc có điêu khắc một đồ án, không ngờ có hình dáng như Cổ ma","phamCap":"Không rõ"},{"chuong":"@c1304","loai":"dùng","importance":"major","giaiDoan":"Dung hợp hồn phách Cổ Ma","text":"Vương Lâm khai thác Ma Hồn bình, dẫn ma hồn bên trong ra để dung hợp thành kén và phát hiện trong bình chứa tới ba nghìn hồn phách Cổ Ma.","anchor":"Trong pháp bảo của Cổ Ma này ẩn chứa tới ba nghìn hồn phách của Cổ Ma","phamCap":"Không rõ"}]},"capNhatToi":"@c1298","nguon":["@c1298","@c1304"]},{"id":"ba-tram-ma-hon-co-ma","name":"Ba trăm ma hồn Cổ Ma","cn":"","aliases":["Ba trăm Cổ Ma"],"category":"khac","categoryLabel":"Ma hồn bị phong ấn","phamCap":"Mỗi ma hồn có khí tức tương đương thiên nhân đệ nhất suy","soHuu":["Tham Lang"],"trangThai":"bị tiếng rống Cổ Thần làm tan tác","blurb":"Ba trăm ma hồn Cổ Ma từ Ma Hồn Bình lao ra, mỗi ma hồn có khí tức tương đương tu sĩ thiên nhân đệ nhất suy. Chúng hợp thành ma phong tấn công Vương Lâm nhưng bị tiếng rống Cổ Thần phá tan.","detail":"Các ma hồn có hình dáng rất giống Cổ Ma Tháp Già, nhưng trong đồng tử trái có khí tức Cổ Thần lực. Vương Lâm nhìn ra chúng bị một Cổ Thần lực cường đại phong ấn, rồi dùng tiếng rống Cổ Thần làm ma phong tự tan nát.","phanLoaiPhu":"ma hồn Cổ Ma","uyLuc":"Mỗi ma hồn tỏa khí tức tương đương tu sĩ thiên nhân đệ nhất suy.","dacDiem":"Bị Cổ Thần lực cường đại phong ấn, mang ký ức sợ hãi Cổ Thần.","chuHienThoi":"Tham Lang","congNang":["Hợp thành ma phong để phong sát mục tiêu.","Tạo áp lực bằng số lượng ba trăm ma hồn có khí tức thiên nhân đệ nhất suy."],"chuSoHuu":[{"ten":"Tham Lang","tuChuong":"@c1298","denChuong":"","cachCoDuoc":"Được mượn ra từ Ma Hồn Bình bằng máu và giao ước.","trangThai":"đã bị tiếng rống Cổ Thần làm tản ra"}],"tabs":{"tienTrinh":[{"chuong":"@c1298","loai":"dùng","importance":"normal","giaiDoan":"Ma phong bị phá","text":"Ba trăm ma hồn Cổ Ma hợp thành ma phong tấn công Vương Lâm nhưng bị tiếng rống Cổ Thần làm tan tác.","anchor":"Ba trăm Cổ Ma bị một Cổ Thần lực cường đại phong ấn","phamCap":"Mỗi ma hồn có khí tức tương đương thiên nhân đệ nhất suy"}]},"capNhatToi":"@c1298","nguon":["@c1298"]},{"id":"phu-kinh-kiem","name":"Phù Kinh Kiếm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tham Lang"],"trangThai":"Từng do Tham Lang lấy được từ cổ mộ; sau trận với Vương Lâm không nêu rõ còn giữ hay đã mất.","blurb":"Một pháp bảo của Tham Lang, được hắn khai là lấy từ cổ mộ bí ẩn trong dòng xoáy bên rìa La Thiên Tinh Vực.","detail":"Phù Kinh Kiếm nằm trong nhóm pháp bảo Tham Lang kể ra khi bị Vương Lâm ép hỏi nguồn gốc pho tượng bị tàn phá. Hắn nói các vật như Phù Kinh Kiếm, Cốt bi, Vụ Ma Thương và nhiều pháp bảo khác đều lấy được từ khu mộ dị thường có đầu lâu khổng lồ, không gian loạn lưu và sương mù sâu bên trong.","nguon":["@c1300"]},{"id":"van-co-moc-linh","name":"Vạn Cổ Mộc Linh","cn":"","category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Tham Lang"],"trangThai":"Được Tham Lang lấy trong khu rừng khô héo của cổ mộ.","blurb":"Mộc linh Tham Lang lấy được từ cây đại thụ duy nhất chưa hoàn toàn chết khô trong khu rừng khô héo của cổ mộ.","detail":"Sau khi bị cuốn sâu trong cổ mộ và tỉnh lại tại một khu rừng khô héo vô biên, Tham Lang đi nhiều năm mới gặp một cây đại thụ còn chưa hoàn toàn khô chết. Hắn lấy vật liên quan đến cây đại thụ này, cùng Cổ Tức Diệp, rồi tiếp tục đi tới trung tâm rừng nơi đặt pho tượng bí ẩn.","nguon":["@c1300"]},{"id":"binh-ngoc-cua-toc-truong-van-don-toc","name":"Bình ngọc của tộc trưởng Vân Độn tộc","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Chung Đại Hồng"],"trangThai":"Được tộc trưởng Vân Độn tộc dâng làm hậu lễ cho Chung Đại Hồng.","blurb":"Chiếc bình ngọc do tộc trưởng Vân Độn tộc lấy ra làm hậu lễ, mong Chung Đại Hồng nói giúp trước Vương Lâm.","detail":"Trên tu chân tinh của Ám Hạt Tộc, Vân Độn tộc vì sợ uy danh chủ nhân của Chung Đại Hồng nên phải cung kính hầu hạ, chữa thương và xin tha lỗi. Tộc trưởng Vân Độn tộc lấy ra một chiếc bình ngọc đưa cho Chung Đại Hồng như lễ vật cầu hòa.","nguon":["@c1300"]},{"id":"ngoc-boi-lua-gat-cua-luu-kim-buu","name":"Ngọc bội lừa gạt của Lưu Kim Bưu","cn":"","category":"khac","categoryLabel":"Vật phẩm hỗ trợ lừa gạt","phamCap":"Không rõ","soHuu":["Vương Lâm","Lưu Kim Bưu"],"trangThai":"bị Vương Lâm thu giữ","blurb":"Ngọc bội từng gắn với khả năng lừa gạt của Lưu Kim Bưu.","detail":"Lưu Kim Bưu ban đầu lấy cớ ngọc bội đã bị Vương Lâm thu nên mình không còn khả năng lừa gạt. Khi bị ép, hắn buộc phải thừa nhận thuật lừa gạt của bản thân không phụ thuộc hoàn toàn vào vật này.","congNang":["Hỗ trợ hoặc gắn với thủ đoạn lừa gạt của Lưu Kim Bưu @c1301"],"chuSoHuu":[{"ten":"Lưu Kim Bưu","tuChuong":"@c1301","denChuong":"@c1301","cachCoDuoc":"Đã có trước khi bị Vương Lâm thu","trangThai":"đã mất"},{"ten":"Vương Lâm","tuChuong":"@c1301","denChuong":"","cachCoDuoc":"Thu giữ từ Lưu Kim Bưu","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1301","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị thu giữ","text":"Lưu Kim Bưu nói ngọc bội của hắn đã bị Vương Lâm thu giữ nên viện cớ không thể tiếp tục lừa gạt.","anchor":"Hiện giờ ngọc bội đã bị thượng tiên thu rồi, tiểu nhân không thể lừa gạt được ai nữa"}]},"capNhatToi":"@c1301","nguon":["@c1301"]},{"id":"pho-tuong-trung-nien-bay-mau","name":"Pho tượng trung niên bảy màu","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":["Vương Lâm"],"trangThai":"Đang do Vương Lâm giữ","blurb":"Pho tượng khiến ngân y nữ tử sợ hãi cực độ ngay khi Vương Lâm lấy ra. Thân ảnh phong ấn trong thức hải nàng giống hệt pho tượng, cho thấy vật này liên quan trực tiếp tới bí mật bảy màu và biến cố cánh cửa.","detail":"Vương Lâm lấy pho tượng ra trong động phủ để hỏi ngân y nữ tử về thân phận người trong tượng, lập tức kích phát nỗi sợ và ký ức đứt đoạn của nàng. Khi Vương Lâm thi triển Sưu thần thuật, sâu trong thức hải ngân y nữ tử xuất hiện một trung niên áo bảy màu do phong ấn biến thành, giống hệt pho tượng. Chương chỉ xác nhận pho tượng liên hệ với thân ảnh bảy màu, thanh khí và biến cố cánh cửa, chưa xác nhận thân phận thật của người trong tượng.","nguon":["@c1303"]},{"id":"mau-tuoi-co-than-cua-vuong-lam","name":"Máu tươi Cổ Thần của Vương Lâm","cn":"","aliases":["Máu tươi Cổ Thần Vương Lâm"],"category":"nguyen-lieu","categoryLabel":"Huyết mạch/vật liệu luyện hóa","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đã dùng để huyết luyện","blurb":"Máu Cổ Thần của Vương Lâm được dùng làm vật liệu huyết luyện kén ma hồn. Cùng với bổn nguyên lực, nó giúp áp chế phản kháng của ma hồn.","detail":"Trong quá trình luyện Ma Hồn bình, Vương Lâm phun máu lên kén ma hồn. Máu này có cả máu Cổ Thần của hắn, góp phần khiến kén ma hồn bị huyết luyện và chuyển sang huyết sắc.","phanLoaiPhu":"Huyết mạch Cổ Thần","congNang":["Dùng làm vật liệu huyết luyện kén ma hồn @c1304","Góp phần áp chế phản kháng của ma hồn @c1304"],"chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1304","denChuong":"","cachCoDuoc":"Huyết mạch tự thân","trangThai":"da-dung-mot-phan"}],"tabs":{"tienTrinh":[{"chuong":"@c1304","loai":"dùng","importance":"normal","giaiDoan":"Huyết luyện kén ma hồn","text":"Vương Lâm dùng máu tươi có cả máu Cổ Thần của mình để huyết luyện kén ma hồn.","anchor":"cũng có cả máu Cổ Thần của Vương Lâm","phamCap":"Không rõ"}]},"capNhatToi":"@c1304","nguon":["@c1304"]},{"id":"giot-mau-chu-tuoc-co-bon-nguyen","name":"Giọt máu Chu Tước có bổn nguyên","cn":"","aliases":["Máu Chu Tước có bổn nguyên"],"category":"nguyen-lieu","categoryLabel":"Huyết vật","phamCap":"Không rõ","soHuu":["Hỏa Tước tộc","Lão tổ Hỏa Tước tộc"],"trangThai":"Được Hỏa Tước tộc xác nhận và truy nguồn","blurb":"Giọt máu có bổn nguyên được đưa từ vùng đất Điên Lạc về Hỏa Tước tộc. Lão tổ của tộc xác nhận đây là máu Chu Tước, từ đó phát tộc mệnh truy tìm nguồn gốc giọt máu tại vùng đất Điên Lạc.","detail":"Ba tộc nhân Hỏa Tước tộc hộ tống giọt máu từ vùng đất Điên Lạc về chủ tinh Hỏa Tước. Tộc trưởng phát hiện giọt máu đang thiêu đốt mang bổn nguyên, nhận thấy sự trọng đại nên vào thánh địa cầu kiến lão tổ. Lão tổ nhiều lần kiểm tra và xác nhận đây là máu Chu Tước có bổn nguyên — một phát hiện được coi là đầu mối trọng yếu. Từ đó, lão tổ ra lệnh toàn tộc phát tộc mệnh truy tìm nguồn gốc giọt máu tại vùng đất Điên Lạc.","phanLoaiPhu":"Máu Chu Tước","hinhDang":"Giọt máu đang thiêu đốt","dacDiem":"Có bổn nguyên và được lão tổ Hỏa Tước tộc xác nhận là máu Chu Tước.","congNang":["Khiến cao tầng Hỏa Tước tộc nhận ra dấu vết bổn nguyên liên quan Chu Tước @c1304","Trở thành đầu mối khiến Hỏa Tước tộc phát tộc mệnh truy tìm nguồn gốc tại vùng đất Điên Lạc @c1304"],"chuHienThoi":"Hỏa Tước tộc","chuSoHuu":[{"ten":"Ba tộc nhân Hỏa Tước tộc từ vùng đất Điên Lạc","tuChuong":"@c1304","denChuong":"@c1304","cachCoDuoc":"Hộ tống từ vùng đất Điên Lạc","trangThai":"da-nop"},{"ten":"Tộc trưởng Hỏa Tước tộc","tuChuong":"@c1304","denChuong":"@c1304","cachCoDuoc":"Tiếp nhận từ tộc nhân","trangThai":"da-dang-len-lao-to"},{"ten":"Lão tổ Hỏa Tước tộc","tuChuong":"@c1304","denChuong":"","cachCoDuoc":"Nhận để xác minh trong thánh địa","trangThai":"dang-truy-nguon"}],"tabs":{"tienTrinh":[{"chuong":"@c1304","loai":"xuất hiện","importance":"major","giaiDoan":"Được xác nhận là máu Chu Tước","text":"Giọt máu từ Điên Lạc được đưa về Hỏa Tước tộc, sau đó được lão tổ xác nhận là máu Chu Tước có bổn nguyên và trở thành nguyên nhân khiến toàn tộc truy tìm nguồn gốc.","anchor":"Không sai, về bổn nguyên cũng không sai","phamCap":"Không rõ"}]},"capNhatToi":"@c1304","nguon":["@c1304"]},{"id":"hon-dan","name":"Hồn đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan/vật chứa bổn nguyên","phamCap":"Không rõ","soHuu":["Trưởng lão Hỏa Tước tộc từng giao dịch với Vương Lâm"],"trangThai":"Được nhắc tới","blurb":"Hồn đan được nhắc qua cảm nhận của trưởng lão Hỏa Tước tộc. Khí tức bổn nguyên trong nó giống với tia bổn nguyên còn lại tại tinh cầu hoang dã ở Điên Lạc.","detail":"Khi truy xét tinh cầu hoang dã sau dị biến lam hỏa, trưởng lão Hỏa Tước tộc nhận ra nơi đó có một tia bổn nguyên giống hệt trong hồn đan từng giao dịch. Chi tiết này nối dị biến Điên Lạc với đầu mối mà ông từng biết.","congNang":["Lưu lại hoặc chứa khí tức bổn nguyên để trưởng lão Hỏa Tước tộc đối chiếu @c1304"],"dacDiem":"Có khí tức bổn nguyên tương tự khí tức tại tinh cầu hoang dã.","tabs":{"tienTrinh":[{"chuong":"@c1304","loai":"nhắc tới","importance":"normal","giaiDoan":"Đối chiếu khí tức bổn nguyên","text":"Hồn đan được nhắc khi trưởng lão Hỏa Tước tộc cảm nhận tia bổn nguyên tại tinh cầu hoang dã giống hệt khí tức trong nó.","anchor":"cảm nhận được một tia bổn nguyên giống hệt như trong hồn đan kia","phamCap":"Không rõ"}]},"capNhatToi":"@c1304","nguon":["@c1304"]},{"id":"pho-tuong-hoa-tuoc-tren-chu-tinh-hoa-tuoc","name":"Pho tượng Hỏa tước trên chủ tinh Hỏa Tước","cn":"","aliases":[],"category":"khac","categoryLabel":"Thánh tượng","phamCap":"Không rõ","soHuu":["Hỏa Tước tộc"],"trangThai":"Tồn tại trên chủ tinh Hỏa Tước","blurb":"Pho tượng Hỏa Tước khổng lồ trên chủ tinh Hỏa Tước. Bên dưới tượng có đại điện nơi tộc trưởng Hỏa Tước tộc đả tọa và xem xét giọt máu được đưa về.","detail":"Trên chủ tinh Hỏa Tước có một pho tượng Hỏa Tước toàn thân bị lửa thiêu đốt. Đại điện dưới pho tượng là nơi tộc trưởng Hỏa Tước tộc tiếp nhận và kiểm tra giọt máu có bổn nguyên trước khi vào thánh địa.","hinhDang":"Pho tượng Hỏa Tước cao lớn, toàn thân thiêu đốt","nguonGoc":"Hỏa Tước tộc","dacDiem":"Gắn với đại điện của tộc trưởng trên chủ tinh Hỏa Tước.","tabs":{"tienTrinh":[{"chuong":"@c1304","loai":"xuất hiện","importance":"normal","giaiDoan":"Đại điện dưới thánh tượng","text":"Pho tượng Hỏa Tước trên chủ tinh xuất hiện như địa điểm gắn với đại điện nơi tộc trưởng kiểm tra giọt máu.","anchor":"trên chủ tinh Hỏa tước có một pho tượng Hỏa tước","phamCap":"Không rõ"}]},"capNhatToi":"@c1304","nguon":["@c1304"]},{"id":"phien-la-cay-kho-vang","name":"Phiến lá cây khô vàng","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Một phiến lá cây khô vàng được Vương Lâm lấy ra sau khi suy tính về hợp nhất thần, ma, yêu. Chương này chưa nói rõ công dụng.","detail":"Vương Lâm lấy ra phiến lá khô vàng cùng một thụ nhân bị phong ấn sau khi tự hỏi về khả năng hợp nhất ba thân thể thần, ma, yêu để phản tổ thành cổ. Công năng cụ thể của vật này chưa được giải thích trong chương 1305.","hinhDang":"Phiến lá cây khô vàng","chuHienThoi":"Vương Lâm","congNang":[],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1305","denChuong":"","cachCoDuoc":"Được lấy ra từ túi đồ hoặc vật sở hữu của Vương Lâm","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1305","loai":"xuất hiện","importance":"normal","giaiDoan":"Được lấy ra","text":"Vương Lâm lấy ra một phiến lá cây khô vàng sau khi suy tính về ba thân thể thần, ma, yêu.","anchor":"Một cái là một phiến lá cây khô vàng"}]},"capNhatToi":"@c1305","nguon":["@c1305"]},{"id":"thu-nhan-bi-phong-an","name":"Thụ nhân bị phong ấn","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm/sinh linh bị phong ấn","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"bi-phong-an","blurb":"Một thụ nhân đang bị phong ấn, được Vương Lâm lấy ra cùng phiến lá cây khô vàng. Chương này chưa giải thích thân phận hay công dụng của thụ nhân.","detail":"Thụ nhân bị phong ấn xuất hiện khi Vương Lâm lấy ra hai vật sau suy tính về thần, ma, yêu. Thông tin hiện có chỉ xác nhận trạng thái bị phong ấn và nằm trong tay Vương Lâm.","hinhDang":"Thụ nhân bị phong ấn","chuHienThoi":"Vương Lâm","congNang":[],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1305","denChuong":"","cachCoDuoc":"Được Vương Lâm lấy ra cùng phiến lá cây khô vàng","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1305","loai":"xuất hiện","importance":"normal","giaiDoan":"Được lấy ra","text":"Vương Lâm lấy ra một thụ nhân bị phong ấn cùng phiến lá cây khô vàng.","anchor":"một là một thụ nhân bị phong ấn"}]},"capNhatToi":"@c1305","nguon":["@c1305"]},{"id":"do-an-bat-giac-cua-van-lac","name":"Đồ án bát giác của Vân Lạc","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm/phương tiện","phamCap":"Không rõ","soHuu":["Vân Lạc"],"trangThai":"dang-co","blurb":"Đồ án bát giác mà Vân Lạc đứng trên khi xuất hiện ngoài vùng đất Điên Lạc. Công năng cụ thể chưa được nêu trong chương này.","detail":"Vân Lạc đại tiểu thư xuất hiện trên một đồ án bát giác ở ngoài vùng đất Điên Lạc, bên cạnh nam tử trung niên. Chương 1305 chỉ mô tả hình dạng và bối cảnh xuất hiện, chưa nêu rõ công dụng.","hinhDang":"Đồ án bát giác","chuHienThoi":"Vân Lạc","congNang":[],"chuSoHuu":[{"ten":"Vân Lạc","tuChuong":"@c1305","denChuong":"","cachCoDuoc":"Đồ án nàng đứng trên khi xuất hiện","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1305","loai":"xuất hiện","importance":"normal","giaiDoan":"Vân Lạc xuất hiện","text":"Vân Lạc đứng trên đồ án bát giác ngoài vùng đất Điên Lạc khi nói chuyện với nam tử trung niên.","anchor":"một nữ tử có mái tóc dài quá vai, đứng trên một đồ án bát giác"}]},"capNhatToi":"@c1305","nguon":["@c1305"]},{"id":"ngoc-gian-moi-cuong-gia-cua-lac-sinh-hoi","name":"Ngọc giản mời cường giả của Lạc Sinh hội","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm/tín vật","phamCap":"Không rõ","soHuu":["Lạc Sinh hội"],"trangThai":"dang-dung","blurb":"Ngọc giản do Lạc Sinh hội đưa ra để mời một số cường giả Thái Cổ Tinh Thần tới trong kỳ tuyển chọn trưởng lão. Đây là tín vật liên quan việc quan chiến hoặc trợ chiến của người ngoài.","detail":"Trong kỳ tuyển chọn trưởng lão, Lạc Sinh hội sẽ đưa ra một số ngọc giản để mời cường giả bên ngoài tới. Người ngoài có thể quan chiến hoặc liên quan trợ chiến, nhưng nếu không thuộc tộc lạc Điên Lạc thì không được trở thành trưởng lão.","chuHienThoi":"Lạc Sinh hội","congNang":["Mời một số cường giả Thái Cổ Tinh Thần tới kỳ tuyển chọn trưởng lão Lạc Sinh hội @c1305"],"chuSoHuu":[{"ten":"Lạc Sinh hội","tuChuong":"@c1305","denChuong":"","cachCoDuoc":"Tín vật do Lạc Sinh hội đưa ra","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1305","loai":"xuất hiện","importance":"normal","giaiDoan":"Dùng mời cường giả","text":"Lạc Sinh hội đưa ra một số ngọc giản để mời cường giả tới kỳ tuyển chọn trưởng lão.","anchor":"Lạc Sinh hội cũng sẽ đưa ra một số ngọc giản, mời một ít cường giả"}]},"capNhatToi":"@c1305","nguon":["@c1305"]},{"id":"ngoc-gian-thong-bao-thieu-de-cua-dien-lac-dai-de","name":"Ngọc giản thông báo thiếu đế của Điên Lạc đại đế","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản thông báo","phamCap":"không rõ","soHuu":["Điên Lạc đại đế"],"trangThai":"đã phát ra","blurb":"Ngọc giản do Điên Lạc đại đế phát cho các bộ tộc để báo sự tồn tại của thiếu đế. Nội dung ban đầu chưa công khai danh tính người được chọn.","detail":"Mấy tháng trước, Điên Lạc đại đế phát ngọc giản báo cho tất cả bộ tộc biết sự tồn tại của thiếu đế. Chương này cho thấy danh tính thiếu đế thứ ba là Vương Lâm được công khai trước mấy vạn tu sĩ.","phanLoaiPhu":"ngọc giản truyền tin","congNang":["Truyền tin về sự tồn tại của thiếu đế tới các bộ tộc @c1307"],"chuSoHuu":[{"ten":"Điên Lạc đại đế","tuChuong":"@c1307","denChuong":"","cachCoDuoc":"người phát ngọc giản","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1307","loai":"nhắc tới","importance":"normal","giaiDoan":"Thông báo thiếu đế","text":"Ngọc giản từng được Điên Lạc đại đế phát cho các bộ tộc để thông báo sự tồn tại của thiếu đế.","anchor":"đã được Điên Lạc đại đế phát ngọc giản, báo cho tất cả các bộ tộc"}]},"capNhatToi":"@c1307","nguon":["@c1307"]},{"id":"do-hinh-bat-giac-khong-lo","name":"Đồ hình bát giác khổng lồ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo độn hành","phamCap":"không rõ","soHuu":["Vân Lạc"],"trangThai":"đang sử dụng","blurb":"Đồ hình bát giác khổng lồ chở Vân Lạc và Tư Mặc Tử tới Đại đế tinh. Nó có kích thước mấy trăm trượng, tỏa sáng và hiện nhiều ký hiệu lóe sáng.","detail":"Một đồ hình bát giác khổng lồ ầm ầm lao tới Đại đế tinh, bên trên có Vân Lạc và Tư Mặc Tử. Pháp bảo này đóng vai trò phương tiện di chuyển trong tinh không khi hai người tới bái kiến đại đế và dự khán tuyển chọn trưởng lão.","hinhDang":"đồ hình bát giác khổng lồ","dacDiem":"Mấy trăm trượng, tỏa sáng, có nhiều ký hiệu lóe sáng.","congNang":["Chở Vân Lạc và Tư Mặc Tử di chuyển trong tinh không tới Đại đế tinh @c1307"],"chuSoHuu":[{"ten":"Vân Lạc","tuChuong":"@c1307","denChuong":"","cachCoDuoc":"đang cưỡi khi xuất hiện trước Đại đế tinh","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1307","loai":"xuất hiện","importance":"normal","giaiDoan":"Tới Đại đế tinh","text":"Đồ hình bát giác khổng lồ chở Vân Lạc và Tư Mặc Tử lao tới gần Đại đế tinh.","anchor":"có một đồ hình bát giác khổng lồ ầm ầm lao tới"}]},"capNhatToi":"@c1307","nguon":["@c1307"]},{"id":"mau-viem-long","name":"Máu Viêm long","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"khong-ro","soHuu":["Chu Tước đời thứ hai","Vương Lâm","Lão Chu Tước"],"trangThai":"dang-dung","blurb":"Huyết dịch hỏa thuộc tính lấy từ đầu Viêm long dưới hồ. Khi Vương Lâm uống vào, nó khiến hỏa bổn nguyên nồng đậm hơn và nguyên lực tăng thêm một tia.","detail":"Chu Tước đời thứ hai tiết lộ thứ trong bầu không phải rượu mà là máu. Máu Viêm long chứa lực lượng hỏa diễm mạnh, bình thuốc thường của Vương Lâm vừa chạm vào đã bị hòa tan, còn bầu rượu của lão giả có thể chứa được.","phanLoaiPhu":"huyết dịch hỏa thuộc tính","nguonGoc":"lấy từ Viêm long dưới hồ","congNang":["Tăng hỏa bổn nguyên của Vương Lâm @c1310","Bổ sung thêm một tia nguyên lực cho Vương Lâm @c1310","Trợ lực thức tỉnh Chu Tước khi nhuộm vào hương thí luyện"],"dacDiem":"Hỏa lực rất mạnh, có thể hòa tan bình thuốc thường.","chuSoHuu":[{"ten":"Chu Tước đời thứ hai","tuChuong":"@c1310","denChuong":"","cachCoDuoc":"câu Viêm long và lấy máu","trangThai":"đang có nguồn lấy máu"},{"ten":"Vương Lâm","tuChuong":"@c1310","denChuong":"","cachCoDuoc":"được uống và hứng máu theo lệnh lão giả","trangThai":"đã luyện hóa một phần"}],"tabs":{"tienTrinh":[{"chuong":"@c1310","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ bản chất","text":"Máu Viêm long được lão giả cho Vương Lâm uống trong bầu, sau đó tiếp tục lấy từ đầu rồng để Vương Lâm hứng và luyện hóa.","anchor":"Đây không phải là rượu mà là máu"},{"chuong":"@c1320","loai":"dùng","importance":"normal","giaiDoan":"Ép máu nhuộm Địa Phương hương","text":"Lão Chu Tước mở vết thương Viêm long ép máu tưới Địa Phương hương đang cháy để trợ lực Vương Lâm thức tỉnh.","anchor":"Máu tươi phun ra, đột nhiên chảy xuống, nhuốm đỏ Địa Phương hương đang cháy kia"}]},"capNhatToi":"@c1310","nguon":["@c1310","@c1320"]},{"id":"bau-ruou-chua-mau-viem-long","name":"Bầu rượu chứa máu Viêm long","cn":"","category":"khac","categoryLabel":"Vật chứa","phamCap":"khong-ro","soHuu":["Chu Tước đời thứ hai","Vương Lâm"],"trangThai":"đang dùng","blurb":"Bầu của Chu Tước đời thứ hai dùng để chứa máu Viêm long. Nó chứa được loại máu mà bình thuốc thường của Vương Lâm không chịu nổi.","detail":"Ban đầu Vương Lâm tưởng thứ trong bầu là rượu, sau mới biết là máu Viêm long. Khi lão giả lấy máu rồng, Vương Lâm cầm bầu bay tới hứng máu, trong khi bình thuốc khác bị máu hòa tan.","phanLoaiPhu":"vật chứa đặc biệt","congNang":["Chứa máu Viêm long @c1310"],"dacDiem":"Có thể chứa máu Viêm long trong khi bình thuốc thường bị hòa tan.","chuSoHuu":[{"ten":"Chu Tước đời thứ hai","tuChuong":"@c1310","denChuong":"","cachCoDuoc":"vật đang dùng bên hồ","trangThai":"đang có"},{"ten":"Vương Lâm","tuChuong":"@c1310","denChuong":"","cachCoDuoc":"cầm bầu hứng máu theo lệnh lão giả","trangThai":"tạm dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1310","loai":"dùng","importance":"normal","giaiDoan":"Hứng máu rồng","text":"Vương Lâm cầm bầu rượu bay tới hứng máu Viêm long phun ra từ đầu rồng theo lệnh Chu Tước đời thứ hai.","anchor":"Vương Lâm không cần nghĩ ngợi, cầm bầu rượu lên, thân thể nhoáng lên liền bay tới"}]},"capNhatToi":"@c1310","nguon":["@c1310"]},{"id":"can-cau-va-day-cau-bac-cua-lao-gia","name":"Cần câu và dây câu bạc của lão giả","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"khong-ro","soHuu":["Chu Tước đời thứ hai"],"trangThai":"đang dùng","blurb":"Bộ cần câu và dây bạc Chu Tước đời thứ hai dùng để câu Viêm long dưới hồ. Dây bạc cực kỳ cứng cỏi, giữ được hung thú có uy áp ngang bước thứ ba.","detail":"Khi mặt hồ nổi sóng, dây câu bạc kéo căng và lôi Viêm long đỏ dài ngàn trượng khỏi đáy hồ. Dù Viêm long vùng vẫy kịch liệt, dây câu vẫn không đứt, cho thấy đây không phải vật thường.","phanLoaiPhu":"dụng cụ câu rồng","congNang":["Câu và giữ Viêm long dưới hồ @c1310"],"uyLuc":"Khống chế được hung thú có uy áp ngang tu sĩ bước thứ ba.","dacDiem":"Dây câu bạc cực kỳ cứng cỏi, chất liệu chưa rõ.","chuSoHuu":[{"ten":"Chu Tước đời thứ hai","tuChuong":"@c1310","denChuong":"","cachCoDuoc":"vật đang dùng để câu bên hồ","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1310","loai":"dùng","importance":"normal","giaiDoan":"Câu Viêm long","text":"Chu Tước đời thứ hai dùng cần câu và dây bạc kéo Viêm long khỏi hồ, khiến nó giãy giụa cũng không thoát.","anchor":"Nhưng không biết sợi dây này làm bằng chất liệu gì mà cực kỳ cứng cỏi"}]},"capNhatToi":"@c1310","nguon":["@c1310"]},{"id":"long-than-huyet-tuu","name":"Long Thần huyết tửu","cn":"","aliases":[],"category":"khac","categoryLabel":"Rượu hỗ trợ thí luyện","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Long Thần huyết tửu là bình rượu được Chu Tước đời thứ hai dặn Vương Lâm nên uống trước thí luyện.","detail":"Vật phẩm này được nhắc như thứ cần dùng đúng thời điểm trước khi Vương Lâm tiến hành thí luyện, có liên hệ trực tiếp tới chuẩn bị cho thí luyện Chu Tước.","congNang":["Hỗ trợ Vương Lâm trước khi tiến hành thí luyện @c1311"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1311","denChuong":"","cachCoDuoc":"Được Chu Tước đời thứ hai nhắc là bình rượu hắn đang có và nên uống trước thí luyện.","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1311","loai":"nhắc tới","importance":"normal","giaiDoan":"Dặn dùng trước thí luyện","text":"Chu Tước đời thứ hai dặn Vương Lâm nên uống Long Thần huyết tửu trước khi vào thí luyện.","anchor":"Bình Long Thần huyết tửu kia ngươi nên uống trước khi thí luyện"}]},"capNhatToi":"@c1311","nguon":["@c1311"]},{"id":"nua-doan-mong-tay-cua-thai-hoang-cong","name":"Nửa đoạn móng tay của Thái Hoang Công","cn":"","category":"khac","categoryLabel":"Vật phẩm phòng thân","phamCap":"Chưa rõ","soHuu":["Vương Lâm"],"trangThai":"Được Thái Hoang Công tặng cho Vương Lâm","blurb":"Nửa đoạn móng tay do Thái Hoang Công búng tới trước mặt Vương Lâm, bên trong chứa độc công. Lão Chu Tước bảo Vương Lâm nhận lấy vì có thể dùng làm lợi khí đả thương địch thủ.","detail":"Trong lúc lão Chu Tước giới thiệu Thái Hoang Công, Thái Hoang Công đánh giá Vương Lâm không tồi rồi tặng hắn một vật phòng thân. Vật ấy là nửa đoạn móng tay bay tới trước mặt Vương Lâm, chứa độc công của Thái Hoang Công, được nhấn mạnh là có thể dùng để phòng thân và đả thương địch thủ.","nguon":["@c1313"]},{"id":"manh-mai-rua-goi-cu-quy","name":"Mảnh mai rùa gọi cự quy","cn":"","category":"khac","categoryLabel":"Vật phẩm liên hệ cự quy","phamCap":"Chưa rõ","soHuu":[],"trangThai":"Được nhắc lại khi thiếu đế thí luyện mở ra","blurb":"Mảnh mai rùa từng khiến cự quy khổng lồ biến ảo hiện ra dưới thần thông của Vương Lâm. Khi thiếu đế thí luyện mở, cự quy ngàn dặm lại hiện thân, cho thấy vật này có liên hệ trực tiếp với cơ chế thí luyện.","detail":"Chương nhắc tới cự quy khổng lồ từng từ một mảnh mai rùa đột nhiên biến ảo ra dưới thần thông của Vương Lâm. Đến lúc lão Chu Tước mở thiếu đế thí luyện, trường đấu ngàn dặm chấn động, long quy gầm thét và cự quy khổng lồ hiện thân, khiến các tu sĩ vùng đất Điên Lạc tránh xa mà cung kính.","nguon":["@c1313"]},{"id":"ba-cay-huong-thien-dia-nhan","name":"Ba cây hương Thiên Địa Nhân","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm thí luyện","phamCap":"khong-ro","soHuu":["Lão Chu Tước"],"trangThai":"đang dùng trong thí luyện thiếu đế","blurb":"Ba cây hương khổng lồ hiện ra trên lưng cự quy trong nghi thức thí luyện thiếu đế. Chúng là vật dẫn để hồn phách người thí luyện tiến vào ba huyễn giới Thiên, Địa, Nhân.","detail":"Khi Lão Chu Tước hô dâng hương, ba cây hương khổng lồ hiện ra trên lưng cự quy, khiến nơi này giống như một tế đàn lớn. Mỗi cây hương tương ứng một huyễn giới và đồng thời là giới hạn thời gian sinh tử cho hồn phách người thí luyện.","phanLoaiPhu":"vật dẫn thí luyện","hinhDang":"ba cây hương khổng lồ chỉ thẳng lên trời","chuHienThoi":"Lão Chu Tước","congNang":["Làm vật dẫn để hồn phách người thí luyện nhập ba huyễn giới Thiên, Địa, Nhân @c1314","Dùng tốc độ cháy của hương làm giới hạn thời gian cho thí luyện @c1314"],"dacDiem":"Ba cây hương xuất hiện cùng lúc trên lưng cự quy và biến nghi thức thành cảnh tượng như tế đàn.","capNhatToi":"@c1314","chuSoHuu":[{"ten":"Lão Chu Tước","tuChuong":"@c1314","denChuong":"","cachCoDuoc":"chủ trì nghi thức dâng hương","trangThai":"đang sử dụng"}],"tabs":{"tienTrinh":[{"chuong":"@c1314","loai":"xuất hiện","importance":"normal","giaiDoan":"Dâng hương","text":"Ba cây hương khổng lồ hiện ra trên lưng cự quy khi Lão Chu Tước mở nghi thức thí luyện thiếu đế.","anchor":"trên lưng cự quy liền có ba cây hương to lớn hiện ra chỉ thẳng lên trời"}]},"nguon":["@c1314"]},{"id":"cay-huong-thu-nhat","name":"Cây hương thứ nhất đại diện cho Nhân","cn":"","aliases":["Cây hương thứ nhất","Nhân phương hương","Cây hương đại diện cho Nhân"],"category":"phap-bao","categoryLabel":"Vật thí luyện","phamCap":"Không rõ","soHuu":[],"trangThai":"đang kích hoạt cửa Nhân","blurb":"Cây hương thứ nhất trong ba cây hương Thiên Địa Nhân, đại diện cho Nhân. Vương Lâm đặt tay lên nó tại Đại Đế tinh để tiến vào cửa Nhân.","detail":"Trong chương này, Vương Lâm đã hiểu cách đốt cây hương đại diện cho Nhân nhưng cố ý chưa đốt ngay, vì muốn nhìn lại quê cũ, cố nhân và Lý Mộ Uyển trong huyễn cảnh. Ở ngoại giới, việc hắn chậm hoàn thành khiến các cường giả theo dõi phản ứng khác nhau.","phanLoaiPhu":"vật thí luyện","chuHienThoi":"Vương Lâm","congNang":["Kích hoạt cửa Nhân và khảo nghiệm Nhân luyện @c1315"],"dacDiem":"Gắn với cửa Nhân, nơi hồn người thí luyện tiến vào huyễn cảnh tâm ma.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1315","denChuong":"","cachCoDuoc":"đặt tay lên trong thí luyện trên Đại Đế tinh","trangThai":"đang sử dụng"}],"capNhatToi":"@c1315","nguon":["@c1315"],"tabs":{"tienTrinh":[{"chuong":"@c1315","loai":"dùng","importance":"normal","giaiDoan":"Đốt hương bị trì hoãn","text":"Vương Lâm đặt tay lên cây hương thứ nhất và đã hiểu cách đốt, nhưng cố ý trì hoãn để tiếp tục nhìn lại nhân sinh trong cửa Nhân.","anchor":"đệ nhất quan này - Cây hương đại diện cho Nhân làm sao mà đốt","phamCap":"Không rõ"}]}},{"id":"bau-ruou-cua-vuong-lam","name":"Bầu rượu của Vương Lâm","cn":"","aliases":[],"category":"khac","categoryLabel":"Rượu/linh tửu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Bầu rượu được Vương Lâm lấy ra trên thuyền trong cửa Nhân. Rượu trong bầu không phải Long Huyết cũng không phải rượu thường, phàm nhân uống có lợi ích lớn.","detail":"Trong lúc đối ẩm với thanh niên phàm nhân giống mình, Vương Lâm lấy rượu của bản thân ra. Loại rượu này được mô tả là phàm nhân uống vào có thể kéo dài tuổi thọ và mở rộng linh trí.","phanLoaiPhu":"linh tửu","chuHienThoi":"Vương Lâm","congNang":["Phàm nhân uống vào có thể kéo dài tuổi thọ và mở rộng linh trí @c1315"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1315","denChuong":"","cachCoDuoc":"đã mang theo khi vào huyễn cảnh cửa Nhân","trangThai":"đang sở hữu"}],"capNhatToi":"@c1315","nguon":["@c1315"],"tabs":{"tienTrinh":[{"chuong":"@c1315","loai":"dùng","importance":"normal","giaiDoan":"Đối ẩm trên thuyền","text":"Vương Lâm lấy bầu rượu của mình ra trong lúc đối ẩm với thanh niên phàm nhân trên thuyền.","anchor":"Phàm nhân uống vào sẽ kéo dài tuổi thọ, linh trí rộng mở","phamCap":"Không rõ"}]}},{"id":"bau-ruou-day-mau-rong","name":"Bầu rượu đầy máu rồng","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Vật phẩm / máu rồng","phamCap":"khong-ro","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Bầu rượu chứa đầy máu rồng được Vương Lâm lấy ra trong lúc chịu bốn chuyển nghiệp hỏa.","detail":"Vương Lâm lấy bầu rượu đầy máu rồng từ không gian trữ vật và uống cạn trong một hơi. Máu rồng cực nóng khiến ngọn lửa trong cơ thể hắn bạo tăng, tạo thế đối kháng với bốn chuyển nghiệp hỏa đang thiêu đốt hồn phách.","phanLoaiPhu":"máu rồng","congNang":["Kích ngọn lửa trong cơ thể bạo tăng để đối kháng bốn chuyển nghiệp hỏa @c1319"],"dacDiem":"Cực nóng và được chứa đầy trong một bầu rượu.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1319","denChuong":"@c1319","cachCoDuoc":"Lấy từ không gian trữ vật","trangThai":"đã dùng cạn"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1319","loai":"dùng","importance":"normal","giaiDoan":"Uống máu rồng","text":"Vương Lâm lấy bầu rượu đầy máu rồng ra và uống cạn để khiến hỏa lực trong thân thể bạo tăng.","anchor":"một bầu rượu đầy máu rồng xuất hiện"}]},"nguon":["@c1319"]},{"id":"nhan-phuong-huong","name":"Nhân Phương hương","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"da-tat","blurb":"Cây hương đại diện Nhân Phương giới trong thí luyện Chu Tước trên Đại đế tinh. Đã tắt sau khi Vương Lâm vượt qua thí luyện Nhân Phương giới, gây chấn động vì chưa có tiền lệ.","detail":"Cây hương thứ nhất đại diện cho Nhân trong ba cây hương Thiên Địa Nhân. Khi Vương Lâm phá bầu trời Nhân Phương giới lao vào Địa Phương giới, cây hương này tắt hoàn toàn, khiến lão Chu Tước và các tu sĩ xung quanh chấn động vì việc hương tắt chưa từng xảy ra trong thí luyện.","tabs":{"tienTrinh":[{"chuong":"@c1320","loai":"nhắc tới","importance":"normal","giaiDoan":"Hương tắt","text":"Nhân Phương hương tắt sau khi Vương Lâm vượt qua thí luyện Nhân Phương giới, gây chấn động chưa có tiền lệ.","anchor":"Nhân Phương hương tắt, loại chuyện này chưa bao giờ xuất hiện qua"}]},"nguon":["@c1320"]},{"id":"dia-phuong-huong","name":"Địa Phương hương","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"hong","blurb":"Địa Phương hương là cây hương thứ hai trong bộ ba cây hương Thiên Địa Nhân, đại diện cho Địa Phương giới trong thí luyện Chu Tước. Cây hương tự bốc cháy quỷ dị khi Vương Lâm bước vào Địa Phương giới, được lão Chu Tước dùng máu Viêm long nhuộm đỏ để trợ lực thức tỉnh, và cuối cùng nứt gãy đổ xuống đấu trường khiến thí luyện Địa Phương giới kết thúc.","detail":"Địa Phương hương là cây hương thứ hai trong ba cây hương Thiên Địa Nhân, liên thông trực tiếp với không gian Địa Phương giới trong thí luyện của tộc Chu Tước. Khi Vương Lâm bước vào thí luyện Địa Phương giới, cây hương tự bốc cháy một cách quỷ dị mà không ai chạm vào, đánh dấu sự khởi đầu của giai đoạn thí luyện này. Ngọn lửa cháy đến gần nửa thân hương thì dừng lại khi Chu Tước chín màu phát tiếng kêu tỉnh giấc (@c1320). Lão Chu Tước sau đó ép máu Viêm long vạn trượng chảy xuống nhuộm đỏ cây hương nhằm trợ lực cho Vương Lâm thức tỉnh hoàn toàn. Đến giai đoạn cuối, sương mù từ lực tràn ra từ cây hương, thân hương nứt dày đặc rồi gãy nghiêng đổ xuống đấu trường, khiến thí luyện Địa Phương giới kết thúc (@c1323).","congNang":["Liên thông với không gian Địa Phương giới, tự bốc cháy đánh dấu Vương Lâm bước vào thí luyện Địa Phương giới @c1320","Duy trì không gian thí luyện Địa Phương giới; khi thân hương nứt gãy đổ xuống thì thí luyện kết thúc @c1323","Nhận máu Viêm long nhuộm đỏ làm chất trợ lực thức tỉnh cho Vương Lâm @c1320"],"tabs":{"tienTrinh":[{"chuong":"@c1320","loai":"dùng","importance":"major","giaiDoan":"Tự cháy và được nhuộm máu Viêm long","text":"Tự bốc cháy quỷ dị khi Vương Lâm vào Địa Phương giới. Cháy gần nửa thì dừng khi Chu Tước tỉnh giấc. Lão Chu Tước ép máu Viêm long nhuộm đỏ để trợ lực.","anchor":"Chỉ thấy cây hương thứ hai kia, Địa Phương Hương đại diện cho thí luyện ở Địa Phương giới, bỗng nhiên cháy lên một cách quỷ dị"},{"chuong":"@c1323","loai":"hu-ton/tu-bo","importance":"major","giaiDoan":"Gãy đổ","phamCap":"Không rõ","text":"Sương mù từ lực tràn khỏi cây hương, thân hương nứt dày đặc rồi gãy nghiêng đổ xuống đấu trường, khiến thí luyện chỉ còn Thiên phương hương.","anchor":"Ầm một tiếng, cây hương này đột nhiên bị gãy nghiêng rồi đổ xuống"}]},"nguon":["@c1320","@c1323"],"dacDiem":"Tự bốc cháy quỷ dị khi không ai chạm vào; khi cháy gần nửa thì tự dừng; cuối cùng thân hương tràn sương mù từ lực, nứt dày đặc rồi gãy nghiêng đổ xuống đấu trường."},{"id":"hoa-lien-chin-mau","name":"Hỏa liên chín màu","cn":"","category":"phap-bao","categoryLabel":"Hỏa liên","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Hỏa liên ngưng tụ từ hỏa lực chín màu trong Địa Phương giới, nơi Vương Lâm khoanh chân thực hiện thức tỉnh Chu Tước lần bốn.","detail":"Hỏa liên phát ra ngọn lửa chín màu vô tận nhập vào cơ thể Vương Lâm. Khi thức tỉnh hoàn tất, hỏa liên nở tung thành vô số mảnh ngưng tụ về phía Chu Tước.","congNang":["Cung cấp ngọn lửa chín màu cho quá trình thức tỉnh Chu Tước"],"nguon":["@c1321"]},{"id":"viem-huyet-viem-long","name":"Viêm huyết viêm long","cn":"","category":"nguyen-lieu","categoryLabel":"Huyết tinh hoa","phamCap":"","soHuu":["Viêm long vạn trượng"],"trangThai":"da-dung","blurb":"Máu tinh hoa trên đỉnh đầu viêm long, chứa tinh hoa hỏa lực toàn thân, được lão Chu Tước lấy để bổ sung hỏa lực cho quá trình thức tỉnh.","detail":"Viêm huyết ẩn chứa tinh hoa lửa khắp toàn thân viêm long. Khi được truyền vào Địa Phương hương, nó hóa mưa máu trong Địa Phương giới, ngưng tụ thành huyết cầu rồi bị Chu Tước chín màu hấp thu.","congNang":["Bổ sung tinh hoa hỏa lực cho thức tỉnh Chu Tước"],"nguon":["@c1321"]},{"id":"long-huyet-viem-long","name":"Long huyết viêm long","cn":"","category":"nguyen-lieu","categoryLabel":"Huyết dịch","phamCap":"","soHuu":["Viêm long vạn trượng"],"trangThai":"da-dung","blurb":"Long huyết thường của viêm long, kém viêm huyết nhưng lượng rất lớn, được lão Chu Tước ép lấy để duy trì hỏa lực cho quá trình thức tỉnh.","detail":"Khi viêm huyết trên đỉnh đầu viêm long đã cạn, lão Chu Tước mở vết thương trăm trượng trên thân viêm long để lấy long huyết thường. Tuy phẩm chất kém viêm huyết nhưng số lượng rất nhiều nên vẫn bổ sung được hỏa lực liên tục.","congNang":["Bổ sung hỏa lực bằng số lượng lớn"],"nguon":["@c1321"]},{"id":"cay-quat-dieu-am-dao-ton","name":"Cây quạt của Diệu âm đạo tôn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Diệu Âm đạo tôn"],"trangThai":"dang-co","blurb":"Tầng mây dưới chân Diệu âm đạo tôn tiêu tan và hóa thành một cây quạt, được hắn chụp lấy khi dò xét biến cố trên Đại đế tinh.","detail":"Khi Đại đế tinh dị biến, tầng mây mà Diệu âm đạo tôn vẫn nằm bên trên tiêu tan, hóa thành cây quạt. Hắn đứng bật dậy chụp lấy quạt, dùng thần thức dò xét và nhận ra lực lượng Thiên Nghịch thiên đạo.","tabs":{"tienTrinh":[{"chuong":"@c1322","loai":"xuat-hien","importance":"normal","giaiDoan":"Tầng mây hóa quạt khi biến cố Thiên Nghịch","text":"Tầng mây dưới chân Diệu âm đạo tôn tiêu tan, hóa thành cây quạt bị hắn chụp lấy.","anchor":"tầng mây dưới chân tiêu tan, hóa thành một cây quạt bị hắn chụp lấy"}]},"nguon":["@c1322"]},{"id":"thien-phuong-huong","name":"Thiên Phương hương","cn":"","category":"khac","categoryLabel":"Vật phẩm thí luyện","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Nén hương đặc biệt đang bị thiêu đốt trong thí luyện Thiên phương giới, khi cháy hết thì thí luyện kết thúc. (+) Cây hương cuối cùng trong ba cây hương Thiên Địa Nhân, đại diện cho Thiên, cao vút trên lưng cự quy. [CAN-SOAT-GOP]","detail":"Sau khi Nhân phương hương tắt và Địa phương hương gãy, đây là cây hương duy nhất còn lại trên lưng cự quy, cao vút giữa cảnh tượng hoang tàn.","tabs":{"tienTrinh":[{"chuong":"@c1323","loai":"nhac-toi","importance":"normal","giaiDoan":"Cây hương cuối còn lại","text":"Sau hai biến cố, Thiên phương hương là cây hương duy nhất còn đứng trên lưng cự quy.","anchor":"chỉ còn cây hương cuối cùng, cao vút - Thiên phương hương"}]},"capNhatToi":"@c1323","nguon":["@c1323","@c1326"]}]};
